function isServerTimestampField(value) {
    return value != null
        && typeof value === 'object'
        && (value._methodName === 'serverTimestamp' || value.constructor?.name === 'FieldValue');
}

/** Serializa campos de perfil para Cloud Functions (timestamps, sin undefined). */
function profilePayloadForCloud(fields) {
    const out = {};
    for (const [key, value] of Object.entries(fields || {})) {
        if (value === undefined) continue;
        if (isServerTimestampField(value)) {
            out[key] = '__SERVER_TIMESTAMP__';
        } else {
            out[key] = value;
        }
    }
    return out;
}

function tripFieldsForCloud(fields) {
    return profilePayloadForCloud(fields);
}

async function writeOwnProfileDocs(uid, fields) {
    const writeOpts = { merge: true };
    await setDoc(doc(db, 'artifacts', appId, 'users', uid, 'profile', 'data'), fields, writeOpts);
    await setDoc(doc(db, 'artifacts', appId, 'public', 'data', 'users', uid), fields, writeOpts);
}

/** Registro pasajero/conductor: Cloud Function primero, Firestore como respaldo. */
async function registerUserProfileWrite(uid, profileData) {
    if (!uid || !profileData) throw new Error('Perfil requerido');

    try {
        await httpsCallable(cloudFunctions, 'registerUserProfile')({
            profile: profilePayloadForCloud(profileData),
        });
        return;
    } catch (cloudErr) {
        const cloudCode = cloudErr?.code || '';
        if (cloudCode === 'functions/failed-precondition'
            || cloudCode === 'functions/invalid-argument'
            || cloudCode === 'functions/unauthenticated') {
            throw cloudErr;
        }
        console.warn('registerUserProfile cloud fallback:', cloudErr);
    }

    await writeOwnProfileDocs(uid, profileData);
}
window.registerUserProfileWrite = registerUserProfileWrite;

/** Actualización parcial del propio perfil (términos, foto, teléfono, vehículos, etc.). */
async function ownerProfilePatch(uid, fields) {
    if (!uid || !fields) return;

    const isTermsOnly = fields.termsAccepted === true
        && Object.keys(fields).every((k) => ['termsAccepted', 'termsAcceptedAt'].includes(k));

    if (isTermsOnly) {
        try {
            await httpsCallable(cloudFunctions, 'acceptTermsProfile')({
                termsAcceptedAt: fields.termsAcceptedAt || new Date().toISOString(),
            });
            return;
        } catch (cloudErr) {
            console.warn('acceptTermsProfile cloud:', cloudErr);
        }
    } else {
        try {
            await httpsCallable(cloudFunctions, 'registerUserProfile')({
                profile: profilePayloadForCloud(fields),
            });
            return;
        } catch (cloudErr) {
            console.warn('registerUserProfile patch cloud:', cloudErr);
        }
    }

    await writeOwnProfileDocs(uid, fields);
}
window.ownerProfilePatch = ownerProfilePatch;
window.writeOwnProfileDocs = writeOwnProfileDocs;
