function prefillDriverSetupFromProfile(profile) {
    if (!profile) return;
    const setVal = (id, val) => {
        const el = document.getElementById(id);
        if (el && val != null && val !== '') el.value = val;
    };
    setVal('full-name', profile.name);
    setVal('phone-number', profile.phone);
    setVal('emergency-contact-setup', profile.emergencyContact);
    setVal('driver-gender', profile.gender);
    setVal('driver-birthdate', profile.birthDate);
    setVal('driver-id-number', profile.identity);
}

