let sessionGuardUnsub = null;

function stopSessionGuardListener() {
    if (sessionGuardUnsub) {
        sessionGuardUnsub();
        sessionGuardUnsub = null;
    }
}

async function handleForcedRelogin(message) {
    stopSessionGuardListener();
    stopAndroidSessionKeepalive().catch(() => {});
    window.stopDriverLocationTracking?.();
    const msg = message || 'Tu sesión fue cerrada por un supervisor. Vuelve a iniciar sesión.';
    try {
        await signOut(auth);
    } catch (_) {}
    window.showToast?.(msg, 'warning');
    setTimeout(() => location.reload(), 600);
}

function startSessionGuardListener(uid) {
    if (!uid) return;
    stopSessionGuardListener();
    const userRef = doc(db, 'artifacts', appId, 'public', 'data', 'users', uid);
    sessionGuardUnsub = onSnapshot(userRef, (snap) => {
        if (!snap.exists() || !currentUser || currentUser.uid !== uid) return;
        const data = snap.data() || {};
        const serverV = data.sessionVersion || 0;
        if (serverV > getLocalSessionVersion(uid)) {
            handleForcedRelogin(data.forceReloginMessage);
        }
    }, (err) => console.warn('sessionGuard:', err));
}

// ================================================
// FUNCIÓN GLOBAL - Cargar logo y favicon desde Firebase
// ================================================
window.loadAppCustomization = async () => {
    document.querySelectorAll('.auth-hero-logo-img').forEach((img) => {
        img.dataset.logoPending = '1';
    });

    try {
        const snap = await getDoc(doc(db, 'artifacts', appId, 'public', 'data', 'appSettings', 'main'));
        if (!snap.exists()) return;

        const s = snap.data();

        // Actualizar favicon e icono de inicio (PWA / iPhone)
        if (s.loginLogoBase64) {
            const setLink = (rel, href, sizes = null) => {
                let selector = sizes
                    ? `link[rel="${rel}"][sizes="${sizes}"]`
                    : `link[rel="${rel}"]:not([sizes])`;
                let link = document.querySelector(selector);
                if (!link) {
                    link = document.createElement('link');
                    link.rel = rel;
                    if (sizes) link.sizes = sizes;
                    document.head.appendChild(link);
                }
                link.href = href;
            };
            setLink('icon', s.loginLogoBase64);
            setLink('apple-touch-icon', s.loginLogoBase64, '180x180');
        }

        // Guardar en variables globales
        window.customLoginLogo = s.loginLogoBase64 || null;
        window.customWelcomeMessage = s.welcomeMessage || null;

        try {
            if (s.loginLogoBase64) {
                localStorage.setItem(LOGIN_LOGO_CACHE_KEY, s.loginLogoBase64);
            } else {
                localStorage.removeItem(LOGIN_LOGO_CACHE_KEY);
            }
        } catch (e) { /* ignore */ }

        window.showLoginLogo?.();
        window.showCustomLogoInHeader?.();

        // Tonos globales (Personalización): mapa + archivos custom para todos
        try {
            if (s.toneMap || s.customTones) {
                applyRemoteToneConfig({
                    toneMap: s.toneMap || null,
                    customTones: s.customTones || null
                });
            }
        } catch (toneErr) {
            console.warn('loadAppCustomization tones:', toneErr);
        }

    } catch(e) {
        console.error("Error en loadAppCustomization:", e);
    } finally {
        document.querySelectorAll('.auth-hero-logo-img').forEach((img) => {
            delete img.dataset.logoPending;
        });
        if (!window.customLoginLogo) window.showLoginLogo?.();
    }
};

// ================================================
// MOSTRAR LOGO PERSONALIZADO EN EL LOGIN
// ================================================
window.showLoginLogo = () => {
    syncAuthHeroLogos(
        window.customLoginLogo,
        window.customWelcomeMessage,
        '#login-welcome-msg'
    );

    const firebaseLogo = document.getElementById('login-firebase-logo');
    const defaultLogo = document.getElementById('login-default-logo');
    if (window.customLoginLogo && firebaseLogo) {
        firebaseLogo.src = window.customLoginLogo;
        firebaseLogo.classList.add('auth-logo-loaded');
        firebaseLogo.style.display = 'block';
        if (defaultLogo) {
            defaultLogo.style.display = 'none';
            defaultLogo.classList.add('hidden');
        }
    } else if (firebaseLogo && defaultLogo && !firebaseLogo.dataset.logoPending) {
        firebaseLogo.classList.remove('auth-logo-loaded');
        firebaseLogo.style.display = 'none';
        defaultLogo.style.display = 'flex';
        defaultLogo.classList.remove('hidden');
    }
};

const bootLoginBranding = () => {
    window.showLoginLogo?.();
    setTimeout(() => window.loadAppCustomization?.(), 400);
};

if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', bootLoginBranding, { once: true });
} else {
    bootLoginBranding();
}




        try {
            await setPersistence(auth, browserLocalPersistence);
        } catch(e) {
            console.warn("La persistencia local de Auth no pudo ser inicializada.", e);
        }

        // === Low-end / Low-internet helpers for fluency and stability ===
        function isLowEndDevice() {
            try {
                if (navigator.deviceMemory && navigator.deviceMemory < 4) return true;
                if (navigator.hardwareConcurrency && navigator.hardwareConcurrency <= 2) return true;
                return false;
            } catch (_) { return false; }
        }

        function isSlowConnection() {
            try {
                const conn = navigator.connection || navigator.mozConnection || navigator.webkitConnection;
                if (conn) {
                    if (conn.effectiveType === '2g' || conn.effectiveType === 'slow-2g') return true;
                    if (conn.saveData) return true;
                    if (conn.downlink && conn.downlink < 0.5) return true;
                }
                return !navigator.onLine;
            } catch (_) { return false; }
        }

        function shouldUseLowPowerMode() {
            return isLowEndDevice() || isSlowConnection();
        }

        function isDriverAppForeground() {
            return document.visibilityState === 'visible';
        }

        window.isDriverAppForeground = isDriverAppForeground;

        function bindDriverAppVisibilitySync() {
            if (window._driverVisibilityBound) return;
            window._driverVisibilityBound = true;

            const syncDriverAppVisibility = () => {
                if (!currentUser || window.userProfile?.role !== 'driver') return;
                const visible = isDriverAppForeground();
                setDoc(
                    doc(db, 'artifacts', appId, 'public', 'data', 'drivers_location', currentUser.uid),
                    {
                        appVisible: visible,
                        appVisibleAt: Date.now()
                    },
                    { merge: true }
                ).catch(() => {});
                if (visible) window.publishDriverFleetPresence?.();
            };

            document.addEventListener('visibilitychange', syncDriverAppVisibility);
            window.addEventListener('pagehide', syncDriverAppVisibility);
            window.addEventListener('focus', syncDriverAppVisibility);
            window.addEventListener('blur', syncDriverAppVisibility);
        }

        window.isLowEndDevice = isLowEndDevice;
        window.isSlowConnection = isSlowConnection;
        window.shouldUseLowPowerMode = shouldUseLowPowerMode;

        // Global flag for the session
        window.LOW_POWER_MODE = shouldUseLowPowerMode();
        if (window.LOW_POWER_MODE) {
            console.log('%c[Perf] Low-power / low-internet mode activated for fluency', 'color:#f59e0b');
        }

        // Pause non-essential on hidden or offline for battery/data
        document.addEventListener('visibilitychange', () => {
            if (document.hidden && window.LOW_POWER_MODE) {
                // reduce some timers already handled by flags
            }
        });
        window.addEventListener('online', () => {
            if (window.refreshNearbyDriversFromCache) window.refreshNearbyDriversFromCache();
            window.showToast?.('Conexión recuperada', 'success');
        });
        window.addEventListener('offline', () => {
            window.showToast?.('Sin internet - algunos datos en cache', 'warning');
        });

        let userRole = localStorage.getItem('lastUserRole') || 'client';
        let authMode = 'login';

        // Restaurar selección de rol al cargar
        window.restoreLastRoleSelection = () => {
            const saved = localStorage.getItem('lastUserRole') || 'client';
            userRole = saved;
            setTimeout(() => {
                const clientBtn = document.getElementById('role-client');
                const driverBtn = document.getElementById('role-driver');
                if (clientBtn && driverBtn) {
                    document.querySelectorAll('.role-btn').forEach(b => b.classList.remove('bg-white', 'text-blue-600', 'shadow-sm'));
                    const activeBtn = document.getElementById(`role-${saved}`);
                    if (activeBtn) {
                        activeBtn.classList.add('bg-white', 'text-blue-600', 'shadow-sm');
                    }
                    const hint = document.getElementById('login-role-hint');
                    if (hint) hint.textContent = AUTH_ROLE_HINTS[saved] || AUTH_ROLE_HINTS.client;
                    document.getElementById('driver-fields')?.classList.toggle('hidden', saved !== 'driver');
                    document.getElementById('photo-req-label')?.classList.toggle('hidden', saved !== 'driver');

                    // Si era conductor, intentar recordar el tipo de vehículo (moto)
                    if (saved === 'driver') {
                        const lastV = localStorage.getItem('lastVehicleType');
                        if (lastV) {
                            const sel = document.getElementById('driver-vehicle-type');
                            if (sel) sel.value = lastV;
                        }
                    }
                }
            }, 60);
        };
        window.restoreLastRoleSelection();

        registerLiveTripGpsPulse(() => {
            if (!navigator.geolocation?.getCurrentPosition || !currentUser) return;
            const trip = window.currentActiveTripData || activeTrip;
            if (!trip?.id || !['accepted', 'in_progress'].includes(trip.status)) return;

            const hidden = document.hidden;
            // En viaje: alta precisión siempre (estilo Uber), incluso minimizado
            const geoOpts = {
                enableHighAccuracy: true,
                maximumAge: hidden ? 3000 : 1500,
                timeout: hidden ? 12000 : 8000
            };

            navigator.geolocation.getCurrentPosition(
                (position) => {
                    const lat = position.coords.latitude;
                    const lng = position.coords.longitude;
                    const heading = position.coords.heading;
                    const accuracy = position.coords.accuracy;
                    const force = true;

                    window.currentDriverPos = { lat, lng };
                    if (heading != null && Number.isFinite(heading)) {
                        window.currentDriverHeading = heading;
                    }

                    if (trip.driverId === currentUser.uid) {
                        if (window.__publishDriverGpsPulse) {
                            window.__publishDriverGpsPulse(lat, lng, heading, accuracy);
                        } else {
                            // Fallback: escribir drivers_location directo
                            setDoc(
                                doc(db, 'artifacts', appId, 'public', 'data', 'drivers_location', currentUser.uid),
                                {
                                    lat,
                                    lng,
                                    heading: Number.isFinite(heading) ? heading : null,
                                    accuracy: accuracy != null ? Number(accuracy) : null,
                                    online: true,
                                    appVisible: !document.hidden,
                                    appVisibleAt: Date.now(),
                                    updatedAt: Date.now(),
                                    name: window.userProfile?.name || '',
                                    approvalStatus: window.userProfile?.approvalStatus || 'approved'
                                },
                                { merge: true }
                            ).catch(() => {});
                        }
                    }
                    if (trip.clientId === currentUser.uid && trip.status === 'in_progress') {
                        window.__publishPassengerGpsPulse?.(lat, lng, heading, accuracy, force);
                    }
                },
                () => {},
                geoOpts
            );
        });

        let profilePhotoBase64 = null;
        let helmetPhotoBase64 = null;
        let passengerCascoPhoto1 = null;
        let passengerCascoPhoto2 = null;
        let editProfilePhotoBase64 = null;
        let selectedStars = 0;
        let cancelledTripSnapshot = null;
        let etaInterval = null;
        let navigationInterval = null;

        const CONFIRMED_TRIP_STATUSES = ['accepted', 'in_progress'];
        const TRIP_OFFER_TIMEOUT_SEC = 120;
        const TRIP_OFFER_NEGOTIATION_HOLD_SEC = 180;
        const SCHEDULED_TRIP_PREP_MINUTES = 10;
        const SCHEDULED_TRIP_PREP_MS = SCHEDULED_TRIP_PREP_MINUTES * 60 * 1000;

        function getScheduledTripMs(trip) {
            if (!trip?.scheduledFor) return 0;
            const ms = new Date(trip.scheduledFor).getTime();
            return Number.isFinite(ms) ? ms : 0;
        }

        /** Si al aceptar aún falta más de ~10 min, se reserva como scheduled (no arranca ya). */
        function shouldReserveAsScheduledTrip(trip) {
            const scheduledMs = getScheduledTripMs(trip);
            if (!scheduledMs) return false;
            return Date.now() < scheduledMs - SCHEDULED_TRIP_PREP_MS;
        }

        function isScheduledTripDueForActivation(trip) {
            const scheduledMs = getScheduledTripMs(trip);
            if (!scheduledMs || trip?.status !== 'scheduled') return false;
            return Date.now() >= scheduledMs - SCHEDULED_TRIP_PREP_MS;
        }

        function getScheduledTripMinutesUntil(trip) {
            const scheduledMs = getScheduledTripMs(trip);
            if (!scheduledMs) return null;
            return Math.max(0, Math.ceil((scheduledMs - Date.now()) / 60000));
        }

        function formatScheduledTripWhen(trip) {
            const scheduledMs = getScheduledTripMs(trip);
            if (!scheduledMs) return '';
            return new Date(scheduledMs).toLocaleString('es-HN', {
                weekday: 'short',
                day: 'numeric',
                month: 'short',
                hour: '2-digit',
                minute: '2-digit'
            });
        }

        window.activateScheduledTripIfDue = async (tripId) => {
            if (!tripId) return false;
            window._activatingScheduledTrips = window._activatingScheduledTrips || new Set();
            if (window._activatingScheduledTrips.has(tripId)) return false;
            window._activatingScheduledTrips.add(tripId);

            try {
                const tripRef = doc(db, 'artifacts', appId, 'public', 'data', 'trips', tripId);
                let activated = false;
                let hasDriver = false;
                await runTransaction(db, async (tx) => {
                    const snap = await tx.get(tripRef);
                    if (!snap.exists()) return;
                    const t = snap.data();
                    if (!isScheduledTripDueForActivation(t)) return;
                    const scheduledMs = getScheduledTripMs(t);
                    hasDriver = !!t.driverId;
                    // Con conductor: activar a accepted (flujo normal)
                    // Sin conductor (legacy): pending + buscar
                    tx.update(tripRef, {
                        status: hasDriver ? 'accepted' : 'pending',
                        scheduledEarlyActivated: Date.now() < scheduledMs,
                        activatedAt: serverTimestamp(),
                        scheduledActivatedFrom: 'client_auto'
                    });
                    activated = true;
                });
                if (activated && !hasDriver) {
                    await window.assignNextTripOffer?.(tripId);
                }
                return activated;
            } catch (e) {
                console.warn('activateScheduledTripIfDue:', e);
                return false;
            } finally {
                window._activatingScheduledTrips.delete(tripId);
            }
        };

        window.scanDueScheduledTrips = async (tripDocs = []) => {
            const due = tripDocs.filter((t) => isScheduledTripDueForActivation(t));
            for (const t of due) {
                await window.activateScheduledTripIfDue?.(t.id);
            }
        };

        /**
         * Conductor: iniciar YA un viaje programado reservado (antes de la hora).
         * Pasa a accepted y carga la ruta / flujo normal.
         */
        window.startScheduledTripNow = async (tripId, btnEl = null) => {
            if (!tripId || !currentUser) return;
            if (btnEl) {
                btnEl.disabled = true;
                if (!btnEl.dataset.origHtml) btnEl.dataset.origHtml = btnEl.innerHTML;
                btnEl.innerHTML = '<span class="pointer-events-none">Iniciando…</span>';
            }
            try {
                const tripRef = doc(db, 'artifacts', appId, 'public', 'data', 'trips', tripId);
                const snap = await getDoc(tripRef);
                if (!snap.exists()) throw new Error('Viaje no encontrado.');
                const t = snap.data();
                if (t.driverId !== currentUser.uid) throw new Error('Este viaje no es tuyo.');
                if (t.status === 'accepted' || t.status === 'in_progress') {
                    const data = { id: tripId, ...t };
                    activeTrip = data;
                    window.currentActiveTripData = data;
                    window.presentTripAcceptedUi?.(data, { role: 'driver' });
                    window.showToast?.('El viaje ya está activo.', 'success');
                    return;
                }
                if (t.status !== 'scheduled') {
                    throw new Error('Este viaje ya no está programado.');
                }
                await updateDoc(tripRef, {
                    status: 'accepted',
                    activatedAt: serverTimestamp(),
                    scheduledEarlyActivated: true,
                    scheduledActivatedFrom: 'driver_early_start',
                    acceptedAt: t.acceptedAt || serverTimestamp()
                });
                const data = {
                    id: tripId,
                    ...t,
                    status: 'accepted',
                    scheduledEarlyActivated: true,
                    scheduledActivatedFrom: 'driver_early_start'
                };
                activeTrip = data;
                window.currentActiveTripData = data;
                hideDriverTripOfferPopup?.();
                window.presentTripAcceptedUi?.(data, { role: 'driver' });
                // Ruta / mapa
                try {
                    if (data.originLat != null && data.originLng != null) {
                        window.placePickupMarker?.({ lat: data.originLat, lng: data.originLng }, 'Origen');
                    }
                    if (data.destinationLat != null && data.destinationLng != null) {
                        window.placeDestinationMarker?.({ lat: data.destinationLat, lng: data.destinationLng }, 'Destino');
                    }
                    window.selectDriverOfferForPreview?.(tripId, data);
                    window.openDriverRouteInGoogleMaps?.();
                } catch (_) {}
                window.showToast?.('Viaje programado iniciado. Ve al origen del pasajero.', 'success');
            } catch (e) {
                console.error('startScheduledTripNow:', e);
                window.showToast?.(e?.message || 'No se pudo iniciar el viaje programado.');
                if (btnEl) {
                    btnEl.disabled = false;
                    btnEl.innerHTML = btnEl.dataset.origHtml || btnEl.innerHTML;
                }
            }
        };

        function isTestDriverProfile(profile = window.userProfile) {
            return !!(profile?.isTestDriver || profile?._isDesignatedTestDriver);
        }

        async function syncTestDriverFlagOnLogin(uid) {
            if (!uid || !window.userProfile) return false;
            if (window.userProfile.isTestDriver) {
                window.userProfile._isDesignatedTestDriver = true;
                return true;
            }
            try {
                const snap = await getDoc(doc(db, 'artifacts', appId, 'public', 'data', 'appSettings', 'main'));
                if (snap.exists() && snap.data().testDriverUid === uid) {
                    window.userProfile.isTestDriver = true;
                    window.userProfile._isDesignatedTestDriver = true;
                    return true;
                }
            } catch (_) {}
            return false;
        }

