        async function enrichUsersWithContact(users) {
            return Promise.all((users || []).map(async (u) => {
                let email = getUserDisplayEmail(u);
                let phone = getUserDisplayPhone(u);
                if ((!email || !phone) && u.uid) {
                    try {
                        const priv = await getDoc(doc(db, 'artifacts', appId, 'users', u.uid, 'profile', 'data'));
                        if (priv.exists()) {
                            const p = priv.data();
                            email = email || (p.email || p.payoutEmail || '').trim();
                            phone = phone || (p.phone || '').trim();
                        }
                    } catch (_) {}
                }
                return { ...u, email: email || null, phone: phone || u.phone || null };
            }));
        }

        function showModerationError(e, actionLabel) {
            console.error(actionLabel, e);
            const denied = e?.code === 'permission-denied'
                || e?.code === 'functions/permission-denied'
                || String(e?.message || '').toLowerCase().includes('permission');
            const detail = e?.message || e?.details || '';
            window.showToast(denied
                ? (detail || `Sin permiso (${actionLabel}). Cierra sesión y vuelve a entrar como supervisor.`)
                : `Error: ${actionLabel}${detail ? ` — ${detail}` : ''}`);
        }

        async function prepareStaffModeration() {
            if (!canManageUsers()) {
                const err = new Error('Sin permisos de moderación');
                err.code = 'permission-denied';
                throw err;
            }
            if (!currentUser?.uid) {
                const err = new Error('Sin sesión activa');
                err.code = 'permission-denied';
                throw err;
            }
            if (!isStaffUser(currentUser, window.userProfile)) {
                const err = new Error('Tu cuenta no tiene permisos de staff');
                err.code = 'permission-denied';
                throw err;
            }
            const privRef = doc(db, 'artifacts', appId, 'users', currentUser.uid, 'profile', 'data');
            const pubRef = doc(db, 'artifacts', appId, 'public', 'data', 'users', currentUser.uid);
            const syncFields = {
                uid: currentUser.uid,
                name: window.userProfile?.name || (isAdminUser(currentUser, window.userProfile) ? 'Administrador' : 'Supervisor'),
                email: currentUser.email || window.userProfile?.email || null,
                updatedAt: serverTimestamp()
            };
            if (isSupervisorUser(currentUser, window.userProfile)) {
                syncFields.role = 'supervisor';
                let grantBy = window.userProfile?.staffGrantedBy || null;
                let grantAt = window.userProfile?.staffGrantedAt || null;
                if (!grantBy) {
                    try {
                        const pubSnap = await getDoc(pubRef);
                        if (pubSnap.exists()) {
                            grantBy = pubSnap.data().staffGrantedBy || null;
                            grantAt = pubSnap.data().staffGrantedAt || null;
                        }
                    } catch (_) {}
                }
                if (grantBy) {
                    syncFields.staffGrantedBy = grantBy;
                    syncFields.staffGrantedAt = grantAt || serverTimestamp();
                }
            }
            await setDoc(privRef, syncFields, { merge: true });
            await setDoc(pubRef, syncFields, { merge: true });
        }

        async function ensureStaffPublicRoleSync() {
            try {
                await prepareStaffModeration();
            } catch (e) {
                console.warn('ensureStaffPublicRoleSync:', e);
            }
        }

        function serializeModerationFields(fields) {
            const serverTsKeys = new Set([
                'updatedAt', 'suspendedAt', 'accountRestrictedAt', 'approvedAt', 'rejectedAt',
                'forceReloginAt', 'resubmitRequestedAt', 'renewalRequestedAt', 'staffGrantedAt',
                'validatedAt', 'suspendedUntil', 'restrictedUntil'
            ]);
            const out = {};
            for (const [key, value] of Object.entries(fields || {})) {
                const isFieldValue = value && typeof value === 'object' && !Array.isArray(value)
                    && !(value instanceof Date)
                    && (serverTsKeys.has(key) || value?._methodName === 'serverTimestamp');
                out[key] = isFieldValue ? '__SERVER_TIMESTAMP__' : value;
            }
            return out;
        }

        async function moderationWriteUser(uid, fields) {
            if (!uid) throw new Error('UID requerido');
            if (!canManageUsers()) {
                const err = new Error('Sin permisos de moderación');
                err.code = 'permission-denied';
                throw err;
            }

            try {
                await httpsCallable(cloudFunctions, 'moderateUserProfile')({
                    targetUid: uid,
                    fields: serializeModerationFields(fields),
                });
                prepareStaffModeration().catch((e) => console.warn('prepareStaffModeration:', e));
                return;
            } catch (cloudErr) {
                const cloudCode = cloudErr?.code || '';
                if (cloudCode === 'functions/permission-denied'
                    || cloudCode === 'functions/unauthenticated'
                    || cloudCode === 'functions/invalid-argument'
                    || cloudCode === 'functions/failed-precondition') {
                    throw cloudErr;
                }
                console.warn('moderateUserProfile cloud fallback:', cloudErr);
            }

            await prepareStaffModeration();
            const privRef = doc(db, 'artifacts', appId, 'users', uid, 'profile', 'data');
            const pubRef = doc(db, 'artifacts', appId, 'public', 'data', 'users', uid);
            const patch = { ...fields, updatedAt: serverTimestamp() };
            await setDoc(pubRef, patch, { merge: true });
            await setDoc(privRef, { uid, ...patch }, { merge: true });
        }

        async function syncUserEmailToProfile(user, profile) {
            if (!user?.email || !user?.uid) return profile;
            if (profile?.email === user.email) return profile;
            const fields = { email: user.email, updatedAt: serverTimestamp() };
            try {
                await setDoc(doc(db, 'artifacts', appId, 'users', user.uid, 'profile', 'data'), fields, { merge: true });
                await setDoc(doc(db, 'artifacts', appId, 'public', 'data', 'users', user.uid), fields, { merge: true });
            } catch (e) {
                console.warn('syncUserEmail:', e);
            }
            return { ...profile, email: user.email };
        }
        
