        window.sendInvoiceForTrip = async (tripId, overrideEmail) => {
            if (!tripId) return window.showToast('ID de viaje requerido');
            try {
                const tripRef = doc(db, 'artifacts', appId, 'public', 'data', 'trips', tripId);
                const tripSnap = await getDoc(tripRef);
                if (!tripSnap.exists()) return window.showToast('Viaje no encontrado');

                let trip = { id: tripId, ...tripSnap.data() };

                // Enriquecer cliente y conductor
                let clientInfo = { name: trip.clientName, email: trip.clientEmail };
                let driverInfo = { name: trip.driverName, vehicle: trip.vehicle };

                if (trip.clientId) {
                    try {
                        const [cSnap] = await enrichUsersWithContact([{ uid: trip.clientId }]);
                        if (cSnap) {
                            clientInfo = { name: cSnap.name || trip.clientName, email: cSnap.email || cSnap.payoutEmail };
                        }
                    } catch (_) {}
                }
                if (trip.driverId) {
                    try {
                        const [dSnap] = await enrichUsersWithContact([{ uid: trip.driverId }]);
                        if (dSnap) {
                            driverInfo = { name: dSnap.name || trip.driverName, vehicle: dSnap.vehicle };
                        }
                    } catch (_) {}
                }

                const targetEmail = overrideEmail || clientInfo.email || '';
                if (!targetEmail) {
                    window.showToast('Este viaje no tiene correo asociado del pasajero.');
                    // Aún mostramos preview
                }

                window.showTestFacturaModal(trip, targetEmail);

                // Guardar registro de factura enviada / generada
                try {
                    await updateDoc(doc(db, 'artifacts', appId, 'public', 'data', 'trips', tripId), {
                        facturaGenerated: true,
                        lastFacturaEmail: targetEmail || null,
                        lastFacturaAt: serverTimestamp()
                    });
                } catch (_) {}
            } catch (e) {
                console.error('sendInvoiceForTrip', e);
                window.showToast('Error al cargar datos del viaje.');
            }
        };

