        async function seedTestDriverLocation(trip, driverUid, driverName, phase = 'origin') {
            const lat = phase === 'destination'
                ? (trip.destinationLat ?? trip.originLat)
                : trip.originLat;
            const lng = phase === 'destination'
                ? (trip.destinationLng ?? trip.originLng)
                : trip.originLng;
            if (lat == null || lng == null) return;

            const vType = trip.serviceType || 'auto';
            const zId = window.activeServiceZoneId || trip.serviceZoneId || getDefaultZoneId();
            await setDoc(doc(db, 'artifacts', appId, 'public', 'data', 'drivers_location', driverUid), {
                lat: Number(lat),
                lng: Number(lng),
                name: driverName,
                online: true,
                appVisible: true,
                appVisibleAt: Date.now(),
                vehicleType: vType,
                serviceZoneId: zId,
                updatedAt: Date.now()
            }, { merge: true });

            // Also force show on map immediately
            try {
                window.updateDriverMarker?.(driverUid, Number(lat), Number(lng), false, { vehicleType: vType, name: driverName });
                window.refreshOpsFleetMapFromCache?.();
            } catch (_) {}
        }

        window.adminSimulateTrip = async (tripId, action) => {
            const testDriver = await getTestDriverConfig();
            if (!testDriver?.uid) {
                return window.showToast('Primero designa un conductor de prueba.');
            }

            const tripRef = doc(db, 'artifacts', appId, 'public', 'data', 'trips', tripId);
            const tripSnap = await getDoc(tripRef);
            if (!tripSnap.exists()) return window.showToast('El viaje ya no existe.');
            const trip = tripSnap.data();

            try {
                if (action === 'assign') {
                    if (trip.status !== 'pending') return window.showToast('Este viaje ya fue tomado.');
                    const driverSnap = await getDoc(doc(db, 'artifacts', appId, 'public', 'data', 'users', testDriver.uid));
                    if (!driverSnap.exists()) return window.showToast('Perfil del conductor de prueba no encontrado.');
                    const d = driverSnap.data();
                    const rating = d.ratingCount > 0 ? (d.ratingSum / d.ratingCount).toFixed(1) : '5.0';
                    const pin = Math.floor(1000 + Math.random() * 9000).toString();

                    const priceNum = parseTripPrice(trip);
                    const isBirthdayGift = trip.birthdayFree || trip.paymentMethod === 'birthday_gift';
                    const saldoHoldFields = {};
                    if (trip.paymentMethod === 'saldo' && trip.clientId && !isBirthdayGift) {
                        const chargeAmt = getPassengerSaldoChargeAmount(trip);
                        await deductPassengerSaldo(trip.clientId, chargeAmt);
                        saldoHoldFields.saldoCharged = true;
                        saldoHoldFields.saldoChargedAmount = chargeAmt;
                        saldoHoldFields.saldoChargedAt = serverTimestamp();
                    }

                    await updateDoc(tripRef, {
                        status: 'accepted',
                        driverId: testDriver.uid,
                        driverName: d.name,
                        driverPhoto: d.photo || null,
                        driverVehicle: d.vehicle || null,
                        driverVehiclePhotos: d.vehiclePhotos || null,
                        driverDocumentsPhotos: d.documentsPhotos || null,
                        driverIdentity: d.identity || 'PRUEBA',
                        driverRating: rating,
                        pin,
                        driverArrived: false,
                        isTestTrip: true,
                        acceptedAt: serverTimestamp(),
                        ...saldoHoldFields
                    });
                    await seedTestDriverLocation(trip, testDriver.uid, d.name, 'origin');
                    window.showToast(`Viaje asignado a ${d.name}. PIN: ${pin}`, 'success');
                }

                if (action === 'arrived_pickup') {
                    if (trip.driverId !== testDriver.uid) return window.showToast('Este viaje no tiene al conductor de prueba.');
                    await updateDoc(tripRef, { driverArrived: true });
                    await seedTestDriverLocation(trip, testDriver.uid, trip.driverName || testDriver.name, 'origin');
                    window.showToast('Conductor marcó llegada al origen.', 'success');
                }

                if (action === 'start') {
                    if (trip.driverId !== testDriver.uid) return window.showToast('Este viaje no tiene al conductor de prueba.');
                    await updateDoc(tripRef, { status: 'in_progress', startedAt: serverTimestamp() });
                    // Start timed movement according to ETA instead of instant jump
                    await startSimulatedDriverMovementForTrip(testDriver.uid, trip, trip.driverName || testDriver.name);
                    // Extra refresh so fleet icons start animating right away for admin/sup
                    setTimeout(() => {
                        try { window.refreshOpsFleetMapFromCache?.(); } catch(_) {}
                    }, 80);
                    window.showToast('Viaje iniciado (PIN validado). Conductor se mueve según tiempo estimado.', 'success');
                }

                if (action === 'cancel_sim') {
                    if (trip.driverId !== testDriver.uid) return window.showToast('Este viaje no tiene al conductor de prueba.');
                    window.stopTripSimMovement();
                    // Reset to accepted state or keep, but stop movement
                    await updateDoc(tripRef, { status: 'accepted', driverArrived: true });
                    window.showToast('Simulación del viaje cancelada.', 'warning');
                    await window.loadAdminTestingPanel();
                    return;
                }

                if (action === 'complete') {
                    if (trip.driverId !== testDriver.uid) return window.showToast('Este viaje no tiene al conductor de prueba.');
                    if (!confirm('¿Finalizar este viaje de prueba como si hubiera llegado al destino?')) return;

                    window.stopTripSimMovement();
                    const priceNum = parseTripPrice(trip);
                    let completeFields = { status: 'completed', priceNum, completedAt: serverTimestamp() };
                    let toastMsg = `Viaje finalizado. Ganancia registrada: L. ${priceNum.toFixed(2)}`;

                    const isBirthdayGift = trip.birthdayFree || trip.paymentMethod === 'birthday_gift';
                    if (trip.paymentMethod === 'saldo' || isBirthdayGift) {
                        const settlement = await settleSaldoTripOnComplete(trip, tripId);
                        if (settlement) {
                            completeFields = { ...completeFields, ...settlement.tripUpdate };
                            toastMsg = isBirthdayGift
                                ? `Viaje finalizado. Conductor recibió L. ${settlement.driverNet.toFixed(2)} (regalo cumpleaños).`
                                : `Viaje finalizado. Conductor recibió L. ${settlement.driverNet.toFixed(2)} (comisión L. ${settlement.commissionAmount.toFixed(2)} ya pagada).`;
                        }
                    } else {
                        const { commissionPercent } = await resolveCommissionForTrip(trip);
                        const split = calcTripCommissionSplit(priceNum, commissionPercent);
                        completeFields.commissionPercent = commissionPercent;
                        completeFields.commissionAmount = split.commissionAmount;
                        // Test: solo registra comisión del viaje; no convierte a deuda hasta vencer plazo / cerrar turno.
                    }

                    await updateDoc(tripRef, completeFields);
                    await redeemPromoIfNeeded({ ...trip, ...completeFields }, tripId);
                    if (currentUser?.uid === testDriver.uid) {
                        scheduleDriverEarningsRefresh();
                    }
                    window.showToast(toastMsg, 'success');

                    // Mostrar automáticamente la factura de prueba al admin
                    setTimeout(() => {
                        if (window.currentAdminTab === 'testing') {
                            window.sendInvoiceForTrip(tripId);
                        }
                    }, 1100);
                }

                if (window.currentAdminTab === 'testing') {
                    await window.loadAdminTestingPanel();
                }
            } catch (e) {
                console.error('adminSimulateTrip:', e);
                window.showToast(e?.message || 'Error en simulación.');
            }
        };

