        window.sendPersonalNotification = async (uid, userName, role, btn) => {
            if (!canManageUsers()) {
                return window.showToast('Sin permisos para enviar notificaciones.');
            }
            const msg = document.getElementById('individual-notify-msg')?.value.trim();
            if (!msg) return window.showToast('Escribe un mensaje.');

            btn.disabled = true;
            btn.innerText = 'ENVIANDO...';

            try {
                const colRef = collection(db, 'artifacts', appId, 'public', 'data', 'notifications');
                const newRef = doc(colRef);
                await setDoc(newRef, {
                    targetRole: role || 'driver',
                    targetUserId: String(uid),
                    targetUserName: userName,
                    personal: true,
                    allowReply: true,
                    threadId: newRef.id,
                    message: msg,
                    sentBy: currentUser.uid,
                    sentByName: window.getSenderDisplayName(),
                    createdAt: serverTimestamp(),
                    createdAtMs: Date.now()
                });

                window.showToast(`Notificación enviada solo a ${userName}`, 'success');
                btn.closest('.fixed')?.remove();
            } catch (e) {
                console.error(e);
                window.showToast('Error al enviar la notificación.');
                btn.disabled = false;
                btn.innerText = 'ENVIAR';
            }
        };

