        // Helper para cargar imagen como base64 para jsPDF
        // On localhost this will usually fail with CORS (see error in console).
        // You MUST configure CORS on the Firebase Storage bucket to allow http://127.0.0.1:5500
        // for images to be embedded in the PDF. The code falls back to printing the image URLs.
        async function loadImageAsBase64(url) {
            return new Promise((resolve) => {
                const img = new Image();
                img.crossOrigin = 'anonymous';
                img.onload = () => {
                    try {
                        const canvas = document.createElement('canvas');
                        const maxW = 400;
                        let w = img.width;
                        let h = img.height;
                        if (w > maxW) {
                            h = (maxW / w) * h;
                            w = maxW;
                        }
                        canvas.width = w;
                        canvas.height = h;
                        const ctx = canvas.getContext('2d');
                        ctx.drawImage(img, 0, 0, w, h);
                        const dataUrl = canvas.toDataURL('image/jpeg', 0.7);
                        resolve(dataUrl);
                    } catch (e) {
                        console.warn('Canvas tainted (CORS not configured for localhost):', url);
                        resolve(null);
                    }
                };
                img.onerror = () => {
                    console.warn('Image load blocked (CORS on localhost):', url);
                    resolve(null);
                };
                img.src = url + (url.includes('?') ? '&' : '?') + 't=' + Date.now();
            });
        }

