        window.applyPendingReferralAfterProfile = async (uid, name, role) => {
            const code = resolveReferralCodeInput();
            if (!code) return null;

            const result = await processReferral(db, appId, uid, name, role, code);
            if (result.success) {
                if (window.userProfile && result.newBalance != null) {
                    window.userProfile.balance = result.newBalance;
                    window.userProfile.referralRewardCredited = true;
                    window.refreshPassengerBalanceUI?.();
                }
                window.showToast(
                    `¡Código aplicado! +L. ${result.newUserReward} en tu saldo. ${result.referrerName} ganará L. ${result.referrerReward} cuando completes tu primer viaje.`,
                    "success"
                );
            } else if (result.reason === 'invalid_code') {
                window.showToast("El código de referido no es válido.");
                clearPendingReferralCode();
            } else if (result.reason === 'self_referral') {
                window.showToast("No puedes usar tu propio código de referido.");
            }
            return result;
        };

