        window.previewRechargeReceipt = (input) => {
            if (input.files && input.files[0]) {
                const reader = new FileReader();
                reader.onload = (e) => {
                    const img = new Image();
                    img.onload = () => {
                        const canvas = document.createElement('canvas');
                        let width = img.width;
                        let height = img.height;
                        if (width > 800) { height *= 800 / width; width = 800; }
                        
                        canvas.width = width;
                        canvas.height = height;
                        canvas.getContext('2d').drawImage(img, 0, 0, width, height);
                        
                        window.rechargeReceiptBase64 = canvas.toDataURL('image/jpeg', 0.8);
                        
                        const preview = document.getElementById('recharge-preview');
                        preview.src = window.rechargeReceiptBase64;
                        preview.classList.remove('hidden');
                    };
                    img.src = e.target.result;
                };
                reader.readAsDataURL(input.files[0]);
            }
        };

        window.submitRechargeRequest = async (btn) => {
            const amount = parseFloat(document.getElementById('recharge-amount').value);
            
            if (!amount || amount <= 0) {
                return alert("Ingresa un monto válido");
            }
            if (!window.rechargeReceiptBase64) {
                return alert("Por favor sube la foto del comprobante");
            }

            btn.disabled = true;
            btn.innerText = "ENVIANDO...";

            try {
                await addDoc(collection(db, 'artifacts', appId, 'public', 'data', 'recharge_requests'), {
                    passengerId: currentUser.uid,
                    passengerName: window.userProfile.name,
                    passengerPhone: normalizeHondurasPhone(window.userProfile.phone),
                    amount: amount,
                    receiptPhoto: window.rechargeReceiptBase64,
                    status: 'pending',
                    createdAt: serverTimestamp()
                });

                window.showToast("¡Solicitud enviada! El administrador verificará tu depósito pronto.", "success");
                btn.closest('.fixed').remove();
                window.rechargeReceiptBase64 = null;
            } catch(e) {
                alert("Error al enviar la solicitud");
                btn.disabled = false;
                btn.innerText = "ENVIAR COMPROBANTE PARA VERIFICACIÓN";
            }
        };

