        window.showForgotPassword = () => {
            const current = document.getElementById('email-field')?.value?.trim() || '';
            const modal = document.createElement('div');
            modal.className = 'fixed inset-0 bg-black/70 z-[50000] flex items-center justify-center p-4';
            modal.dataset.forgotPasswordModal = '1';
            modal.innerHTML = `
                <div class="bg-white rounded-3xl w-full max-w-md p-6">
                    <h3 class="font-black text-xl mb-2">Recuperar contraseña</h3>
                    <p class="text-sm text-gray-600 mb-4 leading-snug">
                        Escribe tu <b>correo</b> o <b>teléfono</b> registrado. Te enviaremos un enlace a tu correo para crear una nueva contraseña.
                    </p>
                    <input id="forgot-identifier" type="text" inputmode="email" autocomplete="username"
                           placeholder="Correo o teléfono (+504…)"
                           value="${current.replace(/"/g, '&quot;')}"
                           class="w-full px-4 py-3.5 rounded-2xl border border-gray-200 bg-gray-50 text-sm mb-4 outline-none focus:ring-2 focus:ring-blue-500">
                    <div class="flex gap-2">
                        <button type="button" onclick="this.closest('.fixed').remove()"
                                class="flex-1 py-3 rounded-2xl border font-bold text-sm text-gray-600">Cancelar</button>
                        <button type="button" id="forgot-submit-btn" onclick="window.executeForgotPassword(this)"
                                class="flex-1 py-3 rounded-2xl bg-blue-600 text-white font-black text-sm">ENVIAR ENLACE</button>
                    </div>
                </div>
            `;
            document.body.appendChild(modal);
            modal.querySelector('#forgot-identifier')?.focus();
        };

        window.executeForgotPassword = async (btn) => {
            const modal = btn?.closest('[data-forgot-password-modal]') || document.querySelector('[data-forgot-password-modal]');
            const identifier = document.getElementById('forgot-identifier')?.value?.trim();
            if (!identifier) return window.showToast('Ingresa tu correo o teléfono.');

            if (btn) {
                btn.disabled = true;
                btn.textContent = 'ENVIANDO…';
            }

            try {
                const email = await sendPasswordResetForIdentifier(auth, db, appId, identifier);
                modal?.remove();
                window.showToast(`Enlace enviado a ${maskEmail(email)}. Revisa tu bandeja y spam.`, 'success');
            } catch (e) {
                if (e?.message === 'PHONE_NOT_FOUND') {
                    window.showToast('No hay cuenta con ese teléfono. Prueba con tu correo.');
                } else {
                    window.showToast(authErrorMessage(e, 'reset'));
                }
                if (btn) {
                    btn.disabled = false;
                    btn.textContent = 'ENVIAR ENLACE';
                }
            }
        };

        window.updateRole = (role) => {
            userRole = role;
            localStorage.setItem('lastUserRole', role);

            document.querySelectorAll('.role-btn').forEach(b => b.classList.remove('bg-white', 'text-blue-600', 'shadow-sm'));
            const btn = document.getElementById(`role-${role}`);
            if (btn) btn.classList.add('bg-white', 'text-blue-600', 'shadow-sm');

            const hint = document.getElementById('login-role-hint');
            if (hint) hint.textContent = AUTH_ROLE_HINTS[role] || AUTH_ROLE_HINTS.client;

            document.getElementById('driver-fields')?.classList.toggle('hidden', role !== 'driver');
            document.getElementById('photo-req-label')?.classList.toggle('hidden', role !== 'driver');

            // Si es conductor, intentar restaurar el último tipo de vehículo (moto/auto)
            if (role === 'driver') {
                const lastV = localStorage.getItem('lastVehicleType');
                if (lastV) {
                    // Se aplicará cuando se muestre el setup
                    setTimeout(() => {
                        const sel = document.getElementById('driver-vehicle-type');
                        if (sel) sel.value = lastV;
                    }, 30);
                }
            }
        };

        // Función de compresión de foto de perfil
        window.previewPhoto = (input) => {
            if (input.files && input.files[0]) {
                const reader = new FileReader();
                reader.onload = (e) => {
                    const img = new Image();
                    img.onload = () => {
                        const canvas = document.createElement('canvas');
                        let width = img.width;
                        let height = img.height;
                        if (width > height) {
                            if (width > 256) { height *= 256 / width; width = 256; }
                        } else {
                            if (height > 256) { width *= 256 / height; height = 256; }
                        }
                        canvas.width = width; canvas.height = height;
                        canvas.getContext('2d').drawImage(img, 0, 0, width, height);
                        
                        profilePhotoBase64 = canvas.toDataURL('image/jpeg', 0.7);
                        document.getElementById('photo-preview').innerHTML = `<img src="${profilePhotoBase64}" class="w-full h-full object-cover">`;
                    };
                    img.src = e.target.result;
                };
                reader.readAsDataURL(input.files[0]);
            }
        };

        window.previewHelmetPhoto = (input) => {
            if (!input.files?.[0]) return;
            const reader = new FileReader();
            reader.onload = (e) => {
                const img = new Image();
                img.onload = () => {
                    const canvas = document.createElement('canvas');
                    let width = img.width, height = img.height;
                    if (width > height) { if (width > 400) { height *= 400 / width; width = 400; } }
                    else { if (height > 400) { width *= 400 / height; height = 400; } }
                    canvas.width = width; canvas.height = height;
                    canvas.getContext('2d').drawImage(img, 0, 0, width, height);
                    helmetPhotoBase64 = canvas.toDataURL('image/jpeg', 0.7);
                    const el = document.getElementById('helmet-photo-preview');
                    if (el) el.innerHTML = `<img src="${helmetPhotoBase64}" class="w-full h-full object-cover rounded-xl">`;
                };
                img.src = e.target.result;
            };
            reader.readAsDataURL(input.files[0]);
        };

