                    let height = img.height;
                    
                    // Higher quality + larger size for critical documents so downloads are HD
                    const isDocument = ['license', 'inspection', 'antecedentes', 'policiales'].includes(slot);
                    const maxSize = isDocument ? 1400 : 700;
