// DETENER SEGUIMIENTO DEL CONDUCTOR (Actualizado)
// ================================================
window.stopClientTracking = () => {
    if (window.clientTrackingInterval) {
        clearInterval(window.clientTrackingInterval);
        window.clientTrackingInterval = null;
    }
    if (window.clientTrackingUnsub) {
        window.clientTrackingUnsub();
        window.clientTrackingUnsub = null;
    }
    if (window.passengerLiveRepaintInterval) {
        clearInterval(window.passengerLiveRepaintInterval);
        window.passengerLiveRepaintInterval = null;
    }
    window._repaintPassengerTrackFrame = null;
    window._lastDriverFirebasePos = null;
    window._lastPassengerTrackMeta = null;

    resetPassengerAlertSession(activeTrip?.id || window.currentActiveTripData?.id || null);
    syncPassengerAlertSettingsVisibility(false);

    const trackedDriverId = window._passengerTrackDriverId;
    window.currentTrackTarget = null;
    window._passengerTrackRouteSession = null;
    window.clearRoutePolylines?.({ force: true });
    window.clearOriginDestinationMarkers?.();
    if (trackedDriverId) {
        window.removeDriverMarker?.(trackedDriverId);
    }

    const navTop = document.getElementById('nav-hud-top');
    const navBottom = document.getElementById('nav-hud-bottom');
    if (navTop) navTop.style.display = 'none';
    if (navBottom) navBottom.style.display = 'none';

    document.body.classList.remove('is-navigating');
    window.resetDriverNavCamera?.();
    window.resetPassengerNavCamera?.();
    window.exitPassengerTrackMode?.();
    window.hideCenterMapFab?.();
    window.syncNavigationMapFabs?.();

    // Ocultar panel de llegada al destino
    const pArrival = document.getElementById('passenger-destination-arrival-panel');
    if (pArrival) pArrival.style.display = 'none';
    document.getElementById('driver-destination-controls')?.classList.add('hidden');
};

// ==================== LLEGADA AL ORIGEN (1 km) / DESTINO (1 km) — CONDUCTOR → PASAJERO ====================
const TRIP_PICKUP_ARRIVAL_RADIUS_M = 1000;
const TRIP_DEST_CONFIRM_RADIUS_M = 1000;

window.getTripPickupCoords = (trip) => {
    const t = trip || activeTrip || window.currentActiveTripData;
    if (!t) return null;
    if (t.originLat != null && t.originLng != null) {
        return { lat: t.originLat, lng: t.originLng };
    }
    return null;
};

window.getTripRouteChain = (trip) => {
    const t = trip || activeTrip || window.currentActiveTripData;
    if (!t) return [];
    const origin = {
        address: t.origin,
        latLng: t.originLat != null ? { lat: t.originLat, lng: t.originLng } : null,
    };
    const destination = {
        address: t.destination,
        latLng: t.destinationLat != null ? { lat: t.destinationLat, lng: t.destinationLng } : null,
    };
    return window.buildOrderedRoutePoints?.(origin, destination, t.additionalStops || []) || [];
};

window.getTripCurrentLegIndex = (trip) => {
    const chain = window.getTripRouteChain(trip);
    if (chain.length < 2) return 1;
    const raw = Number(trip?.routeLegIndex);
    const idx = Number.isFinite(raw) && raw >= 1 ? raw : 1;
    return Math.min(idx, chain.length - 1);
};

window.getTripCurrentLegPoint = (trip) => {
    const chain = window.getTripRouteChain(trip);
    const idx = window.getTripCurrentLegIndex(trip);
    return chain[idx] || null;
};

window.getTripCurrentLegNavTarget = (trip) => {
    const point = window.getTripCurrentLegPoint(trip);
    if (!point) return null;
    if (point.latLng?.lat != null && point.latLng?.lng != null) {
        return { lat: point.latLng.lat, lng: point.latLng.lng, address: point.address || '' };
    }
    return point.address || null;
};

window.isTripAtFinalRouteLeg = (trip) => {
    const chain = window.getTripRouteChain(trip);
    if (chain.length < 2) return true;
    return window.getTripCurrentLegIndex(trip) >= chain.length - 1;
};

window.getTripRouteLegLabel = (trip) => {
    const chain = window.getTripRouteChain(trip);
    const idx = window.getTripCurrentLegIndex(trip);
    const point = chain[idx];
    const isFinal = chain.length < 2 || idx >= chain.length - 1;
    return {
        index: idx,
        routeNum: point?.routeNum || idx + 1,
        totalPoints: chain.length,
        address: point?.address || '',
        isFinal,
        hasMultipleLegs: chain.length > 2,
    };
};

window.getTripDestinationCoords = (trip) => {
    const leg = window.getTripCurrentLegPoint(trip);
    if (leg?.latLng?.lat != null && leg?.latLng?.lng != null) {
        return { lat: leg.latLng.lat, lng: leg.latLng.lng };
    }
    const t = trip || activeTrip || window.currentActiveTripData;
    if (!t) return null;
    if (t.destinationLat != null && t.destinationLng != null) {
        return { lat: t.destinationLat, lng: t.destinationLng };
    }
    if (window.currentPassengerTrackDest?.lat != null) return window.currentPassengerTrackDest;
    return null;
};

window.getDistanceMetersBetween = (from, to) => {
    if (!from?.lat || !from?.lng || !to?.lat || !to?.lng) return Infinity;
    if (typeof window.getDistanceToNavPoint === 'function') {
        return window.getDistanceToNavPoint(from, to);
    }
    const dLat = (to.lat - from.lat) * 111000;
    const dLng = (to.lng - from.lng) * 111000 * Math.cos((from.lat || 0) * Math.PI / 180);
    return Math.hypot(dLat, dLng);
};

window.syncDriverPickupArrivalUi = (driverPos = null) => {
    const trip = activeTrip || window.currentActiveTripData;
    const float = document.getElementById('driver-arrived-float');
    const btn = document.getElementById('btn-driver-arrived');
    if (!float || !btn) return;

    const isDriver = window.userProfile?.role === 'driver';
    const pickupPhase = trip?.status === 'accepted'
        && !trip?.driverArrived
        && trip?.driverId === currentUser?.uid;

    if (!isDriver || !pickupPhase) {
        btn.classList.remove('is-disabled');
        btn.removeAttribute('aria-disabled');
        float.title = 'Toca para marcar llegada · arrastra para mover';
        return;
    }

    const pos = driverPos || window.currentDriverPos;
    const pickup = window.getTripPickupCoords(trip);
    const dist = pos && pickup ? window.getDistanceMetersBetween(pos, pickup) : Infinity;
    const within = Number.isFinite(dist) && dist <= TRIP_PICKUP_ARRIVAL_RADIUS_M;

    btn.classList.toggle('is-disabled', !within);
    btn.setAttribute('aria-disabled', within ? 'false' : 'true');

    if (!pickup) {
        float.title = 'Ubicando punto de recogida…';
    } else if (!pos) {
        float.title = 'Obteniendo GPS… botón activo a ≤ 1 km del pasajero';
    } else if (within) {
        float.title = 'Toca para marcar llegada · arrastra para mover';
    } else {
        const distLabel = dist >= 1000
            ? `${(dist / 1000).toFixed(1)} km`
            : `${Math.round(dist)} m`;
        float.title = `A ${distLabel} del pasajero · botón activo a ≤ 1 km`;
    }
};

window.syncDriverDestinationArrivalUi = (driverPos = null) => {
    const trip = activeTrip || window.currentActiveTripData;
    const panel = document.getElementById('driver-destination-controls');
    const btn = document.getElementById('btn-driver-arrived-dest');
    const hint = document.getElementById('driver-dest-distance-hint');
    if (!panel || !btn) return;

    const isDriver = window.userProfile?.role === 'driver';
    const inProgress = trip?.status === 'in_progress' && trip?.driverId === currentUser?.uid;
    if (!isDriver || !inProgress) {
        panel.classList.add('hidden');
        return;
    }

    panel.classList.remove('hidden');
    const pos = driverPos || window.currentDriverPos;
    const dest = window.getTripDestinationCoords(trip);
    const dist = pos && dest ? window.getDistanceMetersBetween(pos, dest) : Infinity;
    const within = Number.isFinite(dist) && dist <= TRIP_DEST_CONFIRM_RADIUS_M;
    const signaled = !!trip.driverArrivedDestination;

    if (signaled) {
        btn.disabled = true;
        btn.querySelector('span').textContent = 'FINALIZANDO VIAJE…';
        if (hint) hint.innerHTML = '✅ Llegada registrada. Completando el viaje…';
        return;
    }

    const legLabel = window.getTripRouteLegLabel?.(trip) || { isFinal: true, routeNum: 2, hasMultipleLegs: false };
    const pointLabel = legLabel.isFinal ? 'destino' : `punto ${legLabel.routeNum}`;

    if (hint) {
        if (!dest) {
            hint.textContent = legLabel.isFinal ? 'Ubicando destino del viaje…' : 'Ubicando siguiente punto…';
        } else if (!pos) {
            hint.textContent = 'Obteniendo tu ubicación GPS…';
        } else if (within) {
            hint.innerHTML = `✅ A <b>${Math.round(dist)} m</b> del ${pointLabel}. Ya puedes presionar el botón.`;
        } else {
            const radiusLabel = TRIP_DEST_CONFIRM_RADIUS_M >= 1000
                ? `${(TRIP_DEST_CONFIRM_RADIUS_M / 1000).toFixed(0)} km`
                : `${TRIP_DEST_CONFIRM_RADIUS_M} m`;
            const distLabel = dist >= 1000
                ? `${(dist / 1000).toFixed(1)} km`
                : `${Math.round(dist)} m`;
            hint.innerHTML = `A <b>${distLabel}</b> del ${pointLabel}. Botón activo a ≤ ${radiusLabel}.`;
        }
    }

    btn.disabled = !within || !dest || !pos;
    btn.querySelector('span').textContent = legLabel.isFinal
        ? 'LLEGUÉ AL DESTINO'
        : (legLabel.hasMultipleLegs ? `LLEGUÉ AL PUNTO ${legLabel.routeNum}` : 'LLEGUÉ AL DESTINO');
};

window.driverSignalDestinationArrival = async () => {
    const trip = activeTrip || window.currentActiveTripData;
    if (!trip?.id || trip.status !== 'in_progress' || trip.driverId !== currentUser?.uid) {
        return window.showToast?.('Solo disponible durante un viaje en curso.');
    }
    if (trip.driverArrivedDestination) {
        return window.showToast?.('Ya registraste la llegada. Espera la confirmación del pasajero.');
    }

    const pos = window.currentDriverPos;
    const dest = window.getTripDestinationCoords(trip);
    if (!pos || !dest) {
        return window.showToast?.('Esperando ubicación GPS o destino del viaje.');
    }
    const dist = window.getDistanceMetersBetween(pos, dest);
    if (dist > TRIP_DEST_CONFIRM_RADIUS_M) {
        const needLabel = TRIP_DEST_CONFIRM_RADIUS_M >= 1000
            ? `${(TRIP_DEST_CONFIRM_RADIUS_M / 1000).toFixed(0)} km`
            : `${TRIP_DEST_CONFIRM_RADIUS_M} m`;
        const nowLabel = dist >= 1000
            ? `${(dist / 1000).toFixed(1)} km`
            : `${Math.round(dist)} m`;
        return window.showToast?.(`Debes estar a ${needLabel} o menos del destino (ahora ~${nowLabel}).`);
    }

    const legLabel = window.getTripRouteLegLabel?.(trip) || { isFinal: true, routeNum: 2 };
    const confirmMsg = legLabel.isFinal
        ? '¿Confirmas que llegaste al destino final con el pasajero? El viaje se finalizará.'
        : `¿Confirmas que llegaste al punto ${legLabel.routeNum}? Se cargará la ruta al siguiente punto.`;
    if (!confirm(confirmMsg)) return;

    try {
        if (!legLabel.isFinal) {
            const nextIdx = window.getTripCurrentLegIndex(trip) + 1;
            await updateDoc(doc(db, 'artifacts', appId, 'public', 'data', 'trips', trip.id), {
                routeLegIndex: nextIdx,
                driverArrivedDestination: false,
            });
            activeTrip = { ...trip, routeLegIndex: nextIdx, driverArrivedDestination: false };
            window.currentActiveTripData = { ...activeTrip };
            window._inProgressNavBootKey = null;
            window._lastTripUiState = null;
            window._passengerTrackKey = null;

            const nextTarget = window.getTripCurrentLegNavTarget(activeTrip);
            if (nextTarget) window.updateNavigation?.(nextTarget, true);

            const nextLabel = window.getTripRouteLegLabel(activeTrip);
            window.syncDriverDestinationArrivalUi(pos);
            window.showToast?.(
                `Punto ${legLabel.routeNum} completado. Ruta cargada al punto ${nextLabel.routeNum}. Toca el botón de Google Maps si quieres navegar ahí.`,
                'success'
            );
            return;
        }

        await updateDoc(doc(db, 'artifacts', appId, 'public', 'data', 'trips', trip.id), {
            driverArrivedDestination: true,
            driverArrivedDestinationAt: serverTimestamp()
        });
        activeTrip = { ...trip, driverArrivedDestination: true };
        window.currentActiveTripData = { ...activeTrip };

        window.syncDriverDestinationArrivalUi(pos);
        await window.finishTrip?.({ skipConfirm: true });
    } catch (e) {
        console.error('driverSignalDestinationArrival:', e);
        window.showToast?.(legLabel.isFinal
            ? 'No se pudo finalizar el viaje en el destino.'
            : 'No se pudo avanzar al siguiente punto.');
    }
};

// ==================== PANEL FIJO MINIMIZABLE PARA CLIENTE: CONFIRMAR LLEGADA AL DESTINO ====================
// Se activa cuando el conductor marca llegada y está a <= 1 km del destino.
// Fijo en esquina + minimizable. Solo visible en fase destination para cliente.

window.ensurePassengerDestinationArrivalPanel = function() {
  const panel = document.getElementById('passenger-destination-arrival-panel');
  if (panel) panel.style.display = 'none';
  return panel || null;
};

window.updatePassengerDestinationArrivalPanel = function() {
  const panel = document.getElementById('passenger-destination-arrival-panel');
  if (panel) panel.style.display = 'none';
};

window.passengerConfirmDestinationArrival = async function() {
  const panel = document.getElementById('passenger-destination-arrival-panel');
  if (panel) panel.style.display = 'none';

  if (!activeTrip || !activeTrip.id) {
    window.showToast?.('Error: no hay viaje activo.');
    return;
  }

  // Verificar distancia con ubicación actual del conductor (debe ser <= 1 km)
  const driverPos = window.currentDriverTrackPos || window._lastDriverFirebasePos;
  const destPos = window.currentPassengerTrackDest || { lat: activeTrip.destinationLat, lng: activeTrip.destinationLng };
  let dist = 999999;
  if (driverPos && destPos && destPos.lat) {
    if (typeof window.getDistanceToNavPoint === 'function') {
      dist = window.getDistanceToNavPoint(driverPos, destPos);
    } else {
      const dLat = (destPos.lat - driverPos.lat) * 111000;
      const dLng = (destPos.lng - driverPos.lng) * 111000 * Math.cos((driverPos.lat || 0) * Math.PI / 180);
      dist = Math.hypot(dLat, dLng);
    }
  }
  if (!activeTrip.driverArrivedDestination) {
    window.showToast?.('Espera a que el conductor presione "Llegué al destino".');
    if (panel) panel.style.display = 'block';
    return;
  }
  if (dist > TRIP_DEST_CONFIRM_RADIUS_M) {
    window.showToast?.(`Solo puedes confirmar si el conductor está a ${TRIP_DEST_CONFIRM_RADIUS_M} m o menos.`);
    if (panel) panel.style.display = 'block';
    return;
  }

  const priceNum = parseTripPrice(activeTrip) || 0;
  const isBirthdayGift = activeTrip.birthdayFree || activeTrip.paymentMethod === 'birthday_gift';
  const payMethod = activeTrip.paymentMethod || 'efectivo';

  window.showToast?.('¡Llegada confirmada! Finalizando viaje…');

  try {
    window.stopClientTracking?.();
    window.exitPassengerTrackMode?.();

    let tripUpdate = {
      status: 'completed',
      completedAt: serverTimestamp(),
      priceNum: isBirthdayGift ? 0 : priceNum,
      passengerConfirmedDestination: true,
      passengerDestinationConfirmedAt: serverTimestamp()
    };

    if (activeTrip.paymentMethod === 'saldo' || isBirthdayGift) {
      const settlement = await settleSaldoTripOnComplete(activeTrip, activeTrip.id);
      if (settlement) tripUpdate = { ...tripUpdate, ...settlement.tripUpdate };
    } else {
      tripUpdate.paymentMethod = payMethod;
      if (!isBirthdayGift) {
        const { commissionPercent } = await resolveCommissionForTrip(activeTrip).catch(() => ({ commissionPercent: 15 }));
        const split = calcTripCommissionSplit(priceNum, commissionPercent);
        tripUpdate.commissionPercent = commissionPercent;
        tripUpdate.commissionAmount = split.commissionAmount;
      }
    }

    await updateDoc(doc(db, 'artifacts', appId, 'public', 'data', 'trips', activeTrip.id), tripUpdate);
    await redeemPromoIfNeeded({ ...activeTrip, ...tripUpdate }, activeTrip.id);

    activeTrip = { ...activeTrip, ...tripUpdate, status: 'completed' };
    window.currentActiveTripData = activeTrip;

    if (payMethod === 'efectivo' && !isBirthdayGift) {
      setTimeout(() => {
        const payMsg = document.createElement('div');
        payMsg.style.cssText = 'position:fixed;bottom:110px;left:50%;transform:translateX(-50%);background:#fefce8;border:2px solid #854d0e;padding:12px 14px;border-radius:10px;z-index:999999;max-width:280px;text-align:center;font-size:13px;';
        payMsg.innerHTML = `
          <strong style="color:#854d0e;">¡VIAJE FINALIZADO!</strong><br>
          Paga <strong style="font-size:18px;">L. ${priceNum.toFixed(2)}</strong> en <strong>EFECTIVO</strong> al conductor ahora.
        `;
        document.body.appendChild(payMsg);
        setTimeout(() => payMsg.remove(), 9000);
      }, 400);
    }

    // === EL CONDUCTOR RECIBIRÁ LA ACTUALIZACIÓN POR LISTENER ===
    // Verá: "Ganancia en efectivo: L. XXX" y podrá cobrar.

    // El sistema ya maneja la calificación automáticamente después de completar el viaje.
    // No se inyecta UI duplicada.
    setTimeout(() => {
      window.showToast?.('Viaje finalizado. El flujo de calificación aparecerá automáticamente.');
      // Ocultar paneles del viaje para que fluya al sistema existente
      document.getElementById('control-panel')?.classList.add('hidden');
    }, 800);

  } catch (e) {
    console.error('Error finalizando por botón de pasajero:', e);
    window.showToast?.('Error al finalizar. Intenta con el conductor.');
    if (panel) panel.style.display = 'block';
  }
};

// Hook the panel in destination tracking
function _initDestinationArrivalPanel() {
  window.updatePassengerDestinationArrivalPanel?.();
}

        function resetAfterTripEnds() {
            if (window.pendingOfferWatch) {
                clearInterval(window.pendingOfferWatch);
                window.pendingOfferWatch = null;
            }
            window.stopNoDriversNotifyCountdown?.();
            try { stopPassengerWaitingLoop(); } catch (_) {}
            try { stopLoopingTone(); } catch (_) {}
            window._passengerAcceptSoundKey = null;
            activeTrip = null;
            window.currentActiveTripData = null;
            window.lastMessageCount = 0;
            window._lastTripUiState = null;
            window._lastNotifiedTripStatus = null;
            window._lastNotifiedDriverArrived = null;
            window._lastNotifiedDriverDestArrived = null;
            window._lastRouteLegIndex = null;
            clearStoredClientTripId();
            resetPassengerAlertSession();
            syncPassengerAlertSettingsVisibility(false);
            window.stopPassengerLiveLocationSharing?.();
            window._inProgressNavBootKey = null;
            unsubscribeTripDocument();

            document.body.classList.remove('trip-active', 'is-searching', 'is-navigating');
            clearPassengerSearchPanelLayout();
            syncPromoUi();
            window.hideCenterMapFab?.();
            window.syncNavigationMapFabs?.();
            window.resetTripPanelCollapse?.();
            window.restoreControlPanelAfterDriverTrip?.();
            window.hideTripFloatPanels?.();

            const atp = document.getElementById('active-trip-panel');
            if (atp) {
              const isMobile = window.innerWidth < 768;
              if (isMobile && document.body.classList.contains('trip-active')) {
                // On cell phones: the central trip panel MUST only disappear when user taps minimize.
                // Do not add 'hidden' automatically.
              } else {
                atp.classList.add('hidden');
              }
            }
            document.getElementById('trip-partner-info')?.classList.add('hidden');
            document.getElementById('searching-state')?.classList.add('hidden');
            document.getElementById('trip-viewers-panel')?.classList.add('hidden');
            document.getElementById('fare-card')?.classList.add('hidden');
            document.getElementById('eta-indicator')?.classList.add('hidden');
            window.recordedTripViews?.clear();
            document.getElementById('nav-hud-top').style.display = 'none';
            document.getElementById('nav-hud-bottom').style.display = 'none';

            // Restore passenger booking form elements after searching/cancel
            if (window.userProfile?.role === 'client') {
                document.getElementById('passenger-booking-route')?.classList.remove('hidden');
                document.getElementById('passenger-booking-advanced')?.classList.remove('hidden');
                document.getElementById('passenger-booking-service')?.classList.remove('hidden');
                document.getElementById('trip-panel-setup')?.classList.remove('hidden');
                document.getElementById('client-trip-headline')?.classList.remove('hidden');
                document.getElementById('client-trip-subline')?.classList.remove('hidden');
                document.getElementById('passenger-city-bar')?.classList.add('hidden');
                document.getElementById('favorites-bar')?.classList.remove('hidden');
                document.getElementById('trip-options-panel')?.classList.remove('hidden');
                document.getElementById('hourly-options')?.classList.remove('hidden');
                document.getElementById('main-client-saldo')?.classList.remove('hidden');
                document.querySelector('.trip-route-fields')?.classList.remove('hidden');
                // delivery-details-panel is toggled by service type as needed
                // reset hourly
                window.currentBookingMode = 'standard';
                window.currentReservedHours = 1;
                window.currentPassengers = 1; // máx 4 personas (auto/taxi)
                window.currentHourlyStopType = 'standard';
                const hToggle = document.getElementById('trip-hourly-toggle');
                if (hToggle) hToggle.checked = false;
                document.getElementById('hourly-options')?.classList.add('hidden');
                window.renderTripPassengerChips?.();
            }

            if (navigationInterval) clearInterval(navigationInterval);
            if (etaInterval) clearInterval(etaInterval);
            navigationInterval = null;
            etaInterval = null;
            window.currentNavTarget = null;
            window.currentNavTargetKey = null;

            window.stopClientTracking();

            window.resetDriverNavCamera?.({ force: true });
            window.exitPassengerTrackMode?.();
            if (window.gMap) {
                window.gMap.setMapTypeId('roadmap');
            }

            // Restart nearby driver markers (with type icons) after trip ends for clients/admins
            setTimeout(() => {
                if (!window.canViewOpsFleetMap?.()) {
                    window.listenForNearbyDrivers?.();
                    window.refreshNearbyDriversFromCache?.();
                } else {
                    window.refreshOpsFleetMapFromCache?.();
                }
            }, 300);

            if (window.userProfile?.role === 'driver') {
                document.getElementById('client-view')?.classList.add('hidden');
                document.getElementById('driver-view')?.classList.remove('hidden');

                const zp = document.getElementById('service-zone-picker');
                const zc = document.getElementById('service-zone-map-chip');
                if (zp) zp.classList.add('hidden');
                if (zc) zc.classList.remove('hidden');
                ensurePassengerCityPickerVisible();
                updateZoneHint();
                window.showControlPanel?.();
            } else {
                document.getElementById('driver-view')?.classList.add('hidden');
                if (window.userProfile?.role === 'client') document.getElementById('client-view')?.classList.remove('hidden');
                ensurePassengerTripPanelUI();
                initServiceZoneUI();
                updateZoneHint();
                if (window.canViewOpsFleetMap?.()) {
                    startOpsFleetMapListener(db, appId);
                    // Ensure users data for fleet cross-check if not yet
                    setTimeout(() => {
                        if ((!window.allUsersData || window.allUsersData.length === 0) && typeof window.loadAdminUsers === 'function') {
                            window.loadAdminUsers().catch(() => {});
                        }
                    }, 180);
                } else {
                    window.listenForNearbyDrivers?.();
                }

                // Asegurar conductores activos visibles "desde ya"
                setTimeout(() => {
                    if (!window.canViewOpsFleetMap?.() && typeof window.refreshNearbyDriversFromCache === 'function') {
                        window.refreshNearbyDriversFromCache();
                    } else if (window.canViewOpsFleetMap?.()) {
                        if (typeof window.pruneGhostFleetMarkers === 'function') window.pruneGhostFleetMarkers();
                        if (typeof window.refreshOpsFleetMapFromCache === 'function') window.refreshOpsFleetMapFromCache();
                    }
                }, 400);

                // Force balance visible for passengers
                const mainS = document.getElementById('main-client-saldo');
                if (mainS) {
                    mainS.classList.remove('hidden');
                    mainS.classList.add('flex');
                }
                const profS = document.getElementById('passenger-balance-section');
                if (profS) profS.classList.remove('hidden');
                if (canUsePassengerSaldo(window.userProfile)) {
                    refreshPassengerBalanceUI();
                }
            }
        }

        function markCancelledTripHandled(tripId) {
            window.handledCancelledTripIds.add(tripId);
            try {
                const stored = JSON.parse(sessionStorage.getItem('honduber_handled_cancelled') || '[]');
                if (!stored.includes(tripId)) {
                    stored.push(tripId);
                    sessionStorage.setItem('honduber_handled_cancelled', JSON.stringify(stored.slice(-50)));
                }
            } catch (_) {}
        }

        function loadHandledCancelledTrips() {
            try {
                const stored = JSON.parse(sessionStorage.getItem('honduber_handled_cancelled') || '[]');
                stored.forEach((id) => window.handledCancelledTripIds.add(id));
            } catch (_) {}
        }
        loadHandledCancelledTrips();

        function isConfirmedCancellation(data) {
            return CONFIRMED_TRIP_STATUSES.includes(data?.cancelledFromStatus);
        }

        function userAlreadySubmittedCancellationSurvey(data) {
            if (!data || !currentUser) return false;
            if (data.clientId === currentUser.uid && data.cancellationSurveyByClient) return true;
            if (data.driverId === currentUser.uid && data.cancellationSurveyByDriver) return true;
            return false;
        }

        function resetCancellationSurveyForm() {
            [
                'cancel-point', 'cancel-who', 'cancel-reason', 'cancel-communication',
                'cancel-incident', 'cancel-agreement', 'cancel-contact', 'cancel-continue'
            ].forEach((name) => {
                document.querySelectorAll(`input[name="${name}"]`).forEach((el) => { el.checked = false; });
            });
            const comments = document.getElementById('cancellation-survey-comments');
            if (comments) comments.value = '';
        }

        function getCheckedSurveyValue(name) {
            return document.querySelector(`input[name="${name}"]:checked`)?.value || '';
        }

        function computeCancellationSurveyFlags(answers) {
            const {
                cancelPoint, whoProposed, reason, communication, incident,
                serviceAgreement, contactShared, tripWillContinue
            } = answers;

            const fraudSignals = [];
            if (serviceAgreement === 'alternative_discussed') fraudSignals.push('acuerdo_alternativo');
            if (contactShared === 'yes_after') fraudSignals.push('contacto_posterior');
            if (contactShared === 'yes_trip' && tripWillContinue !== 'no') fraudSignals.push('contacto_viaje');
            if (tripWillContinue === 'yes') fraudSignals.push('continuara_igual');
            if (tripWillContinue === 'maybe' && contactShared !== 'no') fraudSignals.push('continuara_talvez');
            if (whoProposed === 'them' && serviceAgreement === 'alternative_discussed') fraudSignals.push('otro_propuso_alternativa');

            const fraudFlag = (
                serviceAgreement === 'alternative_discussed'
                || contactShared === 'yes_after'
                || tripWillContinue === 'yes'
                || (tripWillContinue === 'maybe' && contactShared !== 'no')
            );

            const safetySerious = ['disrespect', 'inappropriate', 'unsafe', 'vehicle'].includes(incident)
                || reason === 'safety_concern'
                || communication === 'uncomfortable';
            const safetyConcern = incident === 'misunderstanding'
                || communication === 'tense'
                || communication === 'cold'
                || reason === 'misunderstanding';
            const safetyFlag = safetySerious || safetyConcern;

            return {
                fraudFlag,
                fraudSignals,
                safetySerious,
                safetyConcern,
                safetyFlag,
                cancelPoint,
                whoProposed,
                reason,
                communication,
                incident,
                serviceAgreement,
                contactShared,
                tripWillContinue
            };
        }

        async function applyPartnerModeration(partnerId, partnerRole, flags) {
            if (!partnerId) return { actionTaken: false };

            const pubRef = doc(db, 'artifacts', appId, 'public', 'data', 'users', partnerId);
            const snap = await getDoc(pubRef);
            if (!snap.exists()) return { actionTaken: false };

            const current = snap.data();
            const updates = {};

            if (flags.fraudFlag) {
                const newCount = (current.fraudAlertCount || 0) + 1;
                updates.fraudAlertCount = newCount;
                updates.lastFraudAlertAt = serverTimestamp();

                if (partnerRole === 'driver' && newCount >= FRAUD_ALERTS_SUSPEND_THRESHOLD) {
                    updates.approvalStatus = 'suspended';
                    updates.suspendedAt = serverTimestamp();
                    updates.suspendedReason = 'auto_fraud_alerts';
                    updates.autoSuspended = true;
                } else if (partnerRole === 'client' && newCount >= FRAUD_ALERTS_SUSPEND_THRESHOLD) {
                    updates.accountRestricted = true;
                    updates.accountRestrictedAt = serverTimestamp();
                    updates.accountRestrictedReason = 'auto_fraud_alerts';
                }
            }

            if (flags.safetySerious) {
                const newSafety = (current.safetyIncidentCount || 0) + 1;
                updates.safetyIncidentCount = newSafety;
                updates.lastSafetyIncidentAt = serverTimestamp();

                if (partnerRole === 'driver' && newSafety >= SAFETY_INCIDENTS_SUSPEND_THRESHOLD) {
                    updates.approvalStatus = 'suspended';
                    updates.suspendedAt = serverTimestamp();
                    updates.suspendedReason = 'auto_safety_incidents';
                    updates.autoSuspended = true;
                } else if (partnerRole === 'client' && newSafety >= SAFETY_INCIDENTS_SUSPEND_THRESHOLD) {
                    updates.accountRestricted = true;
                    updates.accountRestrictedAt = serverTimestamp();
                    updates.accountRestrictedReason = 'auto_safety_incidents';
                }
            } else if (flags.safetyConcern) {
                updates.safetyConcernCount = (current.safetyConcernCount || 0) + 1;
                updates.lastSafetyConcernAt = serverTimestamp();
            }

            if (Object.keys(updates).length === 0) return { actionTaken: false };

            await updateDoc(pubRef, updates);
            try {
                await updateDoc(doc(db, 'artifacts', appId, 'users', partnerId, 'profile', 'data'), updates);
            } catch (_) {}

            return {
                actionTaken: true,
                suspended: updates.approvalStatus === 'suspended' || updates.accountRestricted === true,
                partnerRole,
                fraudCount: updates.fraudAlertCount ?? current.fraudAlertCount,
                safetyCount: updates.safetyIncidentCount ?? current.safetyIncidentCount
            };
        }

        function resolveTripParties(s) {
            const clientId = s.clientId || (s.respondentRole === 'client' ? s.respondentId : s.partnerId);
            const driverId = s.driverId || (s.respondentRole === 'driver' ? s.respondentId : s.partnerId);
            const clientName = s.clientName || (s.respondentRole === 'client' ? s.respondentName : s.partnerName) || 'Pasajero';
            const driverName = s.driverName || (s.respondentRole === 'driver' ? s.respondentName : s.partnerName) || 'Conductor';
            return { clientId, driverId, clientName, driverName };
        }

        function renderSanctionAction(uid, name, role) {
            if (!uid) return '';
            const safeName = (name || 'Usuario').replace(/'/g, "\\'");
            return `<button onclick="window.openSanctionModal('${uid}', '${safeName}', '${role}')" class="flex-1 min-w-[120px] bg-red-700 hover:bg-red-600 text-white text-[10px] py-2 rounded-xl font-black uppercase">Sancionar ${role === 'driver' ? 'conductor' : 'pasajero'}</button>`;
        }

