        window.markAllReportsAsSeen = async () => {
            if (!currentUser) return;
            const isMod = isAdminUser(currentUser, window.userProfile) || window.userProfile?.role === 'supervisor';
            if (!isMod) return window.showToast('Sin permiso.');

            if (!confirm('¿Marcar TODOS los pendientes como vistos? Esta acción se guardará permanentemente.')) return;

            const adminList = document.getElementById('admin-users-list');
            const supList = document.getElementById('supervisor-pending-list');
            const container = (window.currentAdminTab === 'reports' && adminList) ? adminList : supList;

            try {
                const now = serverTimestamp();
                const batchUpdates = [];

                // Reports
                const repSnap = await getDocs(collection(db, 'artifacts', appId, 'public', 'data', 'reports'));
                repSnap.docs.forEach(d => {
                    const data = d.data();
                    if (!data.handled) {
                        batchUpdates.push(updateDoc(doc(db, 'artifacts', appId, 'public', 'data', 'reports', d.id), {
                            handled: true, handledAt: now, handledBy: currentUser.uid
                        }));
                    }
                });

                // Surveys
                const survSnap = await getDocs(collection(db, 'artifacts', appId, 'public', 'data', 'cancellation_surveys'));
                survSnap.docs.forEach(d => {
                    const data = d.data();
                    if (!data.handled) {
                        batchUpdates.push(updateDoc(doc(db, 'artifacts', appId, 'public', 'data', 'cancellation_surveys', d.id), {
                            handled: true, handledAt: now, handledBy: currentUser.uid
                        }));
                    }
                });

                // App feedback
                const fbSnap = await getDocs(collection(db, 'artifacts', appId, 'public', 'data', 'app_feedback'));
                fbSnap.docs.forEach(d => {
                    const data = d.data();
                    if (data.status !== 'reviewed') {
                        batchUpdates.push(updateDoc(doc(db, 'artifacts', appId, 'public', 'data', 'app_feedback', d.id), {
                            status: 'reviewed', reviewedAt: now, reviewedBy: currentUser.uid, reviewedByName: window.userProfile?.name || 'Moderador'
                        }));
                    }
                });

                await Promise.all(batchUpdates);
                window.showToast('Todos los reportes marcados como vistos y guardados.', 'success');

                if (container) {
                    await window.loadReportsInto(container, { supervisor: !!supList });
                }
            } catch (e) {
                console.error('markAllReportsAsSeen:', e);
                window.showToast('Error al marcar todos como vistos.');
            }
        };

        window.loadReportsInto = async (container, opts = {}) => {
            if (!container) return;
            const U = window.OpsUi;
            const isSupervisorView = !!opts.supervisor || window.userProfile?.role === 'supervisor';
            container.innerHTML = window.OPS_LOADING_HTML || '<div class="ops-loading"><div class="ops-loading-ring"><i class="fas fa-spinner fa-spin"></i></div></div>';

            try {
                const [repSnap, surveySnap, feedbackSnap] = await Promise.all([
                    getDocs(collection(db, 'artifacts', appId, 'public', 'data', 'reports')),
                    getDocs(collection(db, 'artifacts', appId, 'public', 'data', 'cancellation_surveys')),
                    getDocs(collection(db, 'artifacts', appId, 'public', 'data', 'app_feedback'))
                ]);

                const reports = repSnap.docs.map((d) => ({ id: d.id, ...d.data() }));
                const surveys = surveySnap.docs.map((d) => ({ id: d.id, ...d.data() }));
                const feedback = feedbackSnap.docs
                    .map((d) => ({ id: d.id, ...d.data() }))
                    .sort((a, b) => alertTimestampMs(b) - alertTimestampMs(a));

                // Separate pending vs handled
                const pendingReports = reports.filter(r => !r.handled);
                const handledReports = reports.filter(r => r.handled);

                const pendingFraud = surveys.filter(s => s.fraudFlag && !s.handled);
                const handledFraud = surveys.filter(s => s.fraudFlag && s.handled);

                const pendingSafety = surveys.filter(s => s.safetySerious && !s.fraudFlag && !s.handled);
                const handledSafety = surveys.filter(s => s.safetySerious && !s.fraudFlag && s.handled);

                const pendingNormal = surveys.filter(s => !s.fraudFlag && !s.safetySerious && !s.handled);
                const handledNormal = surveys.filter(s => !s.fraudFlag && !s.safetySerious && s.handled);

                const pendingFeedback = feedback.filter(f => f.status !== 'reviewed');
                const handledFeedback = feedback.filter(f => f.status === 'reviewed');

                const totalPending = pendingReports.length + pendingFraud.length + pendingSafety.length + pendingNormal.length + pendingFeedback.length;

                if (reports.length === 0 && surveys.length === 0 && feedback.length === 0) {
                    container.innerHTML = U?.page(U.empty('fa-clipboard-check', 'Sin reportes', 'No hay alertas ni feedback pendientes.')) || '';
                    return;
                }

                // === DASHBOARD STATS ===
                const statsHtml = `
                    <div class="grid grid-cols-2 md:grid-cols-4 gap-3 mb-4">
                        <div class="bg-red-900/30 border border-red-700 rounded-2xl p-3 text-center">
                            <div class="text-2xl font-black text-red-400">${totalPending}</div>
                            <div class="text-xs font-bold uppercase tracking-widest text-red-300">Pendientes</div>
                        </div>
                        <div class="bg-red-900/30 border border-red-700 rounded-2xl p-3 text-center">
                            <div class="text-2xl font-black text-red-400">${pendingFraud.length + pendingSafety.length}</div>
                            <div class="text-xs font-bold uppercase tracking-widest text-red-300">Fraude + Seguridad</div>
                        </div>
                        <div class="bg-amber-900/30 border border-amber-700 rounded-2xl p-3 text-center">
                            <div class="text-2xl font-black text-amber-400">${pendingReports.length}</div>
                            <div class="text-xs font-bold uppercase tracking-widest text-amber-300">Reportes de viajes</div>
                        </div>
                        <div class="bg-cyan-900/30 border border-cyan-700 rounded-2xl p-3 text-center">
                            <div class="text-2xl font-black text-cyan-400">${pendingFeedback.length}</div>
                            <div class="text-xs font-bold uppercase tracking-widest text-cyan-300">Feedback App</div>
                        </div>
                    </div>
                `;

                let dashboardHtml = '';

                // === PENDIENTES (Dashboard principal) ===
                let pendingHtml = '';

                // Urgentes primero
                if (pendingFraud.length > 0 || pendingSafety.length > 0) {
                    pendingHtml += `<div class="mb-3"><div class="font-black text-red-400 text-xs uppercase tracking-widest mb-1">🔴 Urgentes</div>`;
                    pendingFraud.forEach(s => { pendingHtml += renderCancellationSurveyAdminCard(s, 'fraud'); });
                    pendingSafety.forEach(s => { pendingHtml += renderCancellationSurveyAdminCard(s, 'safety'); });
                    pendingHtml += `</div>`;
                }

                if (pendingReports.length > 0) {
                    pendingHtml += `<div class="mb-3"><div class="font-black text-amber-400 text-xs uppercase tracking-widest mb-1">🚩 Reportes de Viajes</div>`;
                    pendingReports.forEach(r => { pendingHtml += renderTripReportCard(r); });
                    pendingHtml += `</div>`;
                }

                if (pendingFeedback.length > 0) {
                    pendingHtml += `<div class="mb-3"><div class="font-black text-cyan-400 text-xs uppercase tracking-widest mb-1">📥 Feedback de la App</div>`;
                    pendingFeedback.forEach(f => { pendingHtml += renderAppFeedbackCard(f, { isAdmin: true }); });
                    pendingHtml += `</div>`;
                }

                if (pendingNormal.length > 0) {
                    pendingHtml += `<div class="mb-3"><div class="font-black text-gray-400 text-xs uppercase tracking-widest mb-1">📋 Encuestas Normales</div>`;
                    pendingNormal.forEach(s => { pendingHtml += renderCancellationSurveyAdminCard(s, 'normal'); });
                    pendingHtml += `</div>`;
                }

                if (pendingHtml) {
                    const markAllBtn = `
                        <div class="mb-3 text-right">
                            <button onclick="window.markAllReportsAsSeen?.()" 
                                    class="text-xs bg-emerald-700 hover:bg-emerald-600 px-3 py-1.5 rounded-xl font-bold text-white">
                                ✓ MARCAR TODOS COMO VISTOS
                            </button>
                        </div>`;
                    dashboardHtml += U.section({
                        title: '📋 Pendientes por revisar',
                        subtitle: 'Elementos sin marcar como vistos',
                        icon: 'fa-exclamation-circle',
                        variant: 'red',
                        badge: totalPending,
                        body: markAllBtn + pendingHtml
                    });
                } else {
                    dashboardHtml += U.empty('fa-check-circle', 'Todo al día', 'No hay elementos pendientes.');
                }

                // === REVISADOS (collapsible dashboard section) ===
                let handledHtml = '';

                if (handledReports.length > 0) {
                    handledReports.slice(0, 8).forEach(r => { handledHtml += renderTripReportCard(r); });
                }
                if (handledFraud.length > 0 || handledSafety.length > 0) {
                    handledFraud.slice(0, 5).forEach(s => { handledHtml += renderCancellationSurveyAdminCard(s, 'fraud'); });
                    handledSafety.slice(0, 5).forEach(s => { handledHtml += renderCancellationSurveyAdminCard(s, 'safety'); });
                }
                if (handledFeedback.length > 0) {
                    handledFeedback.slice(0, 8).forEach(f => { handledHtml += renderAppFeedbackCard(f, { isAdmin: true }); });
                }

                if (handledHtml) {
                    dashboardHtml += U.section({
                        title: '✅ Revisados',
                        icon: 'fa-check-double',
                        variant: 'default',
                        badge: handledReports.length + handledFraud.length + handledSafety.length + handledFeedback.length,
                        body: handledHtml,
                        collapsible: true,
                        open: false
                    });
                }

                const title = isSupervisorView ? 'Dashboard de Reportes' : 'Dashboard de Reportes y Moderación';
                const subtitle = 'Alertas, quejas y feedback • Supervisores y Admins';

                container.innerHTML = U.page(
                    U.hero(title, subtitle, '') +
                    statsHtml +
                    dashboardHtml
                );

                await markReportsSeen();
            } catch (e) {
                console.error('loadReportsInto:', e);
                container.innerHTML = U?.page(`<p class="text-red-400 text-center font-bold py-8">Error al cargar reportes</p>`) || '';
            }
        };

        function updateModerationBadges(count) {
            ['admin-reports-badge', 'supervisor-reports-badge'].forEach((id) => {
                const badge = document.getElementById(id);
                if (!badge) return;
                if (count > 0) {
                    badge.textContent = count > 99 ? '99+' : String(count);
                    badge.classList.remove('hidden');
                } else {
                    badge.classList.add('hidden');
                }
            });
        }

        function updatePendingVerificationBadge(count) {
            const badge = document.getElementById('supervisor-pending-badge');
            if (!badge) return;
            if (count > 0) {
                badge.textContent = count > 99 ? '99+' : String(count);
                badge.classList.remove('hidden');
            } else {
                badge.classList.add('hidden');
            }
        }

        async function countPendingVerifications() {
            const usersSnap = await getDocs(collection(db, 'artifacts', appId, 'public', 'data', 'users'));
            let count = 0;
            usersSnap.forEach((d) => {
                const u = d.data();
                if (u.role === 'driver' && (u.approvalStatus === 'pending' || driverHasPendingVehicleVerification(u))) {
                    count++;
                    return;
                }
                if (u.role === 'client' && u.approvalStatus === 'pending' && canStaffApprovePassenger(u)) count++;
            });
            return count;
        }

        async function checkPendingVerifications() {
            if (!currentUser) return;
            if (!canManageUsers()) return;
            try {
                const count = await countPendingVerifications();
                updatePendingVerificationBadge(count);
                if (count > 0) {
                    const msg = count === 1
                        ? 'Hay 1 verificación de identidad pendiente.'
                        : `Hay ${count} verificaciones de identidad pendientes.`;
                    notifyTripEvent({
                        title: 'Verificaciones pendientes',
                        body: msg,
                        tag: 'verification-pending',
                        force: true
                    });
                }
            } catch (e) {
                console.warn('checkPendingVerifications:', e);
            }
        }

        function alertTimestampMs(entry) {
            const ts = entry.createdAt;
            if (!ts) return 0;
            return ts.toMillis ? ts.toMillis() : (ts.seconds ? ts.seconds * 1000 : new Date(ts).getTime());
        }

        function isModerationAlert(entry, kind) {
            if (kind === 'survey') {
                return !!(entry.fraudFlag || entry.safetySerious);
            }
            return entry.type === 'cancellation_fraud' || entry.type === 'cancellation_safety'
                || (entry.text || '').includes('[FRAUDE]') || (entry.text || '').includes('[SEGURIDAD]');
        }

        async function countUnreadModerationAlerts() {
            const lastSeen = window.userProfile?.lastSeenReportsAt || 0;
            const [repSnap, surveySnap, feedbackSnap] = await Promise.all([
                getDocs(collection(db, 'artifacts', appId, 'public', 'data', 'reports')),
                getDocs(collection(db, 'artifacts', appId, 'public', 'data', 'cancellation_surveys')),
                getDocs(collection(db, 'artifacts', appId, 'public', 'data', 'app_feedback'))
            ]);

            let count = 0;
            repSnap.docs.forEach((d) => {
                const data = d.data();
                if (isModerationAlert(data, 'report') && alertTimestampMs(data) > lastSeen) count++;
            });
            surveySnap.docs.forEach((d) => {
                const data = d.data();
                if (isModerationAlert(data, 'survey') && alertTimestampMs(data) > lastSeen) count++;
            });
            feedbackSnap.docs.forEach((d) => {
                const data = d.data();
                if (isAppFeedbackAlert(data) && data.status !== 'reviewed' && alertTimestampMs(data) > lastSeen) count++;
            });
            return count;
        }

        async function markReportsSeen() {
            if (!currentUser) return;
            const ts = Date.now();
            try {
                await updateDoc(doc(db, 'artifacts', appId, 'public', 'data', 'users', currentUser.uid), {
                    lastSeenReportsAt: ts
                });
                await updateDoc(doc(db, 'artifacts', appId, 'users', currentUser.uid, 'profile', 'data'), {
                    lastSeenReportsAt: ts
                }).catch(() => {});
                window.userProfile.lastSeenReportsAt = ts;
            } catch (_) {}
            updateModerationBadges(0);
        }

        async function checkUnreadModerationAlerts() {
            if (!currentUser) return;
            const isMod = isAdminUser(currentUser, window.userProfile) || window.userProfile?.role === 'supervisor';
            if (!isMod) return;

            try {
                const count = await countUnreadModerationAlerts();
                updateModerationBadges(count);
                if (count > 0) {
                    const msg = count === 1
                        ? 'Tienes 1 reporte sin revisar (app, fraude o seguridad).'
                        : `Tienes ${count} reportes sin revisar (app, fraude o seguridad).`;
                    window.showToast(msg, 'warning');
                    notifyTripEvent({
                        title: 'Alertas pendientes',
                        body: msg,
                        tag: 'moderation-unread',
                        force: true
                    });
                }
            } catch (e) {
                console.warn('checkUnreadModerationAlerts:', e);
            }
        }

        window.loadSupervisorReports = async () => {
            window.setSupervisorNavActive?.('reports');
            const container = document.getElementById('supervisor-pending-list');
            await window.loadReportsInto(container, { supervisor: true });

            // Pequeño acceso rápido al reporte estilo admin (si lo prefieren)
            setTimeout(() => {
                if (container && !container.querySelector('#admin-reports-link')) {
                    const link = document.createElement('div');
                    link.id = 'admin-reports-link';
                    link.className = 'text-center mt-3';
                    link.innerHTML = `<button onclick="window.openAdminReports?.()" class="text-xs px-3 py-1 bg-gray-800 hover:bg-gray-700 rounded-full font-bold text-gray-300">Abrir Reportes en Panel Admin →</button>`;
                    container.appendChild(link);
                }
            }, 400);
        };

        window.openSanctionModal = (uid, name, role) => {
            const roleLabel = role === 'driver' ? 'conductor' : 'pasajero';
            const modal = document.createElement('div');
            modal.className = 'fixed inset-0 bg-black/70 z-[50000] flex items-center justify-center p-4';
            modal.innerHTML = `
                <div class="bg-white rounded-3xl w-full max-w-sm p-6">
                    <h3 class="font-black text-lg mb-1">Sancionar ${roleLabel}</h3>
                    <p class="text-sm text-gray-600 mb-4">${name}</p>
                    <label class="text-[10px] font-black text-gray-500 uppercase tracking-widest">Días de suspensión / veto</label>
                    <select id="sanction-days-select" class="w-full mt-2 mb-3 border-2 border-gray-200 rounded-2xl p-3 text-sm font-bold">
                        <option value="1">1 día</option>
                        <option value="3">3 días</option>
                        <option value="7" selected>7 días</option>
                        <option value="14">14 días</option>
                        <option value="30">30 días</option>
                        <option value="90">90 días</option>
                    </select>
                    <input id="sanction-days-custom" type="number" min="1" max="365" placeholder="O escribe días personalizados"
                           class="w-full mb-4 border-2 border-gray-200 rounded-2xl p-3 text-sm">
                    <div class="flex gap-2">
                        <button onclick="this.closest('.fixed').remove()" class="flex-1 py-3 rounded-2xl border font-bold text-sm">Cancelar</button>
                        <button id="sanction-confirm-btn" class="flex-1 py-3 rounded-2xl bg-red-600 text-white font-black text-sm">APLICAR SANCION</button>
                    </div>
                </div>
            `;
            document.body.appendChild(modal);
            modal.querySelector('#sanction-confirm-btn').onclick = async () => {
                const custom = parseInt(modal.querySelector('#sanction-days-custom')?.value, 10);
                const selected = parseInt(modal.querySelector('#sanction-days-select')?.value, 10);
                const days = custom > 0 ? custom : selected;
                if (!days || days < 1) return window.showToast('Indica cuántos días de sanción.');
                modal.remove();
                await window.applySanction(uid, role, days, name);
            };
        };

        window.applySanction = async (uid, role, days, name = '') => {
            if (!uid || !days) return;
            if (!canManageUsers()) {
                return window.showToast('Solo administradores y supervisores pueden sancionar.');
            }
            const until = Date.now() + days * 24 * 60 * 60 * 1000;

            try {
                if (role === 'driver') {
                    await moderationWriteUser(uid, {
                        approvalStatus: 'suspended',
                        suspendedAt: serverTimestamp(),
                        suspendedUntil: until,
                        suspendedReason: 'manual_sanction',
                        sanctionDays: days,
                        autoSuspended: false
                    });
                } else {
                    await moderationWriteUser(uid, {
                        accountRestricted: true,
                        accountRestrictedAt: serverTimestamp(),
                        restrictedUntil: until,
                        accountRestrictedReason: 'manual_sanction',
                        sanctionDays: days,
                        approvalStatus: 'suspended'
                    });
                }
                window.showToast(`${name || 'Usuario'} sancionado por ${days} día(s).`, 'success');
                if (window.currentAdminTab === 'reports') {
                    await window.loadReportsInto(document.getElementById('admin-users-list'));
                }
                if (document.getElementById('sup-tab-reports')?.classList.contains('ops-nav-item--active')) {
                    await window.loadSupervisorReports();
                }
            } catch (e) {
                showModerationError(e, 'aplicar sanción');
            }
        };

        async function checkSanctionExpiry(profile, uid) {
            if (!profile || !uid) return profile;
            const now = Date.now();
            let updates = null;

            if (profile.approvalStatus === 'suspended' && profile.suspendedUntil && profile.suspendedUntil < now) {
                updates = {
                    approvalStatus: 'approved',
                    suspendedAt: null,
                    suspendedUntil: null,
                    suspendedReason: null,
                    sanctionDays: null
                };
            }
            if (profile.accountRestricted && profile.restrictedUntil && profile.restrictedUntil < now) {
                updates = {
                    ...updates,
                    accountRestricted: false,
                    accountRestrictedAt: null,
                    restrictedUntil: null,
                    accountRestrictedReason: null,
                    sanctionDays: null
                };
            }
            if (updates) {
                await updateDoc(doc(db, 'artifacts', appId, 'public', 'data', 'users', uid), updates).catch(() => {});
                await updateDoc(doc(db, 'artifacts', appId, 'users', uid, 'profile', 'data'), updates).catch(() => {});
                return { ...profile, ...updates };
            }
            return profile;
        }

        function startModerationAlertListener() {
            if (!currentUser) return;
            const isMod = isAdminUser(currentUser, window.userProfile) || window.userProfile?.role === 'supervisor';
            if (!isMod) return;

            if (window.moderationAlertsUnsub) return;

            try {
                const known = new Set(JSON.parse(localStorage.getItem('honduber_known_alerts') || '[]'));
                window._knownModerationAlerts = known;
            } catch (_) {
                window._knownModerationAlerts = new Set();
            }

            const notifyAlert = async (title, body, id) => {
                if (window._knownModerationAlerts.has(id)) return;
                window._knownModerationAlerts.add(id);
                try {
                    localStorage.setItem('honduber_known_alerts', JSON.stringify([...window._knownModerationAlerts].slice(-200)));
                } catch (_) {}

                window.showToast(body, 'warning');
                notifyTripEvent({ title, body, tag: `mod-alert-${id}`, force: true });
                try {
                    const count = await countUnreadModerationAlerts();
                    updateModerationBadges(count);
                } catch (_) {}
            };

            let surveysReady = false;
            const onModListenError = (err) => console.warn('moderation listener:', err?.code || err);
            const surveysUnsub = onSnapshot(collection(db, 'artifacts', appId, 'public', 'data', 'cancellation_surveys'), (snap) => {
                if (!surveysReady) {
                    snap.docs.forEach((d) => window._knownModerationAlerts.add(`survey-${d.id}`));
                    try {
                        localStorage.setItem('honduber_known_alerts', JSON.stringify([...window._knownModerationAlerts].slice(-200)));
                    } catch (_) {}
                    surveysReady = true;
                    return;
                }
                snap.docChanges().forEach((change) => {
                    if (change.type !== 'added') return;
                    const d = change.doc.data();
                    const id = `survey-${change.doc.id}`;
                    if (d.fraudFlag) {
                        notifyAlert('Alerta de fraude', `Nueva encuesta de fraude: ${d.respondentName || 'Usuario'}`, id);
                    } else if (d.safetySerious) {
                        notifyAlert('Alerta de seguridad', `Nueva alerta de seguridad: ${d.respondentName || 'Usuario'}`, id);
                    }
                });
            }, onModListenError);

            let reportsReady = false;
            const reportsUnsub = onSnapshot(collection(db, 'artifacts', appId, 'public', 'data', 'reports'), (snap) => {
                if (!reportsReady) {
                    snap.docs.forEach((d) => window._knownModerationAlerts.add(`report-${d.id}`));
                    try {
                        localStorage.setItem('honduber_known_alerts', JSON.stringify([...window._knownModerationAlerts].slice(-200)));
                    } catch (_) {}
                    reportsReady = true;
                    return;
                }
                snap.docChanges().forEach((change) => {
                    if (change.type !== 'added') return;
                    const d = change.doc.data();
                    const id = `report-${change.doc.id}`;
                    if (d.type === 'cancellation_fraud' || d.text?.includes('[FRAUDE]')) {
                        notifyAlert('Reporte de fraude', d.text?.slice(0, 120) || 'Nuevo reporte de fraude', id);
                    } else if (d.type === 'cancellation_safety' || d.text?.includes('[SEGURIDAD]')) {
                        notifyAlert('Reporte de seguridad', d.text?.slice(0, 120) || 'Nuevo reporte de seguridad', id);
                    }
                });
            }, onModListenError);

            window.moderationAlertsUnsub = () => {
                surveysUnsub();
                reportsUnsub();
            };
        }

        function showCancellationSurvey(tripData) {
            if (!tripData?.id) return;
            cancelledTripSnapshot = { ...tripData };
            window.cancellationSurveyTripId = tripData.id;

            const iCancelled = tripData.cancelledBy === currentUser.uid;
            const subtitle = document.getElementById('cancellation-survey-subtitle');
            if (subtitle) {
                subtitle.innerText = iCancelled
                    ? 'Cancelaste un viaje ya confirmado. Cuéntanos qué pasó para continuar usando la app.'
                    : 'Se canceló un viaje confirmado. Tu respuesta ayuda a proteger la plataforma y reportar situaciones incómodas o inseguras.';
            }

            resetCancellationSurveyForm();
            document.getElementById('app-interface').style.display = 'none';
            document.getElementById('rating-screen').style.display = 'none';
            document.getElementById('cancellation-survey-screen').style.display = 'flex';

            // Mostrar botón de cerrar solo para admins
            const closeBtn = document.getElementById('cancellation-survey-close-btn');
            if (closeBtn) {
                if (isAdminUser(currentUser, window.userProfile)) {
                    closeBtn.classList.remove('hidden');
                } else {
                    closeBtn.classList.add('hidden');
                }
            }
        }

        function finishCancelledTrip(tripId, data) {
            window._cancellingTripIds?.delete(tripId);
            markCancelledTripHandled(tripId);
            window.cancellationSurveyTripId = null;
            cancelledTripSnapshot = null;

            resetAfterTripEnds();

            clearStoredClientTripId();

            // No borrar búsquedas canceladas: admin/supervisor las ven en Viajes activos
            // (nombre + teléfono) para poder contactar después.
        }

        function handleTripCancelled(tripId, data) {
            if (window.handledCancelledTripIds.has(tripId)) return;
            // Si el pasajero estaba en espera, cortar el sonido en bucle
            try { stopPassengerWaitingLoop(); } catch (_) {}

            // Pre-accept (pending) cancel must NEVER trigger the cancellation questionnaire
            const fromStatus = data?.cancelledFromStatus;
            if (fromStatus === 'pending' || fromStatus === 'scheduled') {
                const iCancelled = data.cancelledBy === currentUser.uid;
                window.showToast(iCancelled ? 'Viaje cancelado correctamente.' : 'El otro participante canceló el viaje.', 'warning');
                finishCancelledTrip(tripId, data);
                return;
            }

            const needsSurvey = isConfirmedCancellation(data) && !userAlreadySubmittedCancellationSurvey(data);
            const iCancelled = data.cancelledBy === currentUser.uid;
            const msg = needsSurvey
                ? (iCancelled
                    ? 'Viaje cancelado. Completa la encuesta para continuar.'
                    : 'Viaje cancelado. Debes completar la encuesta de seguridad.')
                : (iCancelled
                    ? 'Viaje cancelado correctamente.'
                    : 'El otro participante canceló el viaje.');
            window.showToast(msg, 'warning');

            if (needsSurvey) {
                if (window.cancellationSurveyTripId === tripId) return;
                showCancellationSurvey({ id: tripId, ...data });
                return;
            }

            finishCancelledTrip(tripId, data);
        }

        window.closeCancellationSurveyForAdmin = () => {
            if (!isAdminUser(currentUser, window.userProfile)) {
                window.showToast('Solo los administradores pueden cerrar la encuesta sin enviarla.');
                return;
            }

            const screen = document.getElementById('cancellation-survey-screen');
            const tripId = window.cancellationSurveyTripId;

            if (screen) screen.style.display = 'none';

            const appInt = document.getElementById('app-interface');
            if (appInt) appInt.style.display = 'flex';

            window.cancellationSurveyTripId = null;
            cancelledTripSnapshot = null;

            try {
                if (tripId) markCancelledTripHandled(tripId);
                resetAfterTripEnds();
            } catch (e) {
                console.warn('Error restaurando UI después de cerrar encuesta admin:', e);
            }

            // Asegurar vistas según rol + refrescar si es admin en panel de pruebas
            try {
                const isAdmin = isAdminUser(currentUser, window.userProfile);
                if (window.userProfile?.role === 'driver') {
                    document.getElementById('client-view')?.classList.add('hidden');
                    document.getElementById('driver-view')?.classList.remove('hidden');
                } else if (window.userProfile?.role === 'client') {
                    document.getElementById('driver-view')?.classList.add('hidden');
                    if (window.userProfile?.role === 'client') document.getElementById('client-view')?.classList.remove('hidden');
                } else {
                    document.getElementById('client-view')?.classList.add('hidden');
                    document.getElementById('driver-view')?.classList.add('hidden');
                }
                window.showControlPanel?.();

                // Si es admin y estaba en el laboratorio, refrescar el panel para evitar pantalla en blanco
                if (isAdmin && window.currentAdminTab === 'testing' && typeof window.loadAdminTestingPanel === 'function') {
                    setTimeout(() => {
                        try { window.loadAdminTestingPanel(); } catch (_) {}
                    }, 120);
                }
            } catch (_) {}

            // Forzar limpieza extra de posibles overlays/estados que dejan la pantalla en blanco
            try {
                document.body.classList.remove('trip-active', 'is-searching', 'is-navigating');
            clearPassengerSearchPanelLayout();
                window.restoreControlPanelAfterDriverTrip?.();
                const atp = document.getElementById('active-trip-panel');
            if (atp) {
              const isMobile = window.innerWidth < 768;
              if (isMobile && document.body.classList.contains('trip-active')) {
                // On cell phones: the central trip panel MUST only disappear when user taps minimize.
                // Do not add 'hidden' automatically.
              } else {
                atp.classList.add('hidden');
              }
            }
                document.getElementById('searching-state')?.classList.add('hidden');
                document.getElementById('eta-indicator')?.classList.add('hidden');
                document.getElementById('trip-partner-info')?.classList.add('hidden');
                document.getElementById('fare-card')?.classList.add('hidden');
            } catch (_) {}

            window.showToast('Encuesta de cancelación cerrada por administrador (sin enviar).', 'success');
        };

        window.submitCancellationSurvey = async () => {
            const trip = cancelledTripSnapshot;
            if (!trip?.id || !currentUser) return location.reload();

            const answers = {
                cancelPoint: getCheckedSurveyValue('cancel-point'),
                whoProposed: getCheckedSurveyValue('cancel-who'),
                reason: getCheckedSurveyValue('cancel-reason'),
                communication: getCheckedSurveyValue('cancel-communication'),
                incident: getCheckedSurveyValue('cancel-incident'),
                serviceAgreement: getCheckedSurveyValue('cancel-agreement'),
                contactShared: getCheckedSurveyValue('cancel-contact'),
                tripWillContinue: getCheckedSurveyValue('cancel-continue')
            };
            const comments = document.getElementById('cancellation-survey-comments')?.value?.trim() || '';

            const required = Object.values(answers);
            if (required.some((v) => !v)) {
                return window.showToast('Responde todas las preguntas obligatorias de la encuesta.');
            }

            const flags = computeCancellationSurveyFlags(answers);
            const role = window.userProfile?.role === 'driver' ? 'driver' : 'client';
            const partnerId = role === 'client' ? trip.driverId : trip.clientId;
            const partnerName = role === 'client' ? trip.driverName : trip.clientName;
            const partnerRole = role === 'client' ? 'driver' : 'client';
            const surveyField = role === 'client' ? 'cancellationSurveyByClient' : 'cancellationSurveyByDriver';
            const partnerAtFault = flags.fraudFlag
                || answers.incident !== 'nothing'
                || answers.communication === 'uncomfortable'
                || answers.communication === 'tense';
            const shouldModeratePartner = partnerId
                && partnerId !== currentUser.uid
                && partnerAtFault
                && (flags.fraudFlag || flags.safetySerious || flags.safetyConcern);

            try {
                const surveyRef = await addDoc(collection(db, 'artifacts', appId, 'public', 'data', 'cancellation_surveys'), {
                    tripId: trip.id,
                    respondentId: currentUser.uid,
                    respondentRole: role,
                    respondentName: window.userProfile?.name || 'Usuario',
                    clientId: trip.clientId || null,
                    driverId: trip.driverId || null,
                    clientName: trip.clientName || null,
                    driverName: trip.driverName || null,
                    cancelledBy: trip.cancelledBy || null,
                    cancelledFromStatus: trip.cancelledFromStatus || null,
                    cancelPoint: answers.cancelPoint,
                    whoProposed: answers.whoProposed,
                    reason: answers.reason,
                    reasonLabel: CANCEL_REASON_LABELS[answers.reason] || answers.reason,
                    communication: answers.communication,
                    incident: answers.incident,
                    incidentLabel: CANCEL_INCIDENT_LABELS[answers.incident] || answers.incident,
                    serviceAgreement: answers.serviceAgreement,
                    contactShared: answers.contactShared,
                    tripWillContinue: answers.tripWillContinue,
                    comments,
                    fraudFlag: flags.fraudFlag,
                    fraudSignals: flags.fraudSignals,
                    safetyFlag: flags.safetyFlag,
                    safetySerious: flags.safetySerious,
                    partnerId: partnerId || null,
                    partnerName: partnerName || null,
                    origin: trip.origin || null,
                    destination: trip.destination || null,
                    price: trip.price || null,
                    createdAt: serverTimestamp()
                });

                try {
                    await updateDoc(doc(db, 'artifacts', appId, 'public', 'data', 'trips', trip.id), {
                        [surveyField]: true
                    });
                } catch (tripErr) {
                    console.error('survey trip flag:', tripErr);
                }

                let moderation = { actionTaken: false, suspended: false };
                if (shouldModeratePartner) {
                    try {
                        moderation = await applyPartnerModeration(partnerId, partnerRole, flags);
                    } catch (modErr) {
                        console.error('partner moderation:', modErr);
                    }
                }

                if (flags.fraudFlag || flags.safetySerious) {
                    const alertType = flags.fraudFlag ? 'FRAUDE' : 'SEGURIDAD';
                    try {
                        await addDoc(collection(db, 'artifacts', appId, 'public', 'data', 'reports'), {
                            type: flags.fraudFlag ? 'cancellation_fraud' : 'cancellation_safety',
                            tripId: trip.id,
                            surveyId: surveyRef.id,
                            stars: 1,
                            text: `[${alertType}] ${CANCEL_REASON_LABELS[answers.reason] || answers.reason}. ${CANCEL_INCIDENT_LABELS[answers.incident] || ''}. Señales: ${flags.fraudSignals.join(', ') || 'ninguna'}. ${comments}`.trim(),
                            reportedRole: partnerRole,
                            reportedUserId: partnerId || null,
                            reportedUserName: partnerName || null,
                            clientId: trip.clientId || null,
                            driverId: trip.driverId || null,
                            clientName: trip.clientName || null,
                            driverName: trip.driverName || null,
                            reportedByName: window.userProfile?.name || 'Usuario',
                            reportedBy: currentUser.uid,
                            createdAt: serverTimestamp()
                        });
                    } catch (repErr) {
                        console.error('survey report:', repErr);
                    }
                }

                if (moderation.suspended) {
                    window.showToast(
                        partnerRole === 'driver'
                            ? 'Encuesta enviada. El conductor acumuló alertas y fue suspendido automáticamente.'
                            : 'Encuesta enviada. La cuenta del pasajero fue restringida automáticamente.',
                        'warning'
                    );
                } else {
                    window.showToast('Encuesta enviada. Gracias por ayudar a proteger la plataforma.', 'success');
                }

                finishCancelledTrip(trip.id, trip);
                location.reload();
            } catch (e) {
                console.error('submitCancellationSurvey:', e);
                window.showToast('No se pudo enviar la encuesta. Intenta de nuevo.');
            }
        };
        function sortTripsByNewest(trips) {
            return [...trips].sort((a, b) => {
                const ta = a.createdAt?.toMillis?.() || a.createdAt || 0;
                const tb = b.createdAt?.toMillis?.() || b.createdAt || 0;
                return tb - ta;
            });
        }

        function isDemandSimulationTrip(trip) {
            return !!trip?.isDemandSimulation
                || !!trip?.demandSimPreset
                || trip?.clientName === 'Admin · Prueba demanda';
        }

        function getRatedFieldForUser(trip, uid = currentUser?.uid) {
            if (!trip || !uid) return 'ratedByClient';
            return trip.clientId === uid ? 'ratedByClient' : 'ratedByDriver';
        }

        function findMyPendingClientTrip(snap) {
            const pending = snap.docs
                .map((d) => ({ id: d.id, ...d.data() }))
                .filter((t) => t.status === 'pending' && t.clientId === currentUser.uid && !isDemandSimulationTrip(t));
            return sortTripsByNewest(pending)[0] || null;
        }

        function findMyActiveClientTrip(snap) {
            const statusPriority = { in_progress: 50, accepted: 40 };
            const active = snap.docs
                .map((d) => ({ id: d.id, ...d.data() }))
                .filter((t) =>
                    t.clientId === currentUser.uid
                    && !isDemandSimulationTrip(t)
                    && ['accepted', 'in_progress'].includes(t.status)
                );
            if (!active.length) return null;
            active.sort((a, b) => {
                const diff = (statusPriority[b.status] || 0) - (statusPriority[a.status] || 0);
                if (diff !== 0) return diff;
                const ta = a.createdAt?.toMillis?.() || a.createdAt || 0;
                const tb = b.createdAt?.toMillis?.() || b.createdAt || 0;
                return tb - ta;
            });
            return active[0];
        }

        function sortClientTripsByPriority(trips) {
            const statusPriority = { in_progress: 50, accepted: 40, pending: 30 };
            return trips.sort((a, b) => {
                const diff = (statusPriority[b.status] || 0) - (statusPriority[a.status] || 0);
                if (diff !== 0) return diff;
                const ta = a.createdAt?.toMillis?.() || a.createdAt || 0;
                const tb = b.createdAt?.toMillis?.() || b.createdAt || 0;
                return tb - ta;
            });
        }

        const CLIENT_ACTIVE_TRIP_LS_KEY = 'honduber_active_trip_id';
        const CLIENT_ACTIVE_TRIP_SS_KEY = 'honduber_pending_trip_id';

        function getStoredClientTripId() {
            try {
                return localStorage.getItem(CLIENT_ACTIVE_TRIP_LS_KEY)
                    || sessionStorage.getItem(CLIENT_ACTIVE_TRIP_SS_KEY);
            } catch (_) { return null; }
        }

        function setStoredClientTripId(tripId) {
            if (!tripId) return;
            try {
                localStorage.setItem(CLIENT_ACTIVE_TRIP_LS_KEY, tripId);
                sessionStorage.setItem(CLIENT_ACTIVE_TRIP_SS_KEY, tripId);
            } catch (_) {}
        }

        function clearStoredClientTripId() {
            try {
                localStorage.removeItem(CLIENT_ACTIVE_TRIP_LS_KEY);
                sessionStorage.removeItem(CLIENT_ACTIVE_TRIP_SS_KEY);
            } catch (_) {}
        }

        function findMyRelevantTrip(snap) {
            const statusPriority = { in_progress: 50, accepted: 40, scheduled: 35, pending: 30, completed: 10, cancelled: 5 };
            const role = window.userProfile?.role;

            if (role === 'client') {
                const storedId = getStoredClientTripId() || activeTrip?.id;
                if (storedId) {
                    const storedDoc = snap.docs.find((d) => d.id === storedId);
                    if (storedDoc) {
                        const t = { id: storedDoc.id, ...storedDoc.data() };
                        if (isDemandSimulationTrip(t)) { /* ignorar prueba admin */ }
                        else if (t.status === 'completed' && t[getRatedFieldForUser(t)]) { /* continuar */ }
                        else if (t.status === 'cancelled' && window.handledCancelledTripIds.has(t.id)) { /* continuar */ }
                        else if (['pending', 'accepted', 'in_progress', 'scheduled', 'completed', 'cancelled'].includes(t.status)) {
                            return t;
                        }
                    }
                }

                const pending = findMyPendingClientTrip(snap);
                if (pending) return pending;

                // Programado ya reservado con conductor
                const scheduledReserved = snap.docs
                    .map((d) => ({ id: d.id, ...d.data() }))
                    .filter((t) => t.status === 'scheduled' && t.clientId === currentUser.uid && t.driverId && !isDemandSimulationTrip(t));
                if (scheduledReserved.length) {
                    return sortTripsByNewest(scheduledReserved)[0];
                }

                const active = findMyActiveClientTrip(snap);
                if (active) return active;
            }

            const candidates = snap.docs
                .map((d) => ({ id: d.id, ...d.data() }))
                .filter((t) => {
                    if (isDemandSimulationTrip(t)) return false;
                    if (t.status === 'cancelled' && window.handledCancelledTripIds.has(t.id)) return false;
                    const isMine = t.clientId === currentUser.uid || t.driverId === currentUser.uid;
                    if (!isMine) return false;
                    if (t.status === 'completed') return !t[getRatedFieldForUser(t)];
                    // scheduled con driver: reserva programada del conductor
                    if (t.status === 'scheduled') return !!t.driverId && t.driverId === currentUser.uid;
                    return ['pending', 'accepted', 'cancelled', 'in_progress'].includes(t.status);
                });

            if (candidates.length === 0) return null;

            candidates.sort((a, b) => {
                const diff = (statusPriority[b.status] || 0) - (statusPriority[a.status] || 0);
                if (diff !== 0) return diff;
                const ta = a.createdAt?.toMillis?.() || a.createdAt || 0;
                const tb = b.createdAt?.toMillis?.() || b.createdAt || 0;
                return tb - ta;
            });

            return candidates[0];
        }

        function updateSearchingDriverCard(data) {
            const card = document.getElementById('searching-driver-card');
            const title = document.getElementById('searching-driver-card-title');
            const sub = document.getElementById('searching-driver-card-sub');
            if (!card || !title || !sub) return;

            if (!data?.offeredToDriverId || getPassengerDriverOffers(data).length > 0) {
                card.classList.add('hidden');
                return;
            }

            const name = data.offeredToDriverName || 'Un conductor';
            const firstName = String(name).split(' ')[0];
            const dist = data.offerDistanceKm != null ? `${parseFloat(data.offerDistanceKm).toFixed(1)} km` : 'cerca';

            card.classList.remove('hidden');
            if (data.offerToBusyDriver) {
                title.innerHTML = `<i class="fas fa-user-check text-emerald-600"></i> ${firstName} está cerca (${dist}) terminando un viaje`;
                sub.textContent = 'Si acepta, quedas reservado: no pierdes tu turno y verás en el mapa cuándo viene por ti.';
            } else {
                title.innerHTML = `<i class="fas fa-bell text-emerald-600"></i> ${firstName} está viendo tu mensaje (${dist})`;
                sub.textContent = 'Tu mensaje ya está en su pantalla. En cuanto acepte, verás su ruta y tiempo estimado de llegada.';
            }
        }

        function getPendingTripViewedCount(viewedBy) {
            if (!viewedBy || typeof viewedBy !== 'object') return 0;
            return Object.values(viewedBy).filter((v) => v && v.name).length;
        }

        function getPendingTripUiSig(data) {
            const offers = getPassengerDriverOffers(data);
            const offerSig = offers.map((b) => `${b.driverId}:${b.price}:${b.distanceKm ?? ''}:${b.passengerCounterPrice ?? ''}`).join('|');
            const viewedCount = getPendingTripViewedCount(data?.viewedBy);
            return `${offerSig}:${data?.negotiatedPrice ?? ''}:${data?.negotiatedBy || ''}:${viewedCount}`;
        }

        const NO_DRIVERS_NOTIFY_COUNTDOWN_SEC = 120;

        /** Mensajes de retención durante la espera (120s) para que no salgan de la app. */
        const SEARCH_WAIT_RETENTION_TIPS = [
            'Quédate aquí — si sales, se detiene la búsqueda',
            'Tu mensaje ya va en camino a los conductores cercanos',
            'Un conductor puede responder en cualquier momento',
            'No cierres la app: te avisamos al instante cuando acepten',
            'Vale la pena esperar un poco más… ya están viendo tu viaje',
            'Cuando acepten, verás foto, placa y tiempo de llegada',
            'Seguimos avisando a más conductores de tu zona',
            'Casi listo — no te vayas todavía',
            'Los conductores revisan el precio y te escriben al aceptar',
            'Mantén la app abierta para no perder tu lugar en la fila',
            'Estamos trabajando para conectarte lo antes posible',
            'Gracias por tu paciencia — un momento más y alguien te responde'
        ];

        function getSearchWaitRetentionTip(state, remainingSec) {
            const total = NO_DRIVERS_NOTIFY_COUNTDOWN_SEC;
            const elapsed = Math.max(0, total - Math.max(0, remainingSec));
            // Cambia de tip cada ~10 segundos
            const tipIdx = Math.floor(elapsed / 10) % SEARCH_WAIT_RETENTION_TIPS.length;
            const cycle = state?.cycle || 1;
            // En ciclos siguientes, rotar el inicio del array para no repetir el mismo orden
            const rotated = (tipIdx + (cycle - 1) * 3) % SEARCH_WAIT_RETENTION_TIPS.length;
            return SEARCH_WAIT_RETENTION_TIPS[rotated];
        }

        function stopNoDriversNotifyCountdown() {
            if (window._noDriversCountdownTimer) {
                clearInterval(window._noDriversCountdownTimer);
                window._noDriversCountdownTimer = null;
            }
            window._noDriversCountdown = null;
            const box = document.getElementById('searching-notify-countdown');
            if (box) box.classList.add('hidden');
            stopDriverNotifyNameAnimation();
        }
        window.stopNoDriversNotifyCountdown = stopNoDriversNotifyCountdown;

        function paintNoDriversCountdownUi() {
            const state = window._noDriversCountdown;
            const box = document.getElementById('searching-notify-countdown');
            const timeEl = document.getElementById('searching-notify-countdown-time');
            const hintEl = document.getElementById('searching-notify-countdown-hint');
            const labelEl = document.getElementById('searching-notify-countdown-label');
            if (!state || !box || !timeEl) return;

            const remaining = Math.max(0, Math.ceil((state.endsAt - Date.now()) / 1000));
            timeEl.textContent = String(remaining);
            box.classList.remove('hidden');
            const regN = window.pendingTripRegisteredDrivers
                ?? window.lastRegisteredDriversCount
                ?? 0;
            if (labelEl) {
                labelEl.textContent = formatRegisteredDriversWaitingLabel(regN);
            }
            if (hintEl) {
                hintEl.textContent = remaining > 0
                    ? getSearchWaitRetentionTip(state, remaining)
                    : 'Seguimos enviando tu mensaje. Quédate un momento más';
            }
            // Asegurar animación de fotos/mensajes si hay flota
            if (state.tripId && !window._driverNotifyNameTimer) {
                startDriverNotifyNameAnimation({
                    tripId: state.tripId,
                    drivers: window.pendingTripRegisteredNotifyDrivers
                        || window.lastRegisteredNotifyDrivers
                        || [],
                    names: window.pendingTripRegisteredDriverNames
                        || window.lastRegisteredDriverNames
                        || [],
                    total: regN
                });
            }
        }

        /**
         * Mantén al pasajero en espera con mensaje de notificación +
         * cuenta regresiva de 120s y tips de retención (sin despacharlo).
         */
        function ensureNoDriversNotifyCountdown(tripId) {
            if (!tripId) return;
            const existing = window._noDriversCountdown;
            if (existing?.tripId === tripId && existing.endsAt > Date.now()) {
                paintNoDriversCountdownUi();
                return;
            }
            // Si se acabó el ciclo, reinicia otros 120s para no sacar al cliente
            if (existing?.tripId === tripId && existing.endsAt <= Date.now()) {
                window._noDriversCountdown = {
                    tripId,
                    endsAt: Date.now() + NO_DRIVERS_NOTIFY_COUNTDOWN_SEC * 1000,
                    cycle: (existing.cycle || 1) + 1
                };
            } else {
                window._noDriversCountdown = {
                    tripId,
                    endsAt: Date.now() + NO_DRIVERS_NOTIFY_COUNTDOWN_SEC * 1000,
                    cycle: 1
                };
            }
            paintNoDriversCountdownUi();
            if (window._noDriversCountdownTimer) clearInterval(window._noDriversCountdownTimer);
            window._noDriversCountdownTimer = setInterval(() => {
                const s = window._noDriversCountdown;
                if (!s || s.tripId !== tripId) {
                    window.stopNoDriversNotifyCountdown?.();
                    return;
                }
                if (s.endsAt <= Date.now()) {
                    // Reiniciar ciclo: el cliente se queda; no cancelar ni despachar
                    window._noDriversCountdown = {
                        tripId,
                        endsAt: Date.now() + NO_DRIVERS_NOTIFY_COUNTDOWN_SEC * 1000,
                        cycle: (s.cycle || 1) + 1
                    };
                }
                paintNoDriversCountdownUi();
            }, 250);
        }

        function updateSearchingDriversTotal(data) {
            const totalEl = document.getElementById('searching-drivers-total');
            if (!totalEl) return;

            const regN = data?._registeredDrivers
                ?? window.pendingTripRegisteredDrivers
                ?? window.lastRegisteredDriversCount
                ?? 0;
            const viewedN = getPendingTripViewedCount(data?.viewedBy);

            totalEl.classList.remove('hidden');
            const parts = [];
            if (regN > 0) {
                parts.push(formatRegisteredDriversWaitingLabel(regN));
            }
            if (viewedN > 0) {
                parts.push(`${viewedN} ya ${viewedN === 1 ? 'vio' : 'vieron'} tu mensaje`);
            }
            totalEl.textContent = parts.length
                ? parts.join(' · ')
                : 'Conductores están siendo notificados';
        }

        function syncPassengerBoostPricePanel(data) {
            const panel = document.getElementById('passenger-boost-price-panel');
            const curEl = document.getElementById('passenger-boost-current');
            if (!panel) return;

            const baseOk = !!(
                data
                && data.id
                && data.status === 'pending'
                && !data.driverId
                && data.clientId === currentUser?.uid
                && data.paymentMethod !== 'birthday_gift'
                && data.birthdayFree !== true
            );

            // Solo “subir tarifa” si no hay oferta del conductor que el pasajero pueda aceptar.
            // Si un conductor ofreció precio, el pasajero acepta o contraoferta (no sube la base).
            // Si no hay ofertas, o solo espera respuesta a su contraoferta → sí puede subir para atraer más.
            const offers = baseOk ? getPassengerDriverOffers(data) : [];
            const hasDriverOfferToAccept = offers.some((o) => {
                const c = o?.passengerCounterPrice;
                return c == null || Number.isNaN(parseFloat(c));
            });
            const canBoost = baseOk && !hasDriverOfferToAccept;

            if (!canBoost) {
                panel.classList.add('hidden');
                return;
            }

            panel.classList.remove('hidden');
            const priceNum = parseTripPrice(data);
            const label = data.price || (priceNum > 0 ? `L. ${priceNum.toFixed(2)}` : '—');
            if (curEl) {
                const boosts = Number(data.priceBoostCount) || 0;
                curEl.textContent = boosts > 0
                    ? `Tu tarifa: ${label} · subiste ${boosts} vez${boosts === 1 ? '' : 'es'}`
                    : `Tu tarifa: ${label}`;
            }
        }

        /**
         * Pasajero sube el monto de su solicitud pendiente para atraer conductores.
         * options: { delta: number } o { newPrice: number } o { promptCustom: true }
         */
        window.raisePendingTripPrice = async (options = {}) => {
            const trip = activeTrip?.status === 'pending' && activeTrip.clientId === currentUser?.uid
                ? activeTrip
                : null;
            if (!trip?.id) {
                return window.showToast('No hay una solicitud activa para subir el precio.');
            }
            if (trip.driverId) {
                return window.showToast('Ya tienes conductor asignado.');
            }
            if (trip.paymentMethod === 'birthday_gift' || trip.birthdayFree) {
                return window.showToast('El viaje de cumpleaños es gratis; no se puede subir el precio.');
            }

            const current = parseTripPrice(trip);
            if (!(current > 0)) {
                return window.showToast('No se pudo leer el precio actual.');
            }

            let next = null;
            if (options.promptCustom) {
                const raw = prompt(`Tu tarifa actual es L. ${current.toFixed(2)}.\n¿A cuánto quieres subirla?`, String(Math.ceil(current + 20)));
                if (raw == null) return;
                next = parseFloat(String(raw).replace(/,/g, '.').trim());
            } else if (options.newPrice != null) {
                next = parseFloat(options.newPrice);
            } else if (options.delta != null) {
                next = current + parseFloat(options.delta);
            }

            next = Math.round((Number(next) || 0) * 100) / 100;
            if (!(next > current)) {
                return window.showToast(`El nuevo precio debe ser mayor a L. ${current.toFixed(2)}.`);
            }
            if (next > current * 4 && next > current + 200) {
                if (!confirm(`Vas a subir de L. ${current.toFixed(2)} a L. ${next.toFixed(2)}. ¿Confirmas?`)) return;
            }

            // Saldo: validar que alcance el nuevo monto
            if (trip.paymentMethod === 'saldo') {
                const bal = Number(window.userProfile?.balance) || 0;
                const charge = trip.passengerPaysAmount != null ? Math.min(next, Number(trip.passengerPaysAmount) || next) : next;
                // Si no hay promo, el cobro es el precio completo
                const need = trip.promoDiscountApplied ? (Number(trip.passengerPaysAmount) || next) : next;
                // Al subir tarifa con saldo, el cobro será el nuevo precio (promos fijas se recalculan simple)
                const needPay = next;
                if (bal < needPay) {
                    window.showToast(`Saldo insuficiente para L. ${needPay.toFixed(2)}. Recarga o elige efectivo al cancelar y volver a pedir.`, 'warning');
                    setTimeout(() => window.showRechargeModal?.(), 900);
                    return;
                }
            }

            try {
                const tripRef = doc(db, 'artifacts', appId, 'public', 'data', 'trips', trip.id);
                const snap = await getDoc(tripRef);
                if (!snap.exists()) return window.showToast('El viaje ya no está disponible.');
                const t = snap.data();
                if (t.status !== 'pending' || t.clientId !== currentUser.uid || t.driverId) {
                    return window.showToast('Este viaje ya no se puede modificar.');
                }
                const liveCurrent = parseTripPrice(t);
                if (!(next > liveCurrent)) {
                    return window.showToast(`El precio actual ya es L. ${liveCurrent.toFixed(2)}.`);
                }

                const priceText = `L. ${next.toFixed(2)}`;
                await updateDoc(tripRef, {
                    price: priceText,
                    priceNum: next,
                    previousPriceNum: liveCurrent,
                    priceBoostedAt: serverTimestamp(),
                    priceBoostCount: (Number(t.priceBoostCount) || 0) + 1,
                    // Reabrir rueda de ofertas con el nuevo precio
                    offeredToDriverId: null,
                    offeredToDriverName: null,
                    offerSentAt: null,
                    offerDistanceKm: null,
                    candidateDriverIds: [],
                    offerToBusyDriver: false,
                    offerSearchTier: null,
                    // Quitar rechazos previos para que vuelvan a ver el viaje mejor pagado
                    declinedDriverIds: [],
                    negotiationLog: arrayUnion({
                        by: 'passenger',
                        action: 'price_boost',
                        from: liveCurrent,
                        price: next,
                        name: window.userProfile?.name || 'Pasajero',
                        clientId: currentUser.uid,
                        at: Timestamp.now()
                    }),
                    lastNegotiationAt: serverTimestamp()
                });

                if (activeTrip?.id === trip.id) {
                    activeTrip.price = priceText;
                    activeTrip.priceNum = next;
                    activeTrip.previousPriceNum = liveCurrent;
                    activeTrip.priceBoostCount = (Number(t.priceBoostCount) || 0) + 1;
                    activeTrip.declinedDriverIds = [];
                    activeTrip.offeredToDriverId = null;
                    updateSearchingStatusUI(activeTrip);
                }

                window.assignNextTripOffer?.(trip.id)?.catch?.(() => {});
                window.showToast(`Tarifa subida a ${priceText}. Notificando conductores…`, 'success');
            } catch (e) {
                console.error('raisePendingTripPrice:', e);
                window.showToast(e?.message?.includes('permission')
                    ? 'No tienes permiso para cambiar el precio.'
                    : 'No se pudo subir la tarifa. Intenta de nuevo.');
            }
        };

        function updateSearchingStatusUI(data) {
            const headline = document.getElementById('searching-status-headline');
            const sub = document.getElementById('searching-status-sub');
            const summary = document.getElementById('searching-trip-summary');
            const footEl = document.getElementById('searching-drivers-total');
            if (!data) return;

            const onlineN = data._onlineDriversNear ?? window.pendingTripOnlineDrivers ?? window.lastNearbyDriversCount ?? 0;
            const regN = data._registeredDrivers
                ?? window.pendingTripRegisteredDrivers
                ?? window.lastRegisteredDriversCount
                ?? 0;
            const offers = getPassengerDriverOffers(data);
            const closest = offers[0] || null;
            const waitingForOffer = !data.offeredToDriverId && !data.driverId && offers.length === 0;

            let statusLine = 'Buscando conductores';
            let subLine = 'Cuando aceptes un conductor, te daremos tu PIN de seguridad';
            let showNotifyCountdown = false;

            const scheduledMins = getScheduledTripMinutesUntil(data);
            if (data.scheduledFor && !data.driverId && data.status === 'pending') {
                statusLine = scheduledMins != null && scheduledMins > 0
                    ? `Programado · en ${scheduledMins} min`
                    : 'Viaje programado';
                subLine = `Recogida: ${formatScheduledTripWhen(data)}. Buscando conductor que acepte o negocie.`;
            } else if (scheduledMins != null && scheduledMins > 0 && data.status === 'scheduled') {
                statusLine = `Programado · ${scheduledMins} min`;
                subLine = formatScheduledTripWhen(data);
            } else if (offers.length > 0) {
                const name = (closest?.name || 'Un conductor').split(' ')[0];
                const waitingDriverReply = offers.some((o) => o.passengerCounterPrice != null);
                if (waitingDriverReply) {
                    statusLine = offers.length === 1
                        ? `Esperando a ${name}`
                        : 'Esperando respuesta de conductores';
                    subLine = 'Enviaste una contraoferta: el conductor debe aceptarla (tú no puedes aceptar la tuya).';
                } else {
                    statusLine = offers.length === 1 ? `${name} te ofreció un precio` : `${offers.length} conductores te ofrecieron`;
                    subLine = 'Acepta su precio, rechaza o propón otro (el conductor decide si acepta tu precio).';
                }
            } else if (data.negotiatedBy === 'passenger' && data.negotiatedPrice != null) {
                statusLine = 'Esperando al conductor';
                subLine = `Tu contraoferta: L. ${parseFloat(data.negotiatedPrice).toFixed(2)} — debe aceptarla el conductor`;
            } else if (waitingForOffer) {
                // “Estos N conductores están siendo notificados” + mensajes volando a fotos
                if (regN > 0) {
                    statusLine = regN === 1
                        ? '1 conductor está siendo notificado'
                        : `Estos ${regN} conductores están siendo notificados`;
                    subLine = 'Enviando tu mensaje a cada conductor de tu zona';
                } else {
                    statusLine = 'Notificando conductores';
                    subLine = 'Estamos enviando tu mensaje a la flota';
                }
                showNotifyCountdown = true;
            } else if (onlineN > 0) {
                statusLine = `${onlineN} conductor${onlineN === 1 ? '' : 'es'} cerca`;
                subLine = 'En tu ciudad — esperando ofertas';
            }

            if (headline) headline.innerText = statusLine;
            if (sub) sub.innerText = subLine;

            if (showNotifyCountdown && data.id) {
                ensureNoDriversNotifyCountdown(data.id);
                const drivers = data._registeredNotifyDrivers
                    || window.pendingTripRegisteredNotifyDrivers
                    || window.lastRegisteredNotifyDrivers
                    || [];
                const names = data._registeredDriverNames
                    || window.pendingTripRegisteredDriverNames
                    || window.lastRegisteredDriverNames
                    || [];
                startDriverNotifyNameAnimation({
                    tripId: data.id,
                    drivers,
                    names,
                    total: regN || drivers.length || names.length
                });
            } else {
                window.stopNoDriversNotifyCountdown?.();
            }

            if (summary) {
                const routeHtml = window.formatTripRouteOrderHtml?.(data) || '';
                const listedPrice = data.price || '';
                summary.innerHTML = `
                    ${routeHtml ? `<div class="passenger-pending-route-lines">${routeHtml}</div>` : ''}
                    <p class="passenger-pending-listed-price">Tu tarifa: <strong>${listedPrice}</strong></p>
                `;
            }

            // Panel “subir tarifa” si aún no hay conductor / o hay pocas ofertas
            syncPassengerBoostPricePanel(data);

            if (footEl) {
                if (offers.length > 0) {
                    footEl.classList.add('hidden');
                } else if (waitingForOffer) {
                    const viewedN = getPendingTripViewedCount(data.viewedBy);
                    const bits = [];
                    if (regN > 0) bits.push(formatRegisteredDriversWaitingLabel(regN));
                    if (viewedN > 0) bits.push(`${viewedN} revisando tu viaje`);
                    if (!bits.length) bits.push('Tu mensaje sigue activo. No te desconectes.');
                    footEl.textContent = bits.join(' · ');
                    footEl.classList.remove('hidden');
                } else {
                    const viewedN = getPendingTripViewedCount(data.viewedBy);
                    const bits = [];
                    if (viewedN > 0) bits.push(`${viewedN} revisando tu viaje`);
                    if (regN > 0 && !bits.length) bits.push(formatRegisteredDriversWaitingLabel(regN));
                    footEl.textContent = bits.join(' · ') || '';
                    footEl.classList.toggle('hidden', !bits.length);
                }
            }

            updateSearchingDriverCard(data);
            window.renderTripViewersPanel?.(data);

            // Si aún no tenemos el conteo, pedirlo (async y re-pinta)
            if (waitingForOffer && data.id && !(data._registeredDrivers > 0) && !window.pendingTripRegisteredDrivers) {
                prefetchRegisteredDriversCount(data);
            }
        }

        function startPendingOfferWatch(tripId) {
            if (window.pendingOfferWatch) clearInterval(window.pendingOfferWatch);
            if (!tripId) return;

            window.pendingOfferWatch = setInterval(async () => {
                try {
                    const snap = await getDoc(doc(db, 'artifacts', appId, 'public', 'data', 'trips', tripId));
                    if (!snap.exists()) {
                        clearInterval(window.pendingOfferWatch);
                        return;
                    }
                    const t = snap.data();
                    if (t.status !== 'pending') {
                        clearInterval(window.pendingOfferWatch);
                        return;
                    }

                    const onlineNear = await countOnlineDriversNearTrip({ ...t, id: tripId });
                    window.pendingTripOnlineDrivers = onlineNear;
                    const regInfo = await getRegisteredDriversForNotify({
                        zoneId: t.serviceZoneId || null
                    });
                    window.pendingTripRegisteredDrivers = regInfo.count;
                    window.pendingTripRegisteredDriverNames = regInfo.names || [];
                    window.lastRegisteredDriverNames = regInfo.names || [];

                    if (t.offeredToDriverId && isOfferExpired(t)) {
                        await updateDoc(snap.ref, {
                            offeredToDriverId: null,
                            offeredToDriverName: null,
                            offerSentAt: null,
                            offerDistanceKm: null
                        });
                        await window.assignNextTripOffer(tripId);
                    } else if (!t.offeredToDriverId && !t.driverId) {
                        await window.assignNextTripOffer(tripId);
                    }

                    if (activeTrip?.id === tripId) {
                        const live = {
                            id: tripId,
                            ...t,
                            _onlineDriversNear: onlineNear,
                            _registeredDrivers: regInfo.count,
                            _registeredDriverNames: regInfo.names || [],
                            _noDriversNearby: !t.offeredToDriverId && !t.driverId
                        };
                        updateSearchingStatusUI(live);
                        window.renderTripViewersPanel?.({ id: tripId, ...t });
                    }
                } catch (_) {}
            }, 3000);
        }

        window.acceptDriverBid = async (tripId, driverId, options = {}) => {
            if (!tripId || !driverId || !currentUser) return;

            try {
                const tripRef = doc(db, 'artifacts', appId, 'public', 'data', 'trips', tripId);
                const [tripSnap, driverSnap] = await Promise.all([
                    getDoc(tripRef),
                    getDoc(doc(db, 'artifacts', appId, 'public', 'data', 'users', driverId))
                ]);
                if (!tripSnap.exists()) return window.showToast('El viaje ya no está disponible.');
                if (!driverSnap.exists()) return window.showToast('Conductor no encontrado.');

                const trip = tripSnap.data();
                const d = driverSnap.data();
                if (trip.status !== 'pending' || trip.clientId !== currentUser.uid) {
                    return window.showToast('Este viaje ya no está disponible.');
                }
                if (trip.driverId) return window.showToast('Ya elegiste un conductor.');

                const bid = trip.driverBids?.[driverId];
                if (!bid || !bid.price) return window.showToast('Esta oferta ya no está disponible.');

                // Si el pasajero ya mandó contraoferta, no puede “aceptar” su propio precio:
                // debe esperar a que el CONDUCTOR acepte (o cambie el precio).
                const pendingCounter = bid.passengerCounterPrice != null
                    ? parseFloat(bid.passengerCounterPrice)
                    : null;
                if (pendingCounter != null && !Number.isNaN(pendingCounter) && pendingCounter > 0) {
                    return window.showToast(
                        'Ya enviaste una contraoferta. Espera a que el conductor la acepte o cambia tu precio.',
                        'warning'
                    );
                }
                if (trip.negotiatedBy === 'passenger' && trip.negotiatedPrice != null
                    && (trip.passengerCounterTargetDriverId === driverId || !trip.passengerCounterTargetDriverId)) {
                    return window.showToast(
                        'Tu contraoferta está pendiente. El conductor debe aceptarla.',
                        'warning'
                    );
                }

                const driverName = bid.name || d.name || 'Conductor';
                // Solo se acepta el precio que ofreció el conductor (no una auto-aceptación de la contraoferta)
                const effectivePrice = parseFloat(bid.price);
                const skipConfirm = options.skipConfirm === true
                    || getPassengerDriverOffers({ ...trip, id: tripId }).length === 1;
                if (!skipConfirm && !confirm(`¿Irte con ${driverName} por L. ${effectivePrice.toFixed(2)}?`)) return;

                const rating = d.ratingCount > 0 ? (d.ratingSum / d.ratingCount).toFixed(1) : (bid.rating || '5.0');
                const pin = Math.floor(1000 + Math.random() * 9000).toString();
                const priceNum = effectivePrice > 0 ? effectivePrice : parseFloat(bid.price);
                const isBirthdayGift = trip.birthdayFree || trip.paymentMethod === 'birthday_gift';

                const saldoHoldFields = {};
                if (trip.paymentMethod === 'saldo' && !isBirthdayGift && !trip.saldoCharged) {
                    const chargeAmt = getPassengerSaldoChargeAmount({ ...trip, priceNum });
                    await deductPassengerSaldo(trip.clientId, chargeAmt);
                    saldoHoldFields.saldoCharged = true;
                    saldoHoldFields.saldoChargedAmount = chargeAmt;
                    saldoHoldFields.saldoChargedAt = serverTimestamp();
                }

                const driverPhone = normalizeHondurasPhone(d.phone || bid.phone || '') || '';
                const reserveScheduled = shouldReserveAsScheduledTrip(trip);
                const nextStatus = reserveScheduled ? 'scheduled' : 'accepted';
                const acceptedTrip = {
                    ...trip,
                    id: tripId,
                    status: nextStatus,
                    driverId,
                    driverName,
                    driverPhone,
                    driverPhoto: bid.photo || d.photo || null,
                    driverVehicle: d.vehicle || null,
                    driverVehiclePhotos: d.vehiclePhotos || null,
                    driverDocumentsPhotos: d.documentsPhotos || null,
                    driverVehicleType: bid.vehicleType || d.vehicleType || 'auto',
                    serviceType: trip.serviceType || 'auto',
                    driverIdentity: d.identity || 'N/D',
                    driverRating: rating,
                    pin,
                    driverArrived: false,
                    price: `L. ${priceNum.toFixed(2)}`,
                    priceNum,
                    negotiatedPrice: null,
                    negotiatedBy: null,
                    offeredToDriverId: null,
                    offeredToDriverName: null,
                    offerSentAt: null,
                    offerDistanceKm: bid.distanceKm ?? null,
                    candidateDriverIds: [],
                    driverBids: {},
                    chosenDriverBid: bid,
                    clientId: trip.clientId || currentUser.uid,
                    scheduledDriverReserved: reserveScheduled || undefined,
                    ...saldoHoldFields
                };

                await updateDoc(tripRef, {
                    status: nextStatus,
                    driverId,
                    driverName,
                    driverPhone,
                    driverPhoto: acceptedTrip.driverPhoto,
                    driverVehicle: acceptedTrip.driverVehicle,
                    driverVehiclePhotos: acceptedTrip.driverVehiclePhotos,
                    driverDocumentsPhotos: acceptedTrip.driverDocumentsPhotos,
                    driverVehicleType: acceptedTrip.driverVehicleType,
                    serviceType: acceptedTrip.serviceType,
                    driverIdentity: acceptedTrip.driverIdentity,
                    driverRating: rating,
                    pin,
                    driverArrived: false,
                    acceptedAt: serverTimestamp(),
                    price: acceptedTrip.price,
                    priceNum,
                    negotiatedPrice: null,
                    negotiatedBy: null,
                    offeredToDriverId: null,
                    offeredToDriverName: null,
                    offerSentAt: null,
                    offerDistanceKm: acceptedTrip.offerDistanceKm,
                    candidateDriverIds: [],
                    driverBids: {},
                    chosenDriverBid: bid,
                    passengerChoseDriverAt: serverTimestamp(),
                    ...(reserveScheduled ? {
                        scheduledDriverReserved: true,
                        scheduledReservedAt: serverTimestamp()
                    } : {}),
                    ...saldoHoldFields
                });

                activeTrip = acceptedTrip;
                window.currentActiveTripData = acceptedTrip;
                if (reserveScheduled) {
                    window.presentScheduledReservedUi?.(acceptedTrip, { role: 'client' });
                } else {
                    window.presentTripAcceptedUi?.(acceptedTrip, { role: 'client' });
                }
            } catch (e) {
                console.error('acceptDriverBid:', e);
                window.showToast(e?.message || 'No se pudo elegir al conductor.');
            }
        };

        window.acceptNegotiatedPrice = async (tripId, options = {}) => {
            const tripRef = doc(db, 'artifacts', appId, 'public', 'data', 'trips', tripId);
            const snap = await getDoc(tripRef);
            if (!snap.exists()) return;
            const t = snap.data();
            const driverId = t.offeredToDriverId || Object.keys(t.driverBids || {})[0];
            if (!driverId) return window.showToast('Esta propuesta ya no está disponible.');
            return window.acceptDriverBid(tripId, driverId, options);
        };

        window.declineDriverBid = async (tripId, driverId) => {
            if (!tripId || !driverId || !currentUser) return;
            try {
                const tripRef = doc(db, 'artifacts', appId, 'public', 'data', 'trips', tripId);
                const snap = await getDoc(tripRef);
                if (!snap.exists()) return;
                const t = snap.data();
                if (t.clientId !== currentUser.uid || t.status !== 'pending') return;

                await updateDoc(tripRef, {
                    [`driverBids.${driverId}`]: deleteField(),
                    negotiationLog: arrayUnion({
                        by: 'passenger',
                        action: 'decline_bid',
                        driverId,
                        name: window.userProfile?.name || 'Pasajero',
                        clientId: currentUser.uid,
                        at: Timestamp.now()
                    })
                });
                window.showToast('Oferta rechazada. El conductor puede enviarte una mejor.', 'success');
            } catch (e) {
                console.error('declineDriverBid:', e);
                window.showToast('No se pudo rechazar la oferta.');
            }
        };

        window.submitPassengerCounter = async (tripId, driverId, priceOverride = null) => {
            if (!tripId || !driverId || !currentUser) return;
            const inp = document.getElementById(`pax-counter-${tripId}-${driverId}`);
            const raw = priceOverride != null ? String(priceOverride) : (inp?.value || '');
            const newP = parseFloat(String(raw).replace(/,/g, '.').trim());
            if (!newP || newP <= 0 || Number.isNaN(newP)) {
                return window.showToast('Ingresa un precio válido para tu contraoferta.');
            }

            try {
                const tripRef = doc(db, 'artifacts', appId, 'public', 'data', 'trips', tripId);
                const snap = await getDoc(tripRef);
                if (!snap.exists()) return window.showToast('El viaje ya no está disponible.');
                const t = snap.data();
                if (t.status !== 'pending' || t.clientId !== currentUser.uid) {
                    return window.showToast('Este viaje ya no está disponible.');
                }

                const bid = t.driverBids?.[driverId];
                if (!bid?.price) return window.showToast('Esta oferta ya no está disponible.');

                const patch = {
                    [`driverBids.${driverId}.passengerCounterPrice`]: newP,
                    [`driverBids.${driverId}.passengerCounterAt`]: Date.now(),
                    passengerCounterTargetDriverId: driverId,
                    offeredToDriverId: null,
                    offeredToDriverName: null,
                    offerSentAt: null,
                    offerDistanceKm: null,
                    candidateDriverIds: [],
                    negotiatedPrice: newP,
                    negotiatedBy: 'passenger',
                    negotiationLog: arrayUnion({
                        by: 'passenger',
                        action: 'counter_bid',
                        price: newP,
                        name: window.userProfile?.name || 'Pasajero',
                        clientId: currentUser.uid,
                        targetDriverId: driverId,
                        driverOfferPrice: parseFloat(bid.price),
                        at: Timestamp.now()
                    }),
                    lastNegotiationAt: serverTimestamp()
                };
                await updateDoc(tripRef, patch);

                const draftKey = passengerCounterDraftKey(tripId, driverId);
                delete window._passengerCounterDrafts[draftKey];
                delete window._passengerCounterRowOpen[draftKey];
                // Cerrar teclado y no reabrirlo en el siguiente snapshot de Firestore
                suppressPassengerCounterFocus(5000);
                try { inp?.blur(); } catch (_) {}
                const row = document.getElementById(`pax-counter-row-${tripId}-${driverId}`);
                row?.classList.add('hidden');
                const toggle = document.getElementById(`pax-counter-toggle-${tripId}-${driverId}`);
                if (toggle) {
                    toggle.dataset.counterSent = '1';
                    toggle.textContent = 'Cambiar mi precio';
                }
                // Forzar re-render limpio en el próximo update (nueva firma con passengerCounterPrice)
                const list = document.getElementById('trip-viewers-list');
                if (list) delete list.dataset.offersStructuralSig;

                const driverName = (bid.name || 'El conductor').split(' ')[0];
                window.showToast(`Contraoferta de L. ${newP.toFixed(2)} enviada a ${driverName}. Esperando respuesta…`, 'success');
            } catch (e) {
                console.error('submitPassengerCounter:', e);
                window.showToast('No se pudo enviar la contraoferta.');
            }
        };

        window.counterNegotiate = (tripId, targetDriverId = null) => {
            if (targetDriverId) {
                const inp = document.getElementById(`pax-counter-${tripId}-${targetDriverId}`);
                if (inp?.value) return window.submitPassengerCounter(tripId, targetDriverId);
            }
            const newPriceStr = prompt('Ingresa tu contraoferta (L.):');
            if (!newPriceStr) return;
            const newP = parseFloat(newPriceStr);
            if (!newP || newP <= 0) return window.showToast('Precio inválido.');
            if (targetDriverId) return window.submitPassengerCounter(tripId, targetDriverId, newP);

            const tripRef = doc(db, 'artifacts', appId, 'public', 'data', 'trips', tripId);
            updateDoc(tripRef, {
                negotiatedPrice: newP,
                negotiatedBy: 'passenger',
                negotiationLog: arrayUnion({
                    by: 'passenger',
                    price: newP,
                    name: window.userProfile?.name || 'Pasajero',
                    clientId: currentUser.uid,
                    at: Timestamp.now()
                }),
                lastNegotiationAt: serverTimestamp()
            }).then(() => {
                window.showToast(`Contraoferta de L. ${newP.toFixed(2)} enviada.`, 'success');
            }).catch(e => {
                console.error(e);
                window.showToast('Error al enviar contraoferta.');
            });
        };

        window.declineNegotiation = async (tripId) => {
            const tripRef = doc(db, 'artifacts', appId, 'public', 'data', 'trips', tripId);
            const snap = await getDoc(tripRef);
            if (!snap.exists()) return;
            const t = snap.data();
            const driverId = t.offeredToDriverId || Object.keys(t.driverBids || {})[0];
            if (!driverId) return window.showToast('Esta propuesta ya no está disponible.');
            return window.declineDriverBid(tripId, driverId);
        };

        window.syncPassengerBookingForm = (data) => {
            const isClient = window.userProfile?.role === 'client';
            const clientActiveTrip = isClient
                && data
                && ['accepted', 'in_progress'].includes(data.status)
                && !!data.driverId;
            const clientView = document.getElementById('client-view');
            const panelSetup = document.getElementById('trip-panel-setup');
            const bookingRoute = document.getElementById('passenger-booking-route');
            const bookingAdvanced = document.getElementById('passenger-booking-advanced');
            const bookingService = document.getElementById('passenger-booking-service');

            if (clientActiveTrip) {
                clientView?.classList.add('hidden');
                panelSetup?.classList.add('hidden');
                bookingRoute?.classList.add('hidden');
                bookingAdvanced?.classList.add('hidden');
                bookingService?.classList.add('hidden');
                document.getElementById('fare-card')?.classList.add('hidden');
                document.getElementById('scheduled-trip-card')?.classList.add('hidden');
                return;
            }

            if (!isClient || !document.body.classList.contains('trip-active')) {
                bookingRoute?.classList.remove('hidden');
                bookingAdvanced?.classList.remove('hidden');
                bookingService?.classList.remove('hidden');
            }
        };

        window.copyClientTripPin = async () => {
            const pin = String(
                activeTrip?.pin
                || document.getElementById('client-pin-code')?.textContent
                || document.getElementById('client-pin-panel-code')?.textContent
                || ''
            ).trim();
            if (!pin || pin === '----') {
                return window.showToast?.('PIN no disponible aún. Aparece cuando un conductor acepte tu viaje.');
            }
            try {
                await navigator.clipboard.writeText(pin);
                window.showToast?.('PIN copiado. Muéstraselo al conductor.', 'success');
            } catch (_) {
                window.showToast?.(`Tu PIN: ${pin}`, 'success');
            }
        };

        window.formatTripGmapsBtnLabel = (data, role = 'client') => {
            const isDestPhase = data?.status === 'in_progress' || (data?.status === 'accepted' && data?.driverArrived);
            let addr = (isDestPhase ? data?.destination : data?.origin) || '';
            if (isDestPhase && (data?.additionalStops?.length > 0)) {
                const legLabel = window.getTripRouteLegLabel?.(data);
                const legTarget = window.getTripCurrentLegNavTarget?.(data);
                addr = legTarget?.address || addr;
                const short = addr.length > 42 ? `${addr.slice(0, 42)}…` : addr;
                const pointPrefix = legLabel?.isFinal
                    ? 'Ir al destino en Google Maps'
                    : `Ir al punto ${legLabel?.routeNum || ''} en Google Maps`;
                return `${pointPrefix}${short ? ` · ${short}` : ''}`;
            }
            const short = addr.length > 42 ? `${addr.slice(0, 42)}…` : addr;
            if (role === 'driver') {
                return isDestPhase
                    ? `Ir al destino en Google Maps${short ? ` · ${short}` : ''}`
                    : `Ir al origen en Google Maps${short ? ` · ${short}` : ''}`;
            }
            return isDestPhase
                ? `Ir al destino en Google Maps${short ? ` · ${short}` : ''}`
                : `Ir al origen en Google Maps${short ? ` · ${short}` : ''}`;
        };

        /**
         * UI de viaje programado YA RESERVADO (con conductor), aún no en camino.
         */
        window.presentScheduledReservedUi = (data, options = {}) => {
            if (!data?.id) return;
            const role = options.role || window.userProfile?.role;
            const when = formatScheduledTripWhen(data);

            try { stopPassengerWaitingLoop(); } catch (_) {}
            document.body.classList.remove('is-searching', 'trip-active');
            syncPromoUi();
            clearPassengerSearchPanelLayout?.();
            document.getElementById('searching-state')?.classList.add('hidden');
            document.getElementById('trip-viewers-panel')?.classList.add('hidden');
            document.getElementById('fare-card')?.classList.add('hidden');
            document.getElementById('active-trip-panel')?.classList.add('hidden');

            const card = document.getElementById('scheduled-trip-card');
            const whenEl = document.getElementById('scheduled-trip-when');
            const detailEl = document.getElementById('scheduled-trip-detail');
            const actionsEl = document.getElementById('scheduled-trip-actions');
            card?.classList.remove('hidden');

            if (whenEl) whenEl.textContent = when || 'Fecha por confirmar';

            if (role === 'driver' || data.driverId === currentUser?.uid) {
                document.getElementById('driver-view')?.classList.remove('hidden');
                document.getElementById('client-view')?.classList.add('hidden');
                if (detailEl) {
                    detailEl.innerHTML = `
                        <p class="text-xs font-bold text-amber-900 mt-2">Pasajero: <b>${escapeViewerText(data.clientName || 'Cliente')}</b></p>
                        <p class="text-[11px] text-amber-800 mt-1"><i class="fas fa-map-marker-alt"></i> ${escapeViewerText(data.origin || 'Origen')}</p>
                        <p class="text-[11px] text-amber-800"><i class="fas fa-flag-checkered"></i> ${escapeViewerText(data.destination || 'Destino')}</p>
                        <p class="text-[10px] text-amber-700 mt-2">Te avisamos 1 h, 30, 10 y 5 min antes. O inicia cuando quieras.</p>`;
                }
                if (actionsEl) {
                    actionsEl.innerHTML = `
                        <button type="button" id="btn-start-scheduled-now" data-trip-id="${data.id}"
                            class="w-full mt-3 py-3 rounded-xl bg-emerald-600 text-white text-sm font-black trip-touch-btn">
                            <i class="fas fa-play"></i> Hacer viaje programado YA
                        </button>
                        <button type="button" class="w-full mt-2 py-2.5 rounded-xl border border-amber-300 bg-white text-amber-900 text-xs font-black"
                            onclick="window.openDriverRouteInGoogleMaps?.()">
                            <i class="fas fa-route"></i> Ver ruta en Google Maps
                        </button>`;
                    const startBtn = actionsEl.querySelector('#btn-start-scheduled-now');
                    startBtn?.addEventListener('click', () => {
                        window.startScheduledTripNow?.(data.id, startBtn);
                    });
                }
            } else {
                document.getElementById('client-view')?.classList.remove('hidden');
                document.getElementById('driver-view')?.classList.add('hidden');
                if (detailEl) {
                    detailEl.innerHTML = `
                        <p class="text-xs font-bold text-amber-900 mt-2">Conductor: <b>${escapeViewerText(data.driverName || 'Asignado')}</b>
                        ${data.pin ? ` · PIN <b>${escapeViewerText(data.pin)}</b>` : ''}</p>
                        <p class="text-[11px] text-amber-800 mt-1"><i class="fas fa-map-marker-alt"></i> ${escapeViewerText(data.origin || 'Origen')}</p>
                        <p class="text-[10px] text-amber-700 mt-2">Te avisaremos cuando se active (~10 min antes). El conductor puede iniciar antes.</p>`;
                }
                if (actionsEl) actionsEl.innerHTML = '';
            }
            window.showControlPanel?.();
            setStoredClientTripId?.(data.id);
        };

        window.presentTripAcceptedUi = (data, options = {}) => {
            if (!data?.id) return;
            const role = options.role || window.userProfile?.role;

            // Si sigue programado con conductor, UI de reserva (no en camino aún)
            if (data.status === 'scheduled' && data.driverId && shouldReserveAsScheduledTrip(data)) {
                window.presentScheduledReservedUi?.(data, options);
                return;
            }

            const toastKey = `${data.id}:${role}`;

            if (role === 'client' || data.clientId === currentUser?.uid) {
                try { stopPassengerWaitingLoop(); } catch (_) {}
                // Tono de aceptado (una vez por viaje; evita doble con processActiveTripUpdate)
                if (!options.skipAcceptSound && window._passengerAcceptSoundKey !== data.id) {
                    window._passengerAcceptSoundKey = data.id;
                    try { playPassengerAcceptedTone(); } catch (_) {}
                }
            }

            document.getElementById('scheduled-trip-card')?.classList.add('hidden');

            if (!options.silentToast && window._tripAcceptedToastKey !== toastKey) {
                window._tripAcceptedToastKey = toastKey;
                const followUp = role === 'driver'
                    ? 'Abre Google Maps y ve al origen del pasajero.'
                    : (data.driverFinishingOtherTrip
                        ? 'Tu conductor termina otro viaje y luego va hacia ti.'
                        : 'Tu conductor va en camino. Abre la ruta en Google Maps si lo necesitas.');
                window.showToast?.(`¡Viaje aceptado! ${followUp}`, 'success');
                if (role === 'client' && data.pin) {
                    window.setTimeout(() => {
                        window.showToast?.(`Tu PIN de seguridad: ${data.pin}`, 'success');
                    }, 900);
                    notifyTripEvent({
                        title: '¡Conductor asignado!',
                        body: `Tu PIN es ${data.pin}. Muéstraselo al subir al vehículo.`,
                        tag: `trip-pin-${data.id}`,
                        tripId: data.id,
                        force: true,
                        sound: 'none'
                    });
                }
            }

            document.body.classList.add('trip-active');
            document.body.classList.remove('is-searching');
            syncPromoUi();
            clearPassengerSearchPanelLayout?.();
            document.getElementById('searching-state')?.classList.add('hidden');
            document.getElementById('trip-viewers-panel')?.classList.add('hidden');
            document.getElementById('client-view')?.classList.add('hidden');
            document.getElementById('driver-view')?.classList.add('hidden');
            document.getElementById('fare-card')?.classList.add('hidden');
            const activeP = document.getElementById('active-trip-panel');
            activeP?.classList.remove('hidden', 'panel-minimized');
            document.body.classList.remove('panel-minimized');
            window.showControlPanel?.();

            if (role === 'driver' && data.driverId === currentUser?.uid) {
                window.syncDriverTripControls?.(data);
            }
            if (role === 'client' && data.clientId === currentUser?.uid) {
                window.syncClientPinDisplay?.(data);
            }
            window.syncTripFloatPanels?.(data);
        };

        window.syncClientPinDisplay = (data) => {
            const pinEl = document.getElementById('client-pin-display');
            const pinCodeEl = document.getElementById('client-pin-code');
            const pinHintEl = document.getElementById('client-pin-hint');
            const pinPanel = document.getElementById('client-pin-panel');
            const pinPanelCode = document.getElementById('client-pin-panel-code');
            const pinPanelHint = document.getElementById('client-pin-panel-hint');
            const acceptedKicker = document.getElementById('client-trip-accepted-kicker');
            const routeSummary = document.getElementById('active-trip-route-summary');
            const isClient = window.userProfile?.role === 'client';
            const clientActiveTrip = isClient
                && data
                && ['accepted', 'in_progress'].includes(data.status)
                && !!data.driverId;

            routeSummary?.classList.toggle('hidden', clientActiveTrip);
            syncPassengerBookingForm?.(data);

            const shouldShow = isClient
                && data?.status === 'accepted'
                && !!data?.driverId
                && !!data?.pin;

            const pinHintText = data?.driverArrived
                ? 'Toca para copiar · ¡tu conductor llegó! Muéstrale el PIN ahora'
                : 'Toca para copiar · muéstraselo al conductor al subir';
            const panelHintText = data?.driverArrived
                ? '¡Tu conductor llegó! Muéstrale este PIN ahora'
                : 'Muéstraselo al conductor cuando subas al vehículo';

            // PIN solo en el flotante unificado (no duplicar en el panel inferior)
            pinPanel?.classList.add('hidden');

            if (!shouldShow) {
                pinEl?.classList.add('hidden');
                window.syncTripFloatPanels?.(data);
                return;
            }

            if (acceptedKicker) {
                acceptedKicker.innerHTML = '<i class="fas fa-check-circle"></i> ¡Viaje aceptado!';
            }
            const pinStr = String(data.pin);
            if (pinCodeEl) pinCodeEl.textContent = pinStr;
            if (pinPanelCode) pinPanelCode.textContent = pinStr;
            if (pinHintEl) pinHintEl.textContent = pinHintText;
            if (pinPanelHint) pinPanelHint.textContent = panelHintText;

            pinEl?.classList.remove('hidden');
            window.syncTripFloatPanels?.(data);
        };

        window.syncDriverTripControls = (data) => {
            const routeHero = document.getElementById('driver-route-hero');
            const destControls = document.getElementById('driver-destination-controls');
            const driverTools = document.getElementById('driver-active-tools');
            const dp = document.getElementById('driver-pickup-display');
            const routeLabel = routeHero?.querySelector('.driver-route-hero-label');
            const acceptedKicker = document.getElementById('driver-trip-accepted-kicker');
            const activePanel = document.getElementById('active-trip-panel');

            const isDriver = window.userProfile?.role === 'driver';
            const isMine = data?.driverId === currentUser?.uid;
            const active = isDriver && isMine && data && ['accepted', 'in_progress'].includes(data.status);

            if (!active) {
                routeHero?.classList.add('hidden');
                destControls?.classList.add('hidden');
                driverTools?.classList.add('hidden');
                document.body.classList.remove('driver-trip-dest-phase', 'driver-pin-phase');
                if (isDriver) {
                    window.hideDriverTripExtraPanels?.();
                    window.syncTripFloatPanels?.(null);
                }
                return;
            }

            document.getElementById('service-zone-picker')?.classList.add('hidden');
            document.getElementById('trip-panel-setup')?.classList.add('hidden');
            activePanel?.classList.remove('hidden');
            // Chat + centrar siempre disponibles para el conductor en viaje aceptado / en curso / PIN
            driverTools?.classList.remove('hidden');
            window.showControlPanel?.();

            const wasRouteHidden = routeHero?.classList.contains('hidden');
            routeHero?.classList.remove('hidden');

            const isInProgress = data.status === 'in_progress';
            const waitingPin = data.status === 'accepted' && !!data.driverArrived;
            document.body.classList.toggle('driver-trip-dest-phase', isInProgress);
            document.body.classList.toggle('driver-pin-phase', waitingPin);

            if (!isInProgress) {
                destControls?.classList.add('hidden');
            }

            const isDestPhase = isInProgress || waitingPin;
            const targetAddress = isDestPhase ? (data.destination || '') : (data.origin || '');
            if (dp) dp.textContent = targetAddress || 'Sin dirección';
            if (acceptedKicker) {
                if (!isInProgress && data.status === 'accepted') {
                    acceptedKicker.classList.remove('hidden');
                    acceptedKicker.innerHTML = '<i class="fas fa-check-circle"></i> ¡Viaje aceptado!';
                } else {
                    acceptedKicker.classList.add('hidden');
                }
            }
            if (routeLabel) {
                routeLabel.textContent = window.formatTripGmapsBtnLabel?.(data, 'driver')
                    || (isDestPhase ? 'Toca para ir al destino en Google Maps' : 'Toca para ir al origen en Google Maps');
            }

            window.syncDriverPickupArrivalUi?.();
            window.syncDriverDestinationArrivalUi?.();
            window.hideDriverTripExtraPanels?.();
            window.syncTripFloatPanels?.(data);

            if (wasRouteHidden) {
                const panel = document.getElementById('control-panel');
                panel?.classList.remove('panel-collapsed');
                document.body.classList.remove('panel-minimized');
                const label = document.getElementById('trip-panel-toggle-label');
                if (label) label.textContent = 'Minimizar';
                if (panel) panel.scrollTop = 0;
            }
        };

        function restorePendingTripUI(data) {
            if (!data?.id) return;
            window.listenForNearbyDrivers?.();
            // Forzar mostrar conductores activos "desde ya"
            setTimeout(() => window.refreshNearbyDriversFromCache?.(), 200);
            activeTrip = { id: data.id, ...data };

            // Ensure client-view visible (searching UI lives inside), hide only booking chrome
            if (window.userProfile?.role === 'client') {
                if (window.userProfile?.role === 'client') document.getElementById('client-view')?.classList.remove('hidden');
            }

            // Hide booking form pieces inside client-view (searching-state lives inside it)
            document.getElementById('client-trip-headline')?.classList.add('hidden');
            document.getElementById('client-trip-subline')?.classList.add('hidden');
            document.getElementById('favorites-bar')?.classList.add('hidden');
            document.getElementById('delivery-details-panel')?.classList.add('hidden');
            document.getElementById('freight-details-panel')?.classList.add('hidden');
            document.getElementById('trip-options-panel')?.classList.add('hidden');
            document.querySelector('.trip-route-fields')?.classList.add('hidden');
            document.getElementById('driver-view')?.classList.add('hidden');
            const atp = document.getElementById('active-trip-panel');
            if (atp) {
              const isMobile = window.innerWidth < 768;
              if (isMobile && document.body.classList.contains('trip-active')) {
                // On cell phones: the central trip panel MUST only disappear when user taps minimize.
                // Do not add 'hidden' automatically.
              } else {
                atp.classList.add('hidden');
              }
            }
            document.getElementById('fare-card')?.classList.add('hidden');
            document.getElementById('client-service-type-wrap')?.classList.add('hidden');
            document.getElementById('service-zone-picker')?.classList.add('hidden');
            document.getElementById('service-zone-map-chip')?.classList.add('hidden');
            document.getElementById('scheduled-trip-card')?.classList.add('hidden');
            document.getElementById('searching-state')?.classList.remove('hidden');

            updateSearchingStatusUI(data);
            window._lastPendingTripUiSig = getPendingTripUiSig(data);
            prefetchRegisteredDriversCount(data);
            countOnlineDriversNearTrip(data).then((n) => {
                window.pendingTripOnlineDrivers = n;
                if (activeTrip?.id === data.id) {
                    updateSearchingStatusUI({
                        ...data,
                        _onlineDriversNear: n,
                        _registeredDrivers: window.pendingTripRegisteredDrivers
                            ?? window.lastRegisteredDriversCount
                            ?? 0,
                        _noDriversNearby: !data.offeredToDriverId && !data.driverId
                    });
                }
            }).catch(() => {});

            window.renderTripViewersPanel?.(data);
            renderInstallReminderBanner('passenger_request');
            document.body.classList.add('is-searching');
            document.body.classList.remove('trip-active', 'panel-minimized', 'panel-collapsed');
            syncPromoUi();
            window.showControlPanel?.();
            // Sonido en bucle mientras el cliente espera que acepten el viaje
            try { startPassengerWaitingLoop(); } catch (_) {}

            const panel = document.getElementById('control-panel');
            panel?.classList.remove('panel-collapsed', 'panel-hidden');
            if (panel) panel.scrollTop = 0;

            setStoredClientTripId(data.id);

            subscribeToTripDocument(data.id);
            startPendingOfferWatch(data.id);
        }

        function unsubscribeTripDocument() {
            if (window.myTripDocUnsub) {
                window.myTripDocUnsub();
                window.myTripDocUnsub = null;
            }
        }

        function subscribeToTripDocument(tripId) {
            if (!tripId || !currentUser) return;
            if (window.myTripDocUnsubTripId === tripId && window.myTripDocUnsub) return;

            unsubscribeTripDocument();
            window.myTripDocUnsubTripId = tripId;

            const tripRef = doc(db, 'artifacts', appId, 'public', 'data', 'trips', tripId);
            window.myTripDocUnsub = onSnapshot(tripRef, (snap) => {
                if (!snap.exists()) return;
                const data = { id: snap.id, ...snap.data() };
                const isMine = data.clientId === currentUser.uid || data.driverId === currentUser.uid;
                if (!isMine) return;
                processActiveTripUpdate(data);
            }, (err) => console.error('subscribeToTripDocument:', err));
        }

        function processActiveTripUpdate(data) {
            if (!data?.id || !currentUser) return;

            const isParticipant = data.clientId === currentUser.uid || data.driverId === currentUser.uid;
            if (isParticipant) {
                syncLiveTripKeepalive(data);
                if (['accepted', 'in_progress'].includes(data.status)) {
                    ensureInProgressLiveTracking(data);
                }
            }

            if (data.clientId === currentUser.uid) {
                if (['accepted', 'in_progress'].includes(data.status) && data.driverId) {
                    ensurePassengerTrackingForTrip(data);
                    if (data.status === 'in_progress' && data.driverArrivedDestination) {
                        if (activeTrip?.id === data.id) {
                            activeTrip = { ...activeTrip, ...data };
                            window.currentActiveTripData = activeTrip;
                        }
                        _initDestinationArrivalPanel?.();
                        const trackPos = window.currentDriverTrackPos || window._lastDriverFirebasePos;
                        if (trackPos) window.updatePassengerDestinationArrivalPanel?.(trackPos);
                    }
                } else if (['completed', 'cancelled'].includes(data.status)) {
                    window._passengerTrackKey = null;
                    window._passengerTrackSessionKey = null;
                    window._passengerTrackRouteSession = null;
                    window.stopPassengerLiveLocationSharing?.();
                    if (data.status === 'completed') {
                    // Mostrar al conductor el pago en efectivo
                    if (data.driverId === currentUser.uid && (data.paymentMethod === 'efectivo' || !data.paymentMethod)) {
                        const p = parseFloat(data.priceNum || 0);
                        setTimeout(() => {
                            window.showToast?.(`¡Viaje finalizado! Recibe L. ${p.toFixed(2)} en EFECTIVO del pasajero ahora.`);
                        }, 500);
                    }
                        window.stopClientTracking?.();
                        // Para el pasajero: mostrar pago en efectivo si aplica
                        if (data.paymentMethod === 'efectivo' || !data.paymentMethod) {
                            const p = parseFloat(data.priceNum || 0);
                            setTimeout(() => {
                                window.showToast?.(`Paga L. ${p.toFixed(2)} en EFECTIVO al conductor.`);
                            }, 300);
                        }
                    }
                }
            }

            if (data.driverId === currentUser.uid && ['accepted', 'in_progress'].includes(data.status)) {
                ensureDriverLocationForActiveTrip(data);
            }

            if (data.status === 'in_progress' && data.driverId === currentUser.uid) {
                ensureInProgressLiveTracking(data);
            }

            if (['completed', 'cancelled'].includes(data.status)) {
                window.stopPassengerLiveLocationSharing?.();
            }

            if (data.status === 'pending' && data.clientId === currentUser.uid) {
                activeTrip = { id: data.id, ...data };

                // Viaje creado por staff: el cliente debe adueñarse antes de ver ofertas
                if (data.staffCreatedBy && data.staffCreatedClientClaimed !== true) {
                    window.showStaffCreatedTripClaimModal?.(data);
                    window._lastNotifiedTripStatus = 'pending';
                    return;
                }

                const pendingSig = getPendingTripUiSig(data);
                const searchingVisible = !document.getElementById('searching-state')?.classList.contains('hidden');
                const pendingChanged = window._lastPendingTripUiSig !== pendingSig;

                if (!searchingVisible) {
                    restorePendingTripUI(data);
                } else {
                    if (pendingChanged) {
                        updateSearchingStatusUI({
                            ...data,
                            _onlineDriversNear: window.pendingTripOnlineDrivers ?? window.lastNearbyDriversCount,
                            _noDriversNearby: !data.offeredToDriverId && !data.driverId
                        });
                    }
                    window.renderTripViewersPanel?.(data);
                    // Mantener / reanudar bucle de espera si ya está en UI de búsqueda
                    try { startPassengerWaitingLoop(); } catch (_) {}
                }

                window._lastPendingTripUiSig = pendingSig;
                if (window._lastNotifiedTripStatus === null) {
                    window._lastNotifiedTripStatus = 'pending';
                }
                return;
            }

            // Programado reservado (con conductor): no arranca nav aún
            if (data.status === 'scheduled' && data.driverId) {
                activeTrip = { id: data.id, ...data };
                window.currentActiveTripData = data;
                if (isScheduledTripDueForActivation(data)) {
                    window.activateScheduledTripIfDue?.(data.id).catch(() => {});
                } else {
                    const role = data.driverId === currentUser?.uid ? 'driver' : 'client';
                    window.presentScheduledReservedUi?.(data, { role });
                }
                window._lastNotifiedTripStatus = 'scheduled';
                return;
            }

            const stateSig = `${data.id}:${data.status}:${!!data.driverArrived}:${!!data.driverArrivedDestination}:${data.routeLegIndex || 1}:${data.chat?.length || 0}`;
            if (window._lastTripUiState === stateSig) return;
            window._lastTripUiState = stateSig;
            window._lastPendingTripUiSig = null;

            if (data.status === 'cancelled') {
                refundPassengerSaldoForTrip(data, data.id).catch((e) => console.warn('refundSaldo:', e));

                const wasQueued = window.driverQueuedTripId === data.id || window.userProfile?.queuedTripId === data.id;
                if (wasQueued && window.userProfile?.role === 'driver') {
                    window.driverQueuedTripId = null;
                    window.userProfile.queuedTripId = null;
                    setDoc(doc(db, 'artifacts', appId, 'users', currentUser.uid, 'profile', 'data'), { queuedTripId: null }, { merge: true }).catch(() => {});
                    setDoc(doc(db, 'artifacts', appId, 'public', 'data', 'users', currentUser.uid), { queuedTripId: null }, { merge: true }).catch(() => {});
                    if (activeTrip?.id !== data.id) {
                        window.showToast('El pasajero en cola canceló su viaje.', 'warning');
                    }
                }

                handleTripCancelled(data.id, data);
                return;
            }

            if (!activeTrip || activeTrip.id !== data.id) {
                window.lastMessageCount = data.chat ? data.chat.length : 0;
            }

            const prevStatus = window._lastNotifiedTripStatus;
            const prevArrived = window._lastNotifiedDriverArrived;
            const prevDestArrived = window._lastNotifiedDriverDestArrived;

            activeTrip = { id: data.id, ...data };
            window.currentActiveTripData = data;

            // Solo colocar marcadores de ruta mientras el viaje está activo (no al completar/cancelar)
            if (['accepted', 'in_progress'].includes(data.status)) {
                if (data.originLat != null && data.originLng != null) {
                    window.placePickupMarker?.({ lat: data.originLat, lng: data.originLng }, 'Origen');
                }
                if (data.destinationLat != null && data.destinationLng != null) {
                    window.placeDestinationMarker?.({ lat: data.destinationLat, lng: data.destinationLng }, 'Destino');
                }
            }

            if (prevStatus !== null && window.userProfile?.role === 'client') {
                if (prevStatus === 'pending' && data.status === 'scheduled' && data.driverId) {
                    try { stopPassengerWaitingLoop(); } catch (_) {}
                    if (window._passengerAcceptSoundKey !== data.id) {
                        window._passengerAcceptSoundKey = data.id;
                        try { playPassengerAcceptedTone(); } catch (_) {}
                    }
                    window.presentScheduledReservedUi?.(data, { role: 'client' });
                    window.showToast?.(
                        `Conductor confirmado para ${formatScheduledTripWhen(data)}. Te avisaremos antes de la hora.`,
                        'success'
                    );
                }
                if (prevStatus === 'scheduled' && data.status === 'accepted') {
                    window.presentTripAcceptedUi?.(data, { role: 'client', skipAcceptSound: true });
                }
                if (prevStatus === 'pending' && data.status === 'accepted') {
                    // Parar espera en bucle + tono de “viaje aceptado” (una sola vez)
                    try { stopPassengerWaitingLoop(); } catch (_) {}
                    if (window._passengerAcceptSoundKey !== data.id) {
                        window._passengerAcceptSoundKey = data.id;
                        try { playPassengerAcceptedTone(); } catch (_) {}
                    }
                    const busyMsg = data.driverFinishingOtherTrip
                        ? `${data.driverName || 'Tu conductor'} termina otro viaje y luego va hacia ti.`
                        : `${data.driverName || 'Tu conductor'} va en camino.`;
                    notifyTripEvent({
                        title: '¡Viaje aceptado!',
                        body: busyMsg,
                        tag: `trip-accepted-${data.id}`,
                        tripId: data.id,
                        sound: 'none'
                    });
                    if (window._tripAcceptedToastKey !== `${data.id}:client`) {
                        window._tripAcceptedToastKey = `${data.id}:client`;
                        window.showToast(`¡Viaje aceptado! ${busyMsg}`, 'success');
                    }
                }
                if (prevArrived !== null && data.status === 'accepted' && data.driverArrived && !prevArrived) {
                    triggerPassengerArrivedAlert(data);
                }
                if (prevStatus === 'accepted' && data.status === 'in_progress') {
                    window.showToast?.('Viaje iniciado. Sigue la ruta hacia tu destino en el mapa.', 'success');
                    ensureTripOriginAtPinStart(data).then((corrected) => {
                        ensureInProgressLiveTracking(corrected || data);
                    });
                }
            }

            if (prevStatus !== null && window.userProfile?.role === 'driver') {
                if (prevStatus === 'pending' && data.status === 'scheduled' && data.driverId === currentUser.uid) {
                    window.presentScheduledReservedUi?.(data, { role: 'driver' });
                }
                if (prevStatus === 'scheduled' && data.status === 'accepted' && data.driverId === currentUser.uid) {
                    window.presentTripAcceptedUi?.(data, { role: 'driver' });
                    window.showToast?.('Viaje programado activo. Ve al origen del pasajero.', 'success');
                }
                if (prevStatus === 'pending' && data.status === 'accepted' && data.driverId === currentUser.uid) {
                    const body = `${data.clientName || 'El pasajero'} confirmó contigo. Abre Google Maps y ve al origen.`;
                    notifyTripEvent({
                        title: '¡Viaje aceptado!',
                        body,
                        tag: `trip-accepted-${data.id}`,
                        tripId: data.id
                    });
                    if (window._tripAcceptedToastKey !== `${data.id}:driver`) {
                        window.presentTripAcceptedUi?.(data, { role: 'driver' });
                    }
                }
                if (prevStatus !== 'in_progress' && data.status === 'in_progress') {
                    notifyTripEvent({
                        title: 'Viaje iniciado',
                        body: 'El pasajero confirmó el PIN. Dirígete al destino.',
                        tag: `trip-started-${data.id}`,
                        tripId: data.id
                    });
                }
            }

            window._lastNotifiedTripStatus = data.status;
            window._lastNotifiedDriverArrived = !!data.driverArrived;
            window._lastNotifiedDriverDestArrived = !!data.driverArrivedDestination;

            if (data.chat && data.chat.length > window.lastMessageCount) {
                const newMessages = data.chat.slice(window.lastMessageCount);
                window.lastMessageCount = data.chat.length;

                let shouldPlaySound = false;

                newMessages.forEach((msg) => {
                    if (msg.sender !== currentUser.uid) {
                        shouldPlaySound = true;

                        if (!window.chatOpen) {
                            ['chat-badge', 'chat-badge-driver', 'driver-tools-chat-badge', 'driver-pin-chat-badge'].forEach((id) => {
                                const badge = document.getElementById(id);
                                if (!badge) return;
                                const count = parseInt(badge.innerText || '0') + 1;
                                badge.innerText = count;
                                badge.classList.remove('hidden');
                                badge.classList.add('animate-bounce');
                                setTimeout(() => badge.classList.remove('animate-bounce'), 2500);
                            });
                        }

                        notifyChatMessage({
                            senderName: msg.senderName || (window.userProfile?.role === 'client' ? 'Tu conductor' : 'Tu pasajero'),
                            text: msg.text,
                            tripId: data.id
                        });

                        if (!shouldNotifyInBackground()) {
                            window.speakMessage(`${msg.senderName} dice: ${msg.text}`);
                        }
                    }
                });

                if (shouldPlaySound) {
                    try {
                        const audioObj = new Audio('https://actions.google.com/sounds/v1/ui/message_notification.ogg');
                        audioObj.play().catch(() => {});
                    } catch (e) {}
                }
            }

            if (data.status === 'accepted' || data.status === 'in_progress') {
                if (window.pendingOfferWatch) {
                    clearInterval(window.pendingOfferWatch);
                    window.pendingOfferWatch = null;
                }
                // Ya no está buscando: cortar bucle de espera del pasajero
                if (data.clientId === currentUser?.uid) {
                    try { stopPassengerWaitingLoop(); } catch (_) {}
                }
                setStoredClientTripId(data.id);
                window.stopNearbyDriversListener?.();
                document.body.classList.add('trip-active');
                document.body.classList.remove('is-searching');
                syncPromoUi();
                clearPassengerSearchPanelLayout();
                window.refreshIOSInstallBanner?.();
                window.showControlPanel?.();
                const activeP = document.getElementById('active-trip-panel');
                if (activeP) {
                    activeP.classList.remove('hidden');
                    activeP.classList.remove('panel-minimized');
                    // tap superior para minimizar durante ruta (conductor)
                    if (!activeP.dataset.minBound) {
                        activeP.dataset.minBound = '1';
                        activeP.addEventListener('click', (e) => {
                            if (e.target.closest('button, input, a, [data-trip-action]')) return;
                            const rect = activeP.getBoundingClientRect();
                            if (e.clientY - rect.top <= 40) {
                                activeP.classList.toggle('panel-minimized');
                            }
                        });
                    }
                }
                document.getElementById('client-view')?.classList.add('hidden');
                document.getElementById('trip-panel-setup')?.classList.add('hidden');
                document.getElementById('driver-view')?.classList.add('hidden');
                document.getElementById('searching-state')?.classList.add('hidden');
                document.getElementById('fare-card')?.classList.add('hidden');
                document.getElementById('scheduled-trip-card')?.classList.add('hidden');
                document.getElementById('trip-viewers-panel')?.classList.add('hidden');
                syncPassengerBookingForm?.(data);

                const ao = document.getElementById('active-origin-text');
                if (ao) {
                    ao.innerText = (typeof getDriverTripPointLabel === 'function')
                        ? getDriverTripPointLabel(data, 'origin')
                        : (data.originPlaceName || window.shortenMapPlaceLabel?.(data.origin) || data.origin || '');
                }
                const ad = document.getElementById('active-dest-text');
                if (ad) {
                    ad.innerText = (typeof getDriverTripPointLabel === 'function')
                        ? getDriverTripPointLabel(data, 'destination')
                        : (data.destinationPlaceName || window.shortenMapPlaceLabel?.(data.destination) || data.destination || '');
                }
                // Hourly note + personas (también en viaje normal)
                const hourlyNote = document.getElementById('active-hourly-note');
                if (hourlyNote) {
                    const paxN = Math.max(1, parseInt(data.passengers, 10) || 1);
                    if (data.bookingType === 'hourly' && data.reservedHours) {
                        let note = `<span class="inline-block mt-1 text-emerald-700 font-black text-[9px]"><i class="fas fa-clock"></i> ${data.reservedHours} HORA(S)`;
                        if (data.hourlyStartTime) note += ` · inicia ${data.hourlyStartTime}`;
                        if (data.isNightSurcharge) note += ` · +25% noche`;
                        note += `</span>`;
                        note += ` <span class="inline-block mt-1 ml-1 text-amber-700 font-black text-[9px]"><i class="fas fa-users"></i> ${paxN} pers. · ${data.multipleStops ? 'múltiples' : '2'} paradas</span>`;
                        if (data.distanceKmForCharge > 25) {
                            note += ` <span class="inline-block mt-1 ml-1 text-emerald-700 font-black text-[9px]"><i class="fas fa-road"></i> +km</span>`;
                        }
                        hourlyNote.innerHTML = note;
                        hourlyNote.classList.remove('hidden');
                    } else if (paxN > 1 && data.serviceType !== 'delivery' && !isFreightService(data.serviceType)) {
                        hourlyNote.innerHTML = `<span class="inline-block mt-1 text-amber-700 font-black text-[10px]"><i class="fas fa-users"></i> ${paxN} PERSONAS en este viaje${Number(data.passengerSurcharge) > 0 ? ` · +L. ${Number(data.passengerSurcharge).toFixed(0)}` : ''}</span>`;
                        hourlyNote.classList.remove('hidden');
                    } else {
                        hourlyNote.classList.add('hidden');
                        hourlyNote.innerHTML = '';
                    }
                }
                renderChat(data.chat || []);

                if (window.userProfile.role === 'driver') {
                    if (isTestDriverProfile() && (data.status === 'accepted' || data.status === 'in_progress')) {
                        window.showToast?.(
                            `Viaje activo con ${data.clientName || 'pasajero'}. Usa el botón flotante ¡HE LLEGADO! y el chat en el mapa.`,
                            'success'
                        );
                    }
                    syncDriverTripControls?.(data);
                    syncClientPinDisplay?.(data);
                    window.hideDriverTripExtraPanels?.();
                    document.getElementById('client-security-controls')?.classList.add('hidden');
                    window.renderTripPartnerInfo?.(data, 'driver');

                    // Ensure we show the *current* passenger rating (fresh from profile, not just creation-time snapshot)
                    enrichTripClientForDriver(data).then((enriched) => {
                        if (enriched !== data && activeTrip?.id === data.id) {
                            window.renderTripPartnerInfo?.(enriched, 'driver');
                        }
                    });

                    // Aviso automático si staff cambió destino/ruta (no en el primer snapshot del viaje)
                    const routeToken = data.staffRouteChangeToken || null;
                    if (window._lastStaffRouteTripId !== data.id) {
                        window._lastStaffRouteTripId = data.id;
                        window._lastStaffRouteChangeToken = routeToken;
                    } else if (
                        routeToken
                        && routeToken !== window._lastStaffRouteChangeToken
                        && data.driverId === currentUser?.uid
                    ) {
                        window._lastStaffRouteChangeToken = routeToken;
                        const noticeText = 'Punto de destino cambiado por el sistema. Haz clic aquí para cambiar la ruta.';
                        window.showDriverStaffRouteChangeBanner?.(data, noticeText);
                        window._inProgressNavBootKey = null;
                        if (data.status === 'in_progress') {
                            ensureInProgressLiveTracking(data);
                            const nextTarget = window.getTripCurrentLegNavTarget?.(data);
                            if (nextTarget) window.updateNavigation?.(nextTarget, true);
                        } else if (data.status === 'accepted' && data.driverArrived) {
                            ensureDriverTripNavRoute(data);
                        }
                        window.showToast?.(noticeText, 'warning');
                    }

                    if (data.status === 'accepted' && !data.driverArrived) {
                        startDriverPickupNavigation(data);
                    } else if (data.driverArrived && data.status === 'accepted') {
                        ensureDriverTripNavRoute(data);
                    } else if (data.status === 'in_progress') {
                        ensureInProgressLiveTracking(data);
                        window.ensureDriverNavRouteVisible?.();
                    }
                } else {
                    syncDriverTripControls?.(data);
                    syncClientPinDisplay?.(data);
                    document.getElementById('client-security-controls')?.classList.remove('hidden');
                    syncPassengerAlertSettingsVisibility(true);

                    window.renderTripPartnerInfo?.(data, 'client');
                    enrichTripDriverVehicleForPassenger(data).then((enriched) => {
                        if (enriched !== data && activeTrip?.id === data.id) {
                            window.renderTripPartnerInfo?.(enriched, 'client');
                        }
                    });

                    const busyNotice = document.getElementById('client-driver-busy-notice');
                    const busyText = document.getElementById('client-driver-busy-text');
                    if (data.driverFinishingOtherTrip && data.status === 'accepted') {
                        busyNotice?.classList.remove('hidden');
                    } else {
                        busyNotice?.classList.add('hidden');
                    }

                    if (data.status === 'accepted') {
                        document.getElementById('eta-indicator')?.classList.add('hidden');
                        document.getElementById('searching-driver-card')?.classList.add('hidden');
                        window.syncPassengerPanelToggleLabel?.();
                        if (data.driverArrived) {
                            if (etaInterval) clearInterval(etaInterval);
                            window.clearRoutePolylines?.();
                            window.clearOriginDestinationMarkers?.();
                        }
                    } else if (data.status === 'in_progress') {
                        document.getElementById('eta-indicator')?.classList.add('hidden');
                        document.getElementById('searching-driver-card')?.classList.add('hidden');
                        _initDestinationArrivalPanel?.();
                        const currLegIdx = data.routeLegIndex || 1;
                        const prevLegIdx = window._lastRouteLegIndex;
                        if (prevLegIdx != null && currLegIdx > prevLegIdx) {
                            const legLabel = window.getTripRouteLegLabel?.(data);
                            window.showToast?.(
                                `Siguiente parada: punto ${legLabel?.routeNum || currLegIdx}.`,
                                'info'
                            );
                        }
                        window._lastRouteLegIndex = currLegIdx;
                        if (data.driverArrivedDestination && !prevDestArrived) {
                            notifyTripEvent({
                                title: '¡Llegaste al destino!',
                                body: 'Tu conductor marcó llegada. El viaje se está finalizando.',
                                tag: `trip-dest-arrived-${data.id}`,
                                tripId: data.id
                            });
                            window.showToast?.('Tu conductor llegó al destino. Finalizando viaje…', 'success');
                        }
                    } else {
                        window.stopClientTracking?.();
                        document.getElementById('eta-indicator')?.classList.add('hidden');
                        if (etaInterval) clearInterval(etaInterval);
                    }
                }

                window.syncTripFloatPanels?.(data);
            } else if (
                data.status === 'completed'
                && !isDemandSimulationTrip(data)
                && !data[getRatedFieldForUser(data)]
            ) {
            if (isCurrentUserTripPassenger(data)) {
                window.stopClientTracking?.();
                if (etaInterval) clearInterval(etaInterval);
            }
            if (window.userProfile.role === 'driver' && data.driverId === currentUser.uid) {
                scheduleDriverEarningsRefresh();
                window.clearRoutePolylines?.({ force: true });
                window.clearOriginDestinationMarkers?.();
                window.resetDriverNavCamera?.({ force: true });
                document.body.classList.remove('trip-active', 'is-navigating', 'driver-nav-mode', 'driver-trip-dest-phase');
                window.minimizeControlPanelForDriverRating?.();
                window.ensureDriverOnlineAfterTripComplete?.();
                window.refreshPendingTripOffersAfterDriverFreed?.(currentUser.uid);

                // ACREDITAR RECOMPENSA DE REFERIDOS AL PRIMER VIAJE (si el conductor fue referido)
                creditReferralOnFirstTrip(db, appId, currentUser.uid).catch(() => {});
            }
            const ratingScreenEl = document.getElementById('rating-screen');
            const ratingVisible = ratingScreenEl && ratingScreenEl.style.display === 'flex';
            if (window._ratingTripId !== data.id || !ratingVisible) {
                window._ratingTripId = data.id;
                if (isCurrentUserTripPassenger(data)) {
                    if (data.passengerConfirmedArrival || data.paymentConfirmed) {
                        showRatingScreen();
                    } else {
                        showArrivalConfirmation(data);
                    }

                    // Pagar L. 50 al referente en el primer viaje del referido
                    creditReferralOnFirstTrip(db, appId, currentUser.uid).catch(() => {});
                } else {
                    showRatingScreen();
                }
            }
            }
        }

        async function fetchClientActiveTripFromDb() {
            if (!currentUser) return null;

            const pickIfActive = (trip) => {
                if (!trip || trip.clientId !== currentUser.uid || isDemandSimulationTrip(trip)) return null;
                if (['pending', 'accepted', 'in_progress'].includes(trip.status)) return trip;
                return null;
            };

            try {
                const storedId = getStoredClientTripId();
                if (storedId) {
                    const storedSnap = await getDoc(doc(db, 'artifacts', appId, 'public', 'data', 'trips', storedId));
                    if (storedSnap.exists()) {
                        const picked = pickIfActive({ id: storedSnap.id, ...storedSnap.data() });
                        if (picked) return picked;
                    }
                    clearStoredClientTripId();
                }

                const activeStatuses = ['pending', 'accepted', 'in_progress'];
                try {
                    const q = query(
                        collection(db, 'artifacts', appId, 'public', 'data', 'trips'),
                        where('clientId', '==', currentUser.uid),
                        where('status', 'in', activeStatuses)
                    );
                    const qSnap = await getDocs(q);
                    const trips = sortClientTripsByPriority(
                        qSnap.docs.map((d) => ({ id: d.id, ...d.data() }))
                    );
                    if (trips[0]) return trips[0];
                } catch (_) {
                    const allSnap = await getDocs(
                        query(collection(db, 'artifacts', appId, 'public', 'data', 'trips'), where('clientId', '==', currentUser.uid))
                    );
                    const trips = sortClientTripsByPriority(
                        allSnap.docs
                            .map((d) => ({ id: d.id, ...d.data() }))
                            .filter((t) => activeStatuses.includes(t.status) && !isDemandSimulationTrip(t))
                    );
                    if (trips[0]) return trips[0];
                }
            } catch (e) {
                console.error('fetchClientActiveTripFromDb:', e);
            }
            return null;
        }

        async function fetchAndRestoreClientActiveTrip() {
            if (!currentUser) return false;
            const role = window.userProfile?.role;
            if (role === 'driver' || isStaffUser(currentUser, window.userProfile)) return false;

            const trip = await fetchClientActiveTripFromDb();
            if (!trip) return false;

            setStoredClientTripId(trip.id);
            if (trip.status === 'pending') {
                restorePendingTripUI(trip);
            } else {
                window._lastTripUiState = null;
                window._lastNotifiedTripStatus = trip.status;
                window._lastNotifiedDriverArrived = !!trip.driverArrived;
                processActiveTripUpdate(trip);
                if (trip.status === 'in_progress' && trip.driverId) {
                    const bootDest = () => {
                        if (activeTrip?.id !== trip.id) return;
                        startClientDestinationTracking(activeTrip);
                    };
                    if (window.mapLoaded) bootDest();
                    else setTimeout(bootDest, 600);
                }
            }
            return true;
        }

        // --- SISTEMA MAESTRO DEL VIAJE ---
        function listenToMyActiveTrip() {
            if (!currentUser) return;

            if (window.activeTripUnsub) {
                window.activeTripUnsub();
                window.activeTripUnsub = null;
            }

            const storedTripId = getStoredClientTripId();
            if (storedTripId) subscribeToTripDocument(storedTripId);

            // Optimized: query only this user's trips instead of full collection (faster startup and less data)
            const role = window.userProfile?.role;
            let tripQuery;
            if (role === 'driver') {
                tripQuery = query(collection(db, 'artifacts', appId, 'public', 'data', 'trips'), where('driverId', '==', currentUser.uid));
            } else {
                tripQuery = query(collection(db, 'artifacts', appId, 'public', 'data', 'trips'), where('clientId', '==', currentUser.uid));
            }

            window.activeTripUnsub = onSnapshot(tripQuery, (snap) => {
                if (window.userProfile?.role !== 'driver') {
                    const scheduledTrips = snap.docs
                        .map((d) => ({ id: d.id, ...d.data() }))
                        .filter((t) => t.status === 'scheduled' && t.clientId === currentUser.uid && !isDemandSimulationTrip(t));
                    if (scheduledTrips.length) {
                        const scheduledTrip = sortTripsByNewest(scheduledTrips)[0];
                        setStoredClientTripId(scheduledTrip.id);
                        if (isScheduledTripDueForActivation(scheduledTrip)) {
                            window.activateScheduledTripIfDue?.(scheduledTrip.id).catch(() => {});
                        } else if (scheduledTrip.driverId) {
                            window.presentScheduledReservedUi?.(scheduledTrip, { role: 'client' });
                        }
                    }
                } else {
                    // Conductor: reservas programadas mías
                    const myScheduled = snap.docs
                        .map((d) => ({ id: d.id, ...d.data() }))
                        .filter((t) => t.status === 'scheduled' && t.driverId === currentUser.uid && !isDemandSimulationTrip(t));
                    if (myScheduled.length) {
                        const st = sortTripsByNewest(myScheduled)[0];
                        if (isScheduledTripDueForActivation(st)) {
                            window.activateScheduledTripIfDue?.(st.id).catch(() => {});
                        } else if (!activeTrip || activeTrip.id === st.id || activeTrip.status === 'scheduled') {
                            window.presentScheduledReservedUi?.(st, { role: 'driver' });
                        }
                    }
                }

                if (window.userProfile?.role === 'driver') {
                    const myCompletedToday = snap.docs.some((d) => {
                        const t = d.data();
                        if (t.driverId !== currentUser.uid || t.status !== 'completed') return false;
                        const tripDate = tripCompletedDate(t);
                        if (!tripDate) return false;
                        const today = new Date();
                        today.setHours(0, 0, 0, 0);
                        const tomorrow = new Date(today);
                        tomorrow.setDate(tomorrow.getDate() + 1);
                        return tripDate >= today && tripDate < tomorrow;
                    });
                    if (myCompletedToday) scheduleDriverEarningsRefresh();
                }

                const match = findMyRelevantTrip(snap);

                if (match) {
                    subscribeToTripDocument(match.id);
                    processActiveTripUpdate({ ...match });
                } else {
                    const pendingBackup = findMyPendingClientTrip(snap);
                    if (pendingBackup && window.userProfile?.role !== 'driver') {
                        setStoredClientTripId(pendingBackup.id);
                        restorePendingTripUI(pendingBackup);
                        return;
                    }

                    const activeBackup = findMyActiveClientTrip(snap);
                    if (activeBackup && window.userProfile?.role !== 'driver') {
                        setStoredClientTripId(activeBackup.id);
                        window._lastTripUiState = null;
                        processActiveTripUpdate(activeBackup);
                        if (activeBackup.status === 'in_progress' && activeBackup.driverId) {
                            const bootDest = () => {
                                if (activeTrip?.id !== activeBackup.id) return;
                                startClientDestinationTracking(activeTrip);
                            };
                            if (window.mapLoaded) bootDest();
                            else setTimeout(bootDest, 600);
                        }
                        return;
                    }

                    if (activeTrip?.status === 'pending' && activeTrip?.clientId === currentUser.uid) {
                        restorePendingTripUI(activeTrip);
                        return;
                    }

                    if (activeTrip) resetAfterTripEnds();
                    else {
                        document.body.classList.remove('trip-active', 'is-searching');
                        document.getElementById('searching-state')?.classList.add('hidden');
                        if (window.userProfile?.role === 'client') {
                            if (window.userProfile?.role === 'client') document.getElementById('client-view')?.classList.remove('hidden');
                        }
                        window.refreshIOSInstallBanner?.();
                        // ensure booking form visible
                        document.getElementById('client-trip-headline')?.classList.remove('hidden');
                        document.getElementById('client-trip-subline')?.classList.remove('hidden');
                        document.getElementById('favorites-bar')?.classList.remove('hidden');
                        document.getElementById('trip-options-panel')?.classList.remove('hidden');
                        document.querySelector('.trip-route-fields')?.classList.remove('hidden');
                        clearStoredClientTripId();
                    }

                    if (window.userProfile?.role === 'driver') {
                        const isApproved = (window.userProfile.approvalStatus === 'approved' || typeof window.userProfile.approvalStatus === 'undefined');
                        if (!isApproved) {
                            document.getElementById('requests-list').innerHTML = `
                                <div class="py-10 px-4 text-center">
                                    <div class="mx-auto w-16 h-16 bg-amber-100 rounded-full flex items-center justify-center mb-4">
                                        <i class="fas fa-user-clock text-4xl text-amber-500"></i>
                                    </div>
                                    <h4 class="font-black text-amber-600 text-base">CUENTA PENDIENTE DE APROBACIÓN</h4>
                                    <p class="text-xs text-amber-500 mt-2 leading-snug">Un supervisor está verificando tus documentos y fotos del vehículo.</p>
                                </div>
                            `;
                        }
                    }
                }
            });
        }

