window.acceptTermsAndContinue = async () => {
    if (!currentUser) {
        return location.reload();
    }

    try {
        const updateData = {
            termsAccepted: true,
            termsAcceptedAt: new Date().toISOString()
        };

        await window.ownerProfilePatch(currentUser.uid, updateData);

        if (window.userProfile) {
            window.userProfile.termsAccepted = true;
            window.userProfile.termsAcceptedAt = updateData.termsAcceptedAt;
        }

        window.showToast("¡Gracias! Has aceptado los Términos y Condiciones.", "success");

        setTimeout(() => location.reload(), 600);

    } catch (e) {
        console.error('acceptTermsAndContinue:', e);
        const msg = e?.code === 'functions/unauthenticated'
            ? 'Sesión expirada. Cierra sesión y vuelve a entrar.'
            : 'No se pudieron guardar los términos. Recarga (Ctrl+F5) e intenta de nuevo.';
        window.showToast(msg, 'error');
    }
};

// Reenvío / primera verificación de documentos para pasajeros
window.startClientDocumentResubmit = () => {
    showPassengerVerificationSetup({
        title: 'Reenviar documentos',
        subtitle: 'Corrige y vuelve a enviar tu verificación',
    });
};

window.submitPassengerVerification = async () => {
    if (!currentUser?.uid) {
        return alert('Sesión expirada. Vuelve a iniciar sesión.');
    }
    const profile = window.userProfile || {};
    const minor = isMinorProfile(profile);
    const identity = document.getElementById('passenger-identity')?.value.trim() || '';
    if (!window.passengerPhotoBase64) {
        return alert('Toma una foto de tu rostro con la cámara.');
    }
    if (minor) {
        if (!window.passengerBirthCertBase64) {
            return alert('Sube una foto clara de tu partida de nacimiento.');
        }
    } else {
        if (!window.passengerIdFrontBase64) {
            return alert('Sube la foto del anverso (frente) de tu identidad.');
        }
        if (!window.passengerIdBackBase64) {
            return alert('Sube la foto del reverso de tu identidad.');
        }
        if (!identity) {
            return alert('Ingresa tu número de identidad.');
        }
    }

    try {
        const uid = currentUser.uid;
        const base = `artifacts/${appId}/users/${uid}/verification`;

        const verificationSelfieUrl = await resolvePhotoUrl(storage, window.passengerPhotoBase64, `${base}/selfie.jpg`);
        const update = {
            verificationPhoto: verificationSelfieUrl,
            photo: verificationSelfieUrl,
            approvalStatus: 'pending',
            verified: false,
            identityVerificationSubmitted: true,
            verificationSubmittedAt: new Date().toISOString(),
            resubmitRequested: false,
            roleChangeSetupRequired: false,
            isMinorAccount: minor,
        };

        if (minor) {
            const birthCertUrl = await resolvePhotoUrl(storage, window.passengerBirthCertBase64, `${base}/birth-certificate.jpg`);
            update.birthCertificatePhoto = birthCertUrl;
            update.identityFrontPhoto = null;
            update.identityBackPhoto = null;
            if (identity) update.identity = identity;
        } else {
            const frontUrl = await resolvePhotoUrl(storage, window.passengerIdFrontBase64, `${base}/id-front.jpg`);
            const backUrl = await resolvePhotoUrl(storage, window.passengerIdBackBase64, `${base}/id-back.jpg`);
            update.identity = identity;
            update.identityFrontPhoto = frontUrl;
            update.identityBackPhoto = backUrl;
            update.birthCertificatePhoto = null;
        }

        await setDoc(doc(db, 'artifacts', appId, 'users', uid, 'profile', 'data'), update, { merge: true });
        await setDoc(doc(db, 'artifacts', appId, 'public', 'data', 'users', uid), update, { merge: true });

        try {
            await createVerificationAlert(db, appId, { ...window.userProfile, ...update, uid, role: 'client' });
        } catch (alertErr) {
            console.warn('createVerificationAlert:', alertErr);
        }

        if (window.userProfile) Object.assign(window.userProfile, update);

        clearPassengerVerificationPromptDismissed();
        window.cancelPassengerVerificationSetup?.();
        syncPassengerVerificationBanner(window.userProfile);
        window.showToast('Verificación enviada. Ya puedes seguir pidiendo viajes; el conductor verá tu estado y decidirá.', 'success');
    } catch (e) {
        console.error('submitPassengerVerification:', e);
        alert('Error al enviar la verificación. Intenta de nuevo.');
    }
};

// Preview helpers for resubmit (reusing similar logic)
