window.submitClientResubmit = async () => {
    if (!window._resubmitPhoto || !window._resubmitFront || !window._resubmitBack) {
        return alert('Sube las 3 fotos requeridas.');
    }
    if (!currentUser) return;

    try {
        const uid = currentUser.uid;
        const base = `artifacts/${appId}/users/${uid}/verification`;

        const photoUrl = await resolvePhotoUrl(storage, window._resubmitPhoto, `${base}/selfie.jpg`);
        const frontUrl = await resolvePhotoUrl(storage, window._resubmitFront, `${base}/id-front.jpg`);
        const backUrl = await resolvePhotoUrl(storage, window._resubmitBack, `${base}/id-back.jpg`);

        const update = {
            verificationPhoto: photoUrl,
            identityFrontPhoto: frontUrl,
            identityBackPhoto: backUrl,
            photo: photoUrl,
            resubmitRequested: false,
            roleChangeSetupRequired: false,
            approvalStatus: 'pending',
            identityVerificationSubmitted: true,
            verificationSubmittedAt: new Date().toISOString()
        };

        await setDoc(doc(db, 'artifacts', appId, 'users', uid, 'profile', 'data'), update, { merge: true });
        await setDoc(doc(db, 'artifacts', appId, 'public', 'data', 'users', uid), update, { merge: true });

        window.showToast('Documentos reenviados. Espera la revisión del supervisor.', 'success');
        setTimeout(() => location.reload(), 1200);
    } catch (e) {
        console.error(e);
        alert('Error al reenviar. Intenta de nuevo.');
    }
};

// Unified function for profile button: "Reenviar / corregir documentos"
window.startDocumentResubmit = async () => {
    if (!currentUser || !window.userProfile) {
        return window.showToast('Debes estar logueado.');
    }

    const role = window.userProfile.role;
    const uid = currentUser.uid;

    // Always mark that user requested resubmit (so supervisor sees it)
    try {
        await window.ownerProfilePatch(uid, {
            resubmitRequested: true,
            resubmitRequestedAt: new Date().toISOString()
        });
    } catch (e) {
        console.error(e);
    }

    if (role === 'client') {
        showPassengerVerificationSetup({
            title: needsPassengerVerificationCTA(window.userProfile) ? 'Verifica tu identidad' : 'Reenviar documentos',
            subtitle: 'Viajes más rápidos y más confianza',
        });
        window.closeProfilePanel?.();
    } else if (role === 'driver') {
        window.showDriverDocumentResubmit();
        window.closeProfilePanel?.();
    } else {
        window.showToast('Rol no soportado para reenvío de documentos.');
    }
};

