        window.loadSupervisorPastTrips = async () => {
            const container = document.getElementById('supervisor-pending-list');
            if (!container) return;

            window.supervisorTripsPastView = true;
            window.stopSupervisorTripsListener?.();
            window.setSupervisorNavActive?.('trips');

            const U = window.OpsUi;
            container.innerHTML = U.page(
                U.hero('Historial de viajes', 'Todos los viajes completados', '') +
                `<div class="mb-2">${U.btn('Volver a activos', 'window.loadSupervisorTrips()', { variant: 'ghost', icon: 'fa-arrow-left' })}</div>` +
                `<div id="sup-past-trips-inner"></div>`
            );
            const inner = container.querySelector('#sup-past-trips-inner');
            await window.showMyPastTrips(null, inner);
        };

